# Legal research

@app.route("/api/owner/legal/research", methods=["POST"])
def legal_research():
    s = _require_legal_module()
    body = request.get_json(force=True) or {}
    question = body.get("question", "").strip()
    if not question:
        return jsonify({"ok": False, "error": "question required"}), 400
    jurisdiction = (body.get("jurisdiction") or "").strip()
    practice_area = (body.get("practice_area") or "").strip()
    matter_context = (body.get("matter_context") or "").strip()

    # If the attorney didn't fill in the jurisdiction field, try to extract it
    # from the question text so CourtListener can filter by the right court.
    if not jurisdiction:
        _JX_NAMES = {
            "nevada": "Nevada", "california": "California", "texas": "Texas",
            "new york": "New York", "florida": "Florida", "washington": "Washington",
            "oregon": "Oregon", "arizona": "Arizona", "colorado": "Colorado",
            "utah": "Utah", "illinois": "Illinois", "ohio": "Ohio",
            "michigan": "Michigan", "georgia": "Georgia", "north carolina": "North Carolina",
            "virginia": "Virginia", "federal": "federal", "ninth circuit": "9th circuit",
        }
        q_lower = question.lower()
        for phrase, jx_val in _JX_NAMES.items():
            if phrase in q_lower:
                jurisdiction = jx_val
                break

    # Search real legal databases first so the LLM cites actual cases
    from tools import legal_research as tool_legal
    db_results = {}
    try:
        db_results = tool_legal.search(question, jurisdiction=jurisdiction,
                                       practice_area=practice_area)
        log.info(f"legal research db: {db_results.get('total', 0)} results "
                 f"for {question!r}")
    except Exception as e:
        log.warning(f"legal db search failed: {e}")

    db_block = tool_legal.format_for_prompt(db_results) if db_results else ""

    research_prompt = mod_legal.build_research_prompt(
        question,
        jurisdiction=jurisdiction,
        practice_area=practice_area,
        matter_context=matter_context,
        db_results_block=db_block,
    )
    system = (
        "You are an experienced paralegal with expertise in legal research. "
        "Produce thorough, well-organized research memos for attorney review. "
        "ONLY cite cases and statutes that appear in the REAL LEGAL RESEARCH "
        "RESULTS block above — do NOT invent citations. If the databases "
        "returned no results for a point, say so explicitly so the attorney "
        "knows to search manually. Always flag SOL issues and unsettled law. "
        "Never give legal advice directly to clients."
    )
    try:
        memo = llm_client.generate_legal(CONFIG, system,
                                        [{"role": "user", "content": research_prompt}]).text
    except Exception as e:
        log.exception("legal research failed")
        return jsonify({"ok": False, "error": str(e)}), 500
    audit.log_event(DATA_DIR, actor=s["username"], action="legal.research",
                   resource=question[:80])
    return jsonify({
        "ok": True,
        "question": question,
        "memo": memo,
        "sources_found": db_results.get("total", 0),
        "cases_found": len(db_results.get("cases", [])),
    })

