# Regenerate draft with LLM + save to drafts

@app.route("/api/owner/legal/draft", methods=["POST"])
def legal_draft_document():
    s = _require_legal_module()
    body = request.get_json(force=True) or {}
    template_key = body.get("template_key") or body.get("template", "")
    fields = body.get("field_values") or body.get("fields", {})
    matter_id = body.get("matter_id", "") or ""
    matter_title_override = body.get("matter_title", "")

    draft_prompt = mod_legal.build_draft_prompt(template_key, fields)
    if not draft_prompt:
        return jsonify({"ok": False, "error": "unknown template"}), 400

    tmpl = mod_legal.get_template(template_key)
    matter = mod_legal.get_matter(DATA_DIR, matter_id) if matter_id else None
    matter_title = (matter.get("title", "") if matter else
                    matter_title_override or fields.get("case_title", ""))

    system = (
        "You are a highly experienced paralegal. Draft the complete legal document "
        "requested — not a shell, not an outline, a finished draft ready for attorney "
        "review. Be thorough and professional. Use proper legal formatting. Mark any "
        "section where attorney judgment is required with [ATTORNEY REVIEW NEEDED]. "
        "End every document with: 'Prepared by myOrby AI Paralegal — for attorney "
        "review and approval only. Not for distribution without attorney authorization.'"
    )
    try:
        content = llm_client.generate_legal(CONFIG, system, [{"role":"user","content":draft_prompt}]).text
    except Exception as e:
        log.exception("legal draft failed")
        return jsonify({"ok": False, "error": str(e)}), 500

    saved = mod_legal.save_draft(
        DATA_DIR,
        matter_id=matter_id,
        matter_title=matter_title,
        template_key=template_key,
        template_name=tmpl.get("name", template_key) if tmpl else template_key,
        content=content,
        fields=fields,
    )
    audit.log_event(DATA_DIR, actor=s["username"], action="legal.draft.create",
                   resource=f"{template_key} for {matter_title}")
    return jsonify({"ok": True, "template": template_key,
                    "draft": saved})

@app.route("/api/owner/legal/drafts/<draft_id>/export")
def legal_draft_export(draft_id):
    """Return a legal draft as a printable HTML page."""
    _require_legal_module()
    draft = mod_legal.get_draft(DATA_DIR, draft_id)
    if not draft:
        # Try prefix match
        all_drafts = mod_legal.list_drafts(DATA_DIR)
        matches = [d for d in all_drafts if d["id"].startswith(draft_id)]
        draft = matches[0] if matches else None
    if not draft:
        return jsonify({"error": "draft not found"}), 404

    content_html = (draft.get("content") or "")
    content_html = content_html.replace("&", "&amp;").replace("<", "&lt;").replace(">", "&gt;")
    content_html = content_html.replace("\n\n", "</p><p>").replace("\n", "<br>")
    content_html = f"<p>{content_html}</p>"

    name = draft.get("template_name", "Legal Document")
    matter = draft.get("matter_title", "")
    status = draft.get("status", "draft").upper()
    created = draft.get("created_at", 0)
    import datetime as _dt
    date_str = _dt.datetime.fromtimestamp(created).strftime("%B %d, %Y") if created else ""

    html = f"""<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<title>{name} — {matter}</title>
<style>
  body {{ font-family: "Times New Roman", Times, serif; font-size: 12pt;
         margin: 1in; line-height: 1.6; color: #000; }}
  h1 {{ font-size: 14pt; text-align: center; margin-bottom: 4px; }}
  .meta {{ text-align: center; font-size: 10pt; color: #444; margin-bottom: 24px; }}
  .status {{ display: inline-block; padding: 2px 8px; border: 1px solid #999;
             font-size: 9pt; margin-left: 8px; }}
  .content {{ white-space: pre-wrap; }}
  .footer {{ margin-top: 48px; font-size: 9pt; color: #666; border-top: 1px solid #ccc; padding-top: 8px; }}
  @media print {{
    .no-print {{ display: none; }}
    body {{ margin: 0.75in; }}
  }}
</style>
</head>
<body>
<div class="no-print" style="background:#f0f4ff;padding:12px;margin-bottom:20px;border-radius:6px;font-family:sans-serif;font-size:12px;">
  <strong>Print this document:</strong> Use your browser's File → Print (or Ctrl+P / Cmd+P).
  This banner will not appear on the printed page.
</div>
<h1>{name}</h1>
<div class="meta">
  {matter} &nbsp;·&nbsp; {date_str}
  <span class="status">{status}</span>
</div>
<hr>
<div class="content">{content_html}</div>
<div class="footer">Generated by myOrby AI Paralegal &nbsp;·&nbsp; For attorney review only &nbsp;·&nbsp; Not for distribution without attorney authorization</div>
</body>
</html>"""

    from flask import Response
    return Response(html, mimetype="text/html",
                    headers={"Content-Disposition": f'inline; filename="{name.replace(" ","_")}.html"'})


@app.route("/api/owner/legal/billing/invoice/<matter_id>", methods=["GET"])
def legal_billing_invoice(matter_id):
    """Generate a plain-text billing invoice from all unbilled time entries
    for a matter. Returns the formatted invoice text + totals."""
    s = _require_legal_module()
    matter = mod_legal.get_matter(DATA_DIR, matter_id)
    if not matter:
        return jsonify({"error": "matter not found"}), 404

    entries = mod_legal.list_time(DATA_DIR, matter_id=matter_id, billed=False)
    if not entries:
        return jsonify({"ok": True, "invoice_text": "No unbilled time entries found for this matter.",
                        "entry_count": 0, "total": 0.0, "matter_title": matter.get("title", "")})

    from datetime import date as _date
    today = _date.today().isoformat()
    firm_name = matter.get("firm_name") or (CONFIG.get("business") or {}).get("name") or "Law Office"
    atty_name = matter.get("attorney_name") or ""
    client    = matter.get("client_name") or "Client"
    rate      = float(matter.get("rate") or 0)

    lines = [
        f"{'=' * 62}",
        f"  LEGAL BILLING STATEMENT",
        f"  {firm_name}",
        (f"  {atty_name}" if atty_name else ""),
        f"{'=' * 62}",
        f"",
        f"  TO:      {client}",
        f"  MATTER:  {matter.get('matter_number', '')} — {matter.get('title', '')}",
        f"  COURT:   {matter.get('court', '') or 'N/A'}",
        f"  CASE #:  {matter.get('case_number', '') or 'N/A'}",
        f"  DATE:    {today}",
        f"",
        f"{'─' * 62}",
        f"  {'DATE':<12} {'DESCRIPTION':<32} {'HRS':>5} {'RATE':>8} {'AMOUNT':>9}",
        f"{'─' * 62}",
    ]
    subtotal = 0.0
    for e in sorted(entries, key=lambda x: x.get("date", "")):
        d    = (e.get("date") or "")[:10]
        desc = (e.get("description") or "")[:30]
        hrs  = float(e.get("hours") or 0)
        r    = float(e.get("rate") or rate)
        amt  = float(e.get("amount") or (hrs * r))
        subtotal += amt
        lines.append(f"  {d:<12} {desc:<32} {hrs:>5.2f} ${r:>7.2f} ${amt:>8.2f}")

    lines += [
        f"{'─' * 62}",
        f"  {'TOTAL DUE:':<51} ${subtotal:>8.2f}",
        f"{'=' * 62}",
        f"",
        f"  Please remit payment within 30 days.",
        f"  Questions: contact {firm_name}.",
        f"",
        f"  Prepared by myOrby AI Paralegal — attorney review required",
        f"  before sending to client.",
    ]
    invoice_text = "\n".join(l for l in lines if l is not None)

    return jsonify({
        "ok": True,
        "matter_title": matter.get("title", ""),
        "matter_number": matter.get("matter_number", ""),
        "invoice_text": invoice_text,
        "entry_count": len(entries),
        "total": round(subtotal, 2),
        "entries": entries,
    })


