@app.route("/api/public/business_summary")
def public_business_summary():
    """Lightweight, no-auth snapshot for the visitor-facing chat shell.
    Returns ONLY what's safe for any visitor to see. Multi-tenant: picks
    the business profile based on parent-origin / referer (same logic as
    /chat) so the widget header on purblum.com says 'PurBlum' not the
    default 'myOrbi'."""
    business = _resolve_business_profile_for_request(request)
    biz_name = (business.get("name") or CONFIG.get("business", {}).get("name", ""))
    biz_norm = biz_name.lower().replace(" ", "").replace("-", "")
    _is_sales = biz_norm in ("myorbi", "myorby")
    if _is_sales:
        actions = [
            "What is Orby?",
            "How much does it cost?",
            "How does the phone answering work?",
            "Can I see a demo?",
        ]
    else:
        scope = CONFIG.get("scope", {})
        actions = ["Are you open right now?", "Where are you located?"]
        if business.get("services") or business.get("menu"):
            actions.append("What do you offer?")
        if scope.get("public_can_take_orders"):
            actions.append("I'd like to place an order")
        if scope.get("public_can_book_appointments"):
            actions.append("Can I book an appointment?")
        if scope.get("public_can_request_quotes"):
            actions.append("I'd like a quote")
    return jsonify({
        "name": biz_name,
        "tagline": business.get("tagline", ""),
        "welcome": True,
        "quick_actions": actions[:4],
    })

# ---------------------------------------------------------------------------
# Public chat
# ---------------------------------------------------------------------------

def _try_public_lead_capture(message: str, visitor: dict | None = None,
                             history: list | None = None) -> dict | None:
    """Capture visitor contact info from public chat without invoking owner
    SMS/email workflows. Handles natural lead replies like:
    'My name is Test Lead and my phone is 775-555-1212'.

    Mid-conversation (visitor already got at least one Orby reply): saves
    the lead silently and returns None so the LLM can acknowledge naturally
    and keep the conversation going.
    Fresh start (opening message contains contact info): saves and returns
    a short friendly ACK so the LLM call is skipped."""
    text = " ".join(str(message or "").split()).strip()
    visitor = visitor or {}
    phone_m = _re.search(r"(\+?\d[\d\-\(\)\s]{7,}\d)", text)
    email_m = _re.search(r"[\w.\-+]+@[\w.\-]+\.\w+", text)
    name = str(visitor.get("name") or "").strip()
    name_m = _re.search(
        r"\b(?:my\s+name\s+is|name\s+is|i\s+am|i'm)\s+"
        r"(?P<name>[A-Z][A-Za-z'\-]+(?:\s+[A-Z][A-Za-z'\-]+){0,3})\b",
        text,
    )
    if name_m:
        name = name_m.group("name").strip()
    phone = str(visitor.get("phone") or "").strip()
    if phone_m:
        phone = phone_m.group(1).strip()
    email_addr = str(visitor.get("email") or "").strip()
    if email_m:
        email_addr = email_m.group(0).strip()
    if not (phone or email_addr):
        return None
    try:
        captured = mod_messages.capture(
            DATA_DIR,
            msg_type="lead",
            from_name=name or None,
            from_phone=phone or None,
            from_email=email_addr or None,
            body=text[:500],
            source="public_chat",
            config=CONFIG,
        )
        try:
            notify.send(
                CONFIG, DATA_DIR, event="new_lead",
                title=f"New lead: {name or phone or email_addr}",
                body=text[:200], url="/owner",
            )
        except Exception:
            pass
        # Mid-conversation: lead saved, fall through to LLM so Orby
        # acknowledges naturally and keeps the conversation going.
        prior_replies = [m for m in (history or []) if m.get("role") == "assistant"]
        if prior_replies:
            return None
        # Opening message contained contact info: short friendly ACK.
        greeting = f"Got it, {name}! " if name else "Thanks! "
        return {"reply": f"{greeting}What can I help you with?",
                "tier": "local", "source": "public_lead_captured",
                "message_id": captured.get("id")}
    except Exception as e:
        log.warning(f"public lead capture failed: {e}")
        return None  # fall through to LLM rather than showing an error

@app.route("/chat", methods=["POST"])
def public_chat():
    if not BILLING_STATUS.get("active", True):
        return jsonify({
            "reply": (
                f"This {CONFIG.get('business', {}).get('name', 'business')} "
                "assistant is temporarily paused. Please reach out by phone or email."
            ),
            "tier": "none",
            "billing_inactive": True,
        }), 200

    data = request.get_json(silent=True) or {}
    user_msg = (data.get("message") or "").strip()
    history  = data.get("history") or []  # list of {role, content}
    visitor  = data.get("visitor") or {}  # optional {name, phone, email}

    if not user_msg:
        return jsonify({"error": "empty message"}), 400

    # Resolve which business profile this chat is for FIRST — the privacy
    # guard below needs to know whether this is the myOrbi sales bot
    # (where visitors GIVE their contact info as part of the sale and
    # "my email is X" is normal) or a real customer's Orby (where
    # visitors should NOT be probing for the owner's personal data).
    business = _resolve_business_profile_for_request(request)
    _biz_name_norm = str((business.get("name") or "")).strip().lower().replace(" ", "")
    _is_sales_bot = _biz_name_norm in ("myorbi", "myorby")

    # Public chat is a visitor/sales surface. Owner-only actions such as
    # sending texts must happen in the signed-in owner dashboard, otherwise
    # the sales bot can produce confusing "I can't send texts" answers that
    # look like the personal Orbi is broken.
    _PUBLIC_SMS_ACTION_RE = _re.compile(
        r"\b(?:send|text|message|sms)\b.*\b(?:text|message|sms)\b"
        r"|\b(?:text|message|sms)\b.*\b(?:send|tell|ask|say|saying|let|notify)\b",
        _re.IGNORECASE,
    )
    if _PUBLIC_SMS_ACTION_RE.search(user_msg):
        return jsonify({
            "reply": (
                "I can't send owner texts from this public website chat. "
                "Use the signed-in owner dashboard and ask Orbi there. "
                "If you're a visitor and want the business to text you, "
                "leave your name and phone number."
            ),
            "tier": "local",
            "source": "public_owner_sms_action_blocked",
        }), 200

    # ─── PRIVACY GUARD ───────────────────────────────────────────────────
    # Public visitors must NOT be able to fish for owner-only data —
    # calendar, tasks, contacts, email, memory, staff list, file search,
    # or document generation. The owner's chat is at /api/owner/chat and
    # requires login; this endpoint is for visitors only and must refuse
    # any of those intents instead of letting the LLM hallucinate an
    # answer that could leak (or fabricate) personal info.
    #
    # 🚨 EXCEPTION: skip this guard entirely when the chat is the myOrbi
    # sales bot. The sales flow REQUIRES the visitor to provide their
    # own contact info ("my email is X", "my phone is Y", "I want to
    # book a Pro plan") — that's not fishing, that's purchasing. The
    # regex below was tripping legitimate sales-chat replies like
    # "my email address is franklstreet@icloud.com" and dropping the
    # visitor into the canned visitor-restriction fallback.
    _PERSONAL_INTENT_RE = _re.compile(
        r"\b("
        r"my\s+(?:calendar|schedule|agenda|todo|task|tasks|inbox|email|emails|"
            r"contacts?|reminders?|staff|employees|team|notes?|memory|"
            r"day|files?|folder|orbi\s+folder|workspace)"
        r"|what(?:'s| is)?\s+(?:on\s+)?(?:my\s+)?(?:calendar|schedule|inbox|todo)"
        r"|show\s+me\s+(?:my\s+)?(?:calendar|inbox|emails?|tasks?|reminders?|"
            r"contacts?|files?|day|staff|employees|todo)"
        r"|find\s+(?:emails?\s+(?:from|about)|the\s+file\s+about)"
        r"|search\s+(?:my\s+)?(?:emails?|inbox|files?|everything)"
        r"|email\s+[A-Z][a-zA-Z]+(?:\s+[A-Z][a-zA-Z]+)?[\s:,]"
        r"|reply\s+to\s+(?:the\s+)?(?:last\s+)?(?:email|message)\s+from"
        r"|(?:remind|nudge)\s+me\b"
        r"|task:\s|todo:\s"
        r"|appointment\s+with\s+|book\s+(?:a\s+)?(?:meeting|appointment)"
        r"|add\s+[A-Z][a-z]+\s+[A-Z][a-z]+,"
        r"|change\s+\w+'s\s+(?:phone|email|address)"
        r"|(?:what\s+do\s+you\s+(?:remember|know)\s+about)"
        r"|(?:write|draft|build|make|create|generate|compose)\s+(?:me\s+)?"
            r"(?:a\s+|an\s+)?(?:letter|spreadsheet|sheet|chart|deck|"
            r"powerpoint|presentation|ad|advertisement|invoice|proposal|"
            r"flyer|brief|report|document|doc|essay)"
        r"|(?:who'?s|who\s+is)\s+on\s+(?:my\s+)?(?:staff|team)"
        r"|morning\s+brief|show\s+me\s+my\s+day"
        r"|what'?s\s+(?:coming\s+up\s+)?(?:tomorrow|next\s+week)"
        r"|search\s+everything"
        r")\b",
        _re.IGNORECASE,
    )
    if not _is_sales_bot and _PERSONAL_INTENT_RE.search(user_msg):
        biz_name_for_refusal = (business.get("name") or "this business")
        return jsonify({
            "reply": (
                f"I can only help with questions about {biz_name_for_refusal} "
                f"— hours, services, ordering, location, or leaving a "
                f"message for the owner. Anything personal (calendar, "
                f"contacts, files, emails) is for the owner only — "
                f"if you're the owner, you'd need to sign in at "
                f"`/owner/login` to access that."
            ),
            "tier": "local",
            "source": "personal_intent_blocked",
        }), 200

    lead_capture = _try_public_lead_capture(user_msg, visitor, history=history)
    if lead_capture is not None:
        return jsonify(lead_capture), 200

    # Multi-tenant routing: business profile already resolved above (the
    # privacy guard needed it to detect sales-bot mode).
    scope    = dict(CONFIG.get("scope") or {})

    # Auto-enable ordering for any business profile that has both a menu
    # and an order_submission config — regardless of what the global
    # config.json says. This is the right default for restaurant profiles:
    # if the business can accept orders (kitchen email/printer wired up)
    # and has a menu, Orby should be instructed to collect name + phone.
    if (business.get("menu_items") and business.get("order_submission")
            and not scope.get("public_can_take_orders")):
        scope = dict(scope)
        scope["public_can_take_orders"] = True

    # SALES BOT prospect attachment — when the visitor on twickell.com told
    # Orby their business URL and the client already triggered a scrape,
    # `prospect_url` is forwarded here. We load the freshly-scraped profile
    # and stash it on the business dict so prompts.py can inject a PROSPECT
    # BUSINESS section. Orby stays as myOrbi (the sales bot) but now KNOWS
    # the prospect's business.
    prospect_url_raw = (data.get("prospect_url") or "").strip()
    if prospect_url_raw:
        try:
            from site_scraper.storage import domain_from_url
            prospect_slug = domain_from_url(prospect_url_raw)
            # Prefer the dedicated sales scrape result (<slug>_prospect.json)
            # over any canonical customer profile (<slug>.json). This lets
            # us test the sales flow against URLs we already have curated
            # data for (purblum.com) without conflating the two.
            prospect_path = DATA_DIR / "customer_profiles" / f"{prospect_slug}_prospect.json"
            if not prospect_path.exists():
                prospect_path = DATA_DIR / "customer_profiles" / f"{prospect_slug}.json"
            if prospect_path.exists():
                with prospect_path.open("r", encoding="utf-8") as _pf:
                    business["_prospect_business"] = json.load(_pf)
                    business["_prospect_url"] = prospect_url_raw
        except Exception as _e:
            log.warning(f"prospect_url load failed for {prospect_url_raw!r}: {_e}")

    # REFERRAL — "where can I get one of these for my business?"
    # Single-sentence URL + redirect to host business. Only fires on direct
    # ask; never volunteers (LLM is prompt-gated). Toggleable in Settings.
    referral_resp = _try_orby_referral(user_msg, business)
    if referral_resp is not None:
        return jsonify(referral_resp)

    system   = prompts.build_public_prompt(business, scope)

    # PRE-EXECUTE — fast local answer for common questions (greetings,
    # time, date, hours, address, phone, catalog count). When this fires
    # with "direct", we skip the LLM entirely — instant answer, $0 cost,
    # zero hallucination risk. When it returns "data:..." we still call
    # the LLM but with authoritative data injected, so the LLM only
    # composes wording around real facts (109 tokens instead of 6,302
    # per the my_orby measurement).
    # MUST run AFTER the wellbeing check below so crisis messages don't
    # get reduced to a "Hi! What can I help with?" greeting reply.
    pre_resp, pre_kind = pre_exec.pre_execute(user_msg, DATA_DIR, business)
    # We defer the direct-return until after wellbeing has had its say.

    # WELLBEING — scan EVERY public-chat message for crisis / distress signals
    # BEFORE we route to learned answers, catalog, or the LLM. If a signal
    # fires, log it for the owner's dashboard AND inject the appropriate
    # system-prompt context so Orby handles the moment with care instead
    # of barreling into the buy flow. (Ported from orby_5050/engine/wellbeing.py)
    _wb_level = "ok"
    try:
        _wb = wellbeing.check_message(user_msg)
        _wb_level = _wb["level"]
        if _wb_level != "ok":
            wellbeing.log_flag(DATA_DIR, _wb_level, _wb["signal"],
                                user_msg, source="chat")
            log.warning("public chat wellbeing flag fired: level=%s signal=%r",
                        _wb_level, _wb["signal"])
            if _wb_level == "crisis":
                system += "\n\n" + wellbeing.get_crisis_context()
            else:
                system += "\n\n" + wellbeing.get_distress_context()
    except Exception as e:
        log.warning(f"wellbeing check failed: {e}")

    # PRIORITY 0a — pre_execute DIRECT answers (only if wellbeing didn't
    # flag the message; we want crisis messages to get the careful LLM
    # path, not a chipper "Hi! What can I help with?" greeting reply).
    if pre_kind == "direct" and _wb_level == "ok":
        log.info("pre_execute direct hit: %r", pre_resp[:60])
        return jsonify({"reply": pre_resp, "tier": "local"}), 200

    # PRIORITY 0b — LEARNED ANSWERS (never-guess pattern). If the OWNER has
    # already answered this exact question for a previous visitor, return
    # that answer instantly without calling the LLM. This is what makes
    # Orby's knowledge compound over time and never invent facts about
    # the business.
    learned = mod_learning.find_learned(DATA_DIR, user_msg)
    if learned:
        log.info("learned-answer hit (asked %sx)", learned.get("asked_count", 1))
        return jsonify({
            "reply": learned["answer"],
            "tier": "learned",
            "verified": True,
        }), 200

    # PRIORITY 0c — pre_execute DATA hits (e.g. catalog count, services).
    # The LLM still composes the reply but with authoritative business
    # data injected so it can't invent.
    if pre_kind and pre_kind.startswith("data:"):
        extras_pre = ("LOCAL BUSINESS DATA (AUTHORITATIVE — quote exactly, "
                      "don't paraphrase, don't invent):\n" + pre_resp)
        system += "\n\n" + extras_pre
        log.info("pre_execute data hit: kind=%s len=%d", pre_kind, len(pre_resp))

    # Public chat gets workspace context first (so she can answer about
    # promotions, menus, FAQs the owner dropped into ~/Orby/) — these are
    # AUTHORITATIVE. Web search only fires if workspace had no strong match
    # AND the query smells like it needs current info.
    extras = []

    # PRIORITY 1 — PRODUCT CATALOG (highest authority).
    # If the owner has dropped a CSV / Excel into Orby/Catalog/, surface
    # matching items BEFORE workspace and web. Catalog data is the most
    # specific real-world info Orby can use (real SKUs, real prices, real
    # stock counts) — never let the LLM invent product details when the
    # catalog has the answer.
    try:
        cat_matches = mod_catalog.search(DATA_DIR, user_msg, limit=5)
        # Threshold: score >= 10 means at least one name-token matched OR
        # an exact SKU hit (which scores 1000). Below 10 is fuzzy noise.
        strong_cat = [m for m in cat_matches if m.get("score", 0) >= 10]
        if strong_cat:
            lines = ["PRODUCT CATALOG MATCHES (AUTHORITATIVE — these are real "
                     "items the owner sells. Quote name, SKU, price, and stock "
                     "EXACTLY from this list. Do NOT invent products or similar "
                     "items not shown here. If the visitor asks about a part NOT "
                     "in this list, say honestly 'I don't see that in our "
                     "current inventory — let me check with the owner and get "
                     "back to you. Can I get your name and number?'):"]
            for m in strong_cat:
                bits = [m.get("name", "")]
                if m.get("sku"):     bits.append(f"part #{m['sku']}")
                if m.get("price") is not None: bits.append(f"${m['price']:.2f}")
                if m.get("stock") is not None: bits.append(f"{m['stock']} in stock")
                if m.get("brand"):   bits.append(f"({m['brand']})")
                desc = (m.get("description") or "").strip()
                line = "  - " + " · ".join(b for b in bits if b)
                if desc:
                    line += f"\n      {desc[:160]}"
                lines.append(line)
            extras.append("\n".join(lines))
            log.info("public catalog hits: %d strong matches for %r", len(strong_cat), user_msg[:60])
    except Exception as e:
        log.warning(f"public catalog lookup failed: {e}")

    if is_module_enabled("retail"):
        try:
            retail_ctx = mod_retail.context_block(DATA_DIR)
            if retail_ctx:
                extras.append(retail_ctx)
        except Exception as e:
            log.warning(f"retail context failed: {e}")

    # Priority decision — three-way:
    #   STRONG workspace match (score >= 3) → workspace wins, even for fresh queries.
    #     "What's special right now?" → workspace has a high-scoring "promotion" file → use it.
    #   FRESH query (weather/news/today/etc) + no strong workspace → web search wins.
    #     "Weather in Reno right now" → workspace only weakly matches "Reno" → ignore, hit web.
    #   WEAK workspace match (score 1-2) and not a fresh query → workspace wins.
    #     "What do you do?" → no fresh keyword, workspace has some hits → use workspace.
    msg_lower = user_msg.lower()
    is_fresh_query = any(k in msg_lower for k in tool_web_search._FRESH_KEYWORDS)
    workspace_hit = False
    top_score = 0
    try:
        ws_matches = mod_workspace.search(CONFIG, DATA_DIR, user_msg, limit=3)
        if ws_matches:
            top_score = ws_matches[0].get("score", 0)
            # Workspace wins if it's a strong match, OR if it's a non-fresh query
            if top_score >= 3 or (top_score >= 1 and not is_fresh_query):
                workspace_hit = True
                ws_ctx = mod_workspace.context_block(CONFIG, DATA_DIR, user_msg)
                if ws_ctx:
                    extras.append(
                        "OWNER'S WORKSPACE FILES (AUTHORITATIVE — quote exactly, "
                        "don't paraphrase, don't invent alternatives):\n" + ws_ctx
                    )
                    log.info(f"public workspace hit: top score {top_score}, fresh={is_fresh_query}")
    except Exception as e:
        log.warning(f"public workspace context failed: {e}")
    if not workspace_hit and tool_web_search.needs_web_search(user_msg):
        try:
            web_ctx = tool_web_search.context_block(user_msg)
            if web_ctx:
                extras.append(
                    "WEB SEARCH RESULTS (current real-time info). Quote facts "
                    "directly from these results. If the specific answer the "
                    "user asked about is NOT in the results below, say so "
                    "honestly — do NOT fall back to your training data or "
                    "invent facts.\n" + web_ctx
                )
                log.info(f"public web search: {user_msg[:60]!r}")
        except Exception as e:
            log.warning(f"public web search failed: {e}")

    # URL FETCH — if the visitor pasted a specific URL, go fetch the page
    try:
        urls_in_msg = tool_url_fetch.extract_urls(user_msg)[:3]
        if urls_in_msg:
            fetched = [tool_url_fetch.fetch_or_search(u) for u in urls_in_msg]
            url_ctx = tool_url_fetch.context_block(fetched)
            if url_ctx:
                extras.append(url_ctx)
                log.info(f"public url_fetch: {len(urls_in_msg)} url(s)")
    except Exception as e:
        log.warning(f"public url_fetch failed: {e}")
    if extras:
        system += "\n\n" + "\n\n".join(extras)

    # AUTHORITATIVE ORDER TOTALS — if the conversation has order intent,
    # extract → cart → compute exact subtotal/tax/total in Python (not in
    # the LLM, which makes arithmetic mistakes on multi-line money math).
    # Inject the exact dollars as a system fact so the LLM quotes them
    # verbatim when the customer asks "how much?" or at the end-summary.
    _injected_totals = None  # filled in below, used in the response JSON
    try:
        history_for_total = [m for m in history if m.get("role") in ("user", "assistant")]
        history_for_total.append({"role": "user", "content": user_msg})
        # Latency fix — only run the expensive extraction when the customer
        # is closing the order or explicitly asking the price. Mid-order
        # modifier collection ("12 inch", "no onions") does NOT need totals.
        if (_looks_like_order_chat(history_for_total)
            and _is_end_of_order_message(user_msg)
            and business.get("menu_items")):
            import phone_order
            # Construct a menu dict that phone_order.load_menu would have
            # produced — categories+items+modifier_groups schema.
            menu_for_compute = _menu_dict_from_profile(business)
            extracted = phone_order.extract_order_from_history(
                history_for_total, menu_for_compute, llm_client, CONFIG,
            )
            if extracted.get("ok") and extracted.get("items"):
                cart, _warn = phone_order.build_cart_for_purblum(extracted["items"], menu_for_compute)
                phone_order.annotate_cart_with_menu_prices(cart, menu_for_compute)
                totals = phone_order.compute_cart_total(cart, business.get("tax_rate", 0))
                if totals["subtotal"] > 0:
                    lines = ["⚠️ AUTHORITATIVE ORDER TOTALS — YOU MUST INCLUDE THESE",
                             "These prices were computed by Python from the canonical menu.",
                             "When you summarize the order or the customer asks the price,",
                             "INCLUDE these numbers verbatim. Do NOT omit them. Do NOT round.",
                             "Do NOT guess different numbers.",
                             ""]
                    for li in totals["lines"]:
                        lines.append(f"  • {li['qty']}x {li['name']}: ${li['line_total']:.2f}")
                    lines.append("")
                    lines.append(f"  SUBTOTAL: ${totals['subtotal']:.2f}")
                    if totals['tax_rate_pct']:
                        lines.append(f"  TAX ({totals['tax_rate_pct']:.2f}%): ${totals['tax']:.2f}")
                        lines.append(f"  TOTAL: ${totals['total']:.2f}")
                    lines.append("")
                    lines.append("Quote these exact dollar figures in your end-of-order summary.")
                    system += "\n\n" + "\n".join(lines)
                    # Stash for the response JSON so the chat widget can
                    # render a live cart panel.
                    _injected_totals = totals
                    log.info(f"chat order totals injected: subtotal=${totals['subtotal']} total=${totals['total']}")
    except Exception as e:
        log.warning(f"chat order-totals injection failed: {e}")

    messages = [m for m in history if m.get("role") in ("user", "assistant")][-10:]
    messages.append({"role": "user", "content": user_msg})

    # Visitor rate limit — protect the LLM budget from runaway loops or
    # malicious traffic. Identity = client IP for unauthenticated chat.
    _visitor_ip = request.headers.get("X-Forwarded-For", request.remote_addr or "anon")
    _rl_ok, _rl_used, _rl_cap = rate_limit.check_and_increment(_visitor_ip, role="visitor")
    if not _rl_ok:
        log.warning(f"public chat rate-limited: {_visitor_ip} {_rl_used}/{_rl_cap}")
        return jsonify({
            "reply": ("I've been quite busy today. Please try again in a little while, "
                      "or leave your name and number and someone will reach out."),
            "tier": "rate_limited", "latency_ms": 0,
        })

    # Pin already-captured sales info into the system prompt so the LLM
    # can't ask for the same thing twice. The sales prompt covers the
    # field list ("ask for name, then biz, then email, then phone"), but
    # over 29k chars of instructions + 20 turns of history, the LLM
    # loses track and re-asks. Scanning history for already-given values
    # and pinning them as authoritative cuts the "she keeps asking my
    # name" failure mode.
    _captured = _extract_captured_sales_info(history)
    if _captured:
        pin_lines = ["\nALREADY CAPTURED FROM THIS CONVERSATION — "
                      "DO NOT ASK AGAIN:"]
        for k, v in _captured.items():
            pin_lines.append(f"  · {k}: {v}")
        pin_lines.append("If you need additional fields, ask ONLY for the "
                          "missing ones. Never re-ask anything in the list "
                          "above.")
        system = system + "\n" + "\n".join(pin_lines)

    # Inline helper used by the NAV fallback below to extract customer
    # info (name, email, phone, biz, seats) from the conversation history's
    # recap message. terms.html accepts these as query params and pre-fills
    # the acceptance record so the customer doesn't have to retype.
    def _extract_customer_params_from_history(msgs):
        import re as _re_local
        params = {}
        full_text = "\n".join(str(m.get("content", "")) for m in msgs)
        recap_match = _re_local.search(
            r"([A-Z][A-Za-z'\-]+(?:\s+[A-Z][A-Za-z'\-]+)?)\s+at\s+"
            r"([A-Za-z0-9'&,\-\s]+?),\s+"
            r"([A-Za-z0-9._%+\-]+@[A-Za-z0-9.\-]+\.[A-Za-z]{2,}),\s+"
            r"([0-9\-\(\)\s\+]{10,20}),\s+"
            r"(\d{1,3})\s*seats?",
            full_text,
        )
        if recap_match:
            params["name"] = recap_match.group(1).strip()
            params["biz"] = recap_match.group(2).strip().rstrip(",.")
            params["email"] = recap_match.group(3).strip()
            params["phone"] = recap_match.group(4).strip()
            params["seats"] = recap_match.group(5).strip()
            return params
        em = _re_local.search(r"([A-Za-z0-9._%+\-]+@[A-Za-z0-9.\-]+\.[A-Za-z]{2,})", full_text)
        if em:
            params["email"] = em.group(1)
        ph = _re_local.search(r"\b(\d{3}[-.\s]?\d{3}[-.\s]?\d{4})\b", full_text)
        if ph:
            params["phone"] = ph.group(1)
        # Standalone seats fallback — scan the ENTIRE conversation for any
        # mention of N seats/seat. Use the LAST match so later corrections
        # (customer says "actually 3") win over earlier guesses.
        seats_all = _re_local.findall(r"\b(\d{1,2})\s*seats?\b", full_text, _re_local.IGNORECASE)
        if seats_all:
            params["seats"] = seats_all[-1]
        return params

    resp = llm_client.generate(CONFIG, system, messages)
    # Auto-retry once when LLM came back empty — handles HuggingFace
    # transient timeouts. Without this, visitors hit "I'm having
    # trouble reaching my AI" mid-conversation and Orby loses track
    # of state on the next turn.
    if not (resp and resp.text and resp.text.strip()):
        log.info("LLM came back empty on first try — retrying once")
        resp = llm_client.generate(CONFIG, system, messages)

    # SALES SCRAPE marker — when the SALES MODE OVERRIDE prompt has the bot
    # ask for the visitor's URL and the visitor provides one, the LLM emits
    # `<<SCRAPE:url>>` in its reply. Strip it from the user-visible text and
    # forward the URL to the client so chat.js can fire /api/public/sales_scrape.
    _sales_scrape_request = None
    # SCRAPE FALLBACK (added 2026-06-22): the LLM keeps saying "Cool,
    # looking at example.com now — give me about a minute" but drops the
    # <<SCRAPE:...>> marker, so the scrape never fires and the customer
    # waits forever. Detect the "looking at <url>" phrasing in the LLM
    # response when no marker is present and synthesize the marker.
    if (resp and resp.text and "<<SCRAPE:" not in resp.text
        and any(p in resp.text.lower() for p in (
            "looking at ", "checking out ", "pulling up ", "give me about a minute",
            "give me a sec",
        ))):
        try:
            _m = _re.search(
                r"(?:looking|checking|pulling)[^.?!\n]*?"
                r"((?:https?://)?[a-z0-9][a-z0-9-]*(?:\.[a-z0-9][a-z0-9-]*)+(?:/[^\s)]*)?)",
                resp.text, flags=_re.IGNORECASE,
            )
            if _m:
                _u = _m.group(1).strip().rstrip(".,;:!?")
                if not _u.lower().startswith("http"):
                    _u = "https://" + _u
                # Replace the entire LLM output with a clean Phase 4 template
                # so any hallucinated Phase 4.1 content (training-data business
                # info) gets discarded. The LLM dropped the marker AND ignored
                # FULL STOP — we can't trust anything it wrote after "looking at".
                resp.text = f"Cool, looking at {_u} now — give me about a minute. <<SCRAPE:{_u}>>"
                log.info(f"chat: SCRAPE fallback fired (LLM dropped marker), url={_u}")
        except Exception as _e:
            log.warning(f"SCRAPE fallback failed: {_e}")

    if resp and resp.text and "<<SCRAPE:" in resp.text:
        try:
            _m = _re.search(r"<<SCRAPE:\s*(.+?)\s*>>", resp.text)
            if _m:
                _scrape_url = _m.group(1).strip()
                _sales_scrape_request = {"url": _scrape_url}
                # Keep only the text BEFORE the marker — the LLM frequently
                # ignores "FULL STOP" and appends Phase 4.1 content (using
                # hallucinated training-data knowledge) in the same response.
                # Anything after the <<SCRAPE:...>> tag is pre-emptive and
                # wrong; discard it so the customer only sees "Cool, looking
                # at your site now..." and nothing else until the real scrape
                # result comes back on the (continue) turn.
                _pre_marker = resp.text[: _m.start()].rstrip()
                resp.text = _pre_marker if _pre_marker else resp.text
        except Exception as _e:
            log.warning(f"SCRAPE marker parse failed: {_e}")

    # SALES NAV marker — at the end of the sales flow the LLM emits
    # `<<NAV:url>>` so the chat client navigates the visitor's browser
    # directly to the legal-acceptance + checkout page. Strip the marker
    # from the visible text and surface the URL.
    _sales_nav_request = None
    if resp and resp.text and "<<NAV:" in resp.text:
        try:
            _m = _re.search(r"<<NAV:\s*(.+?)\s*>>", resp.text)
            if _m:
                _nav_url = _m.group(1).strip()
                _ok_hosts = (
                    "https://billing.twickell.com/",
                    "https://twickell.com/",
                )
                if any(_nav_url.startswith(h) for h in _ok_hosts):
                    # REWRITE: Frank explicitly wants the chat NAV destination
                    # to be twickell.com/terms (the polished marketing-styled
                    # Terms of Service page), NOT billing.twickell.com/agree
                    # (the plain billing-side template). If the LLM emitted
                    # an /agree URL, rewrite to /terms?tier=<key> + customer
                    # info from history so terms.html can pre-fill the
                    # acceptance form.
                    _agree_m = _re.match(
                        r"https://billing\.twickell\.com/agree/([a-z_]+)",
                        _nav_url,
                    )
                    if _agree_m:
                        _tier_key = _agree_m.group(1)
                        try:
                            _customer_params = _extract_customer_params_from_history(messages)
                        except Exception:
                            _customer_params = {}
                        # SAFETY UPGRADE: if the LLM picked receptionist_mo
                        # but the conversation history shows Website Controller
                        # was pitched (Base + Receptionist + Website), upgrade
                        # to full_mo so the customer is charged for the bundle
                        # they actually agreed to.
                        if _tier_key in ("receptionist_mo", "receptionist_yr"):
                            _history_text = " ".join(
                                str(m.get("content", "")) for m in messages
                            ).lower()
                            if ("website controller" in _history_text
                                or "+ website" in _history_text
                                or "and website" in _history_text
                                or "everything" in _history_text
                                or "all of it" in _history_text):
                                _new = "full_yr" if _tier_key.endswith("_yr") else "full_mo"
                                log.info(f"chat: NAV tier upgrade "
                                         f"{_tier_key} -> {_new} (bundle includes Website)")
                                _tier_key = _new
                        from urllib.parse import urlencode
                        _qs = urlencode({"tier": _tier_key, **_customer_params})
                        _nav_url = f"https://twickell.com/terms?{_qs}"
                        log.info(f"chat: rewrote NAV {_agree_m.group(0)} -> "
                                  f"twickell.com/terms?tier={_tier_key}")
                    _sales_nav_request = {"url": _nav_url}
                resp.text = _re.sub(
                    r"\s*<<NAV:\s*.+?\s*>>\s*", " ", resp.text
                ).strip()
        except Exception as _e:
            log.warning(f"NAV marker parse failed: {_e}")

    # BUSINESS-NAME GUESS SCRUB (added 2026-06-22, revised 2026-06-22):
    # Frank's directive: USE what the scrape returned — state business name
    # confidently if you have it, only ask for what's missing. The earlier
    # bug was hedging ("is it likely X?", "maybe something like Y?") and
    # inventing variations from the URL. Only strip those weasel phrases;
    # let stated facts from a successful scrape survive.
    if (resp and resp.text):
        try:
            _l = resp.text.lower()
            if "business name" in _l or "biz name" in _l:
                _patterns = [
                    # Hedge / guess phrasings — strip these
                    r"\s*(is\s+it\s+(likely|the\s+same\s+as)\s+[^.?!\n]*[.?!]?)",
                    r"\s*,?\s*maybe\s+something\s+like\s+['\"][^'\"]+['\"][^.?!\n]*[.?!]?",
                    r"\s*,?\s*perhaps\s+['\"][^'\"]+['\"][^.?!\n]*[.?!]?",
                    r"\s*,?\s*likely\s+['\"][^'\"]+['\"][^.?!\n]*[.?!]?",
                    r"\s*,?\s*(or\s+does\s+it\s+go\s+by\s+something\s+else[?.!]?)",
                    # "but I want to confirm that with you" — drops the
                    # weak "confirm" verbiage but keeps the asserted name
                    r"\s*,?\s*but\s+I\s+want\s+(?:to\s+)?(?:confirm|verify)[^.?!\n]*[.?!]?",
                    r"\s*,?\s*but\s+I'?d?\s+like\s+to\s+(?:confirm|verify)[^.?!\n]*[.?!]?",
                    r"\s*so,?\s+to\s+confirm[\s:,]+",
                ]
                _orig = resp.text
                for _pat in _patterns:
                    resp.text = _re.sub(_pat, " ", resp.text, flags=_re.IGNORECASE)
                resp.text = _re.sub(r"\s{2,}", " ", resp.text).strip()
                if _orig != resp.text:
                    log.info("chat: scrubbed business-name hedge phrases")
        except Exception as _e:
            log.warning(f"biz-name scrub failed: {_e}")

    # PARENTHETICAL STAGE-DIRECTION SCRUB: LLM sometimes appends internal
    # narration as parenthetical asides despite the prompt ban, e.g.
    # "(Standing by while I review your site...)" or "(I'll get back to you
    # with details)". Strip any parenthetical that reads like a stage direction
    # — contains "standing by", "reviewing", "I'll", "just a", "hold on",
    # "scanning", "checking", "give me a", "be right", "one moment".
    if resp and resp.text:
        try:
            _stage_direction_re = _re.compile(
                r'\s*\([^)]{0,200}(?:'
                r'standing by|reviewing|just a|hold on|one moment|'
                r'give me a|be right|scanning|checking|I\'ll|I will|'
                r'working on|pulling up|looking at|on my way|sit tight|'
                r'note[:\s]|note —|scrape|didn\'t return|did not return'
                r')[^)]{0,800}\)',
                _re.IGNORECASE,
            )
            _orig = resp.text
            resp.text = _stage_direction_re.sub('', resp.text).strip()
            resp.text = _re.sub(r'\s{2,}', ' ', resp.text).strip()
            if _orig != resp.text:
                log.info("chat: scrubbed parenthetical stage-direction")
        except Exception as _e:
            log.warning(f"parenthetical scrub failed: {_e}")

    # NAV FALLBACK (added 2026-06-22): the sales-bot LLM (Qwen 72B via
    # Scaleway) reliably says "Perfect — sending you to the terms page now"
    # at close-out but routinely drops the <<NAV:...>> marker, leaving the
    # customer stranded on the chat. Detect close-out phrasing and inject
    # the right tier URL server-side based on conversation history.
    if (_sales_nav_request is None
        and resp and resp.text
        and any(p in resp.text.lower() for p in (
            "sending you to the terms",
            "heading to the terms",
            "heading to checkout",
            "off to the terms",
            "off to checkout",
            "send you to the terms",
            "send you to checkout",
        ))):
        try:
            history_text = " ".join(
                str(m.get("content", "")) for m in messages
            ).lower()
            # Infer tier from conversation history. Order matters —
            # check most-specific first.
            if "restaurant" in history_text and any(
                k in history_text for k in ("everything", "all of it", "full stack")
            ):
                _tier = "restaurant_mo"
            elif any(k in history_text for k in (
                    "everything", "all of it", "all of the above", "the whole thing"
            )):
                _tier = "full_mo"  # Base + Receptionist + Website Controller
            elif "website" in history_text and "phone" not in history_text and "receptionist" not in history_text:
                _tier = "website_mo"
            elif "phone" in history_text or "receptionist" in history_text:
                _tier = "receptionist_mo"
            elif "marketing" in history_text:
                _tier = "marketing_mo"
            elif "restaurant" in history_text:
                _tier = "restaurant_mo"
            else:
                _tier = "base_mo"
            # Send the customer to twickell.com/terms (the polished Terms of
            # Service page) with the tier + customer info as query params.
            # terms.html already knows how to read these, show the Accept
            # button, and forward to billing.twickell.com/agree-finalize
            # (which records acceptance and proceeds to Stripe checkout).
            # Frank 2026-06-22: explicitly wants the destination to be the
            # twickell-styled /terms page, NOT the plain billing.twickell.com
            # /agree page.
            try:
                _customer_params = _extract_customer_params_from_history(messages)
            except Exception:
                _customer_params = {}
            from urllib.parse import urlencode
            _qs = urlencode({"tier": _tier, **_customer_params})
            _sales_nav_request = {"url": f"https://twickell.com/terms?{_qs}"}
            log.info(f"chat: NAV fallback fired (LLM dropped marker), "
                     f"inferred tier={_tier}, "
                     f"customer_params={list(_customer_params.keys())}")
        except Exception as _e:
            log.warning(f"NAV fallback failed: {_e}")

    # LEARNING-LOOP TRIGGER — if Orby's reply reads like "I don't know"
    # AND the visitor was actually asking a question, kick off the
    # learning loop: capture the question for the owner to answer, ask
    # the visitor for their contact info, and override Orby's bluff
    # with a clear "I'll find out and get back to you" reply.
    # EXCEPTION: never trigger for general knowledge questions (weather,
    # facts, how-to, geography, science, etc.) — the LLM handles those.
    pending_record = None
    if (mod_learning.reply_indicates_unknown(resp.text or "")
        and mod_learning.is_question_form(user_msg)
        and not mod_learning.is_general_knowledge_question(user_msg)):
        try:
            asker = {
                "name":  (visitor.get("name") or "").strip(),
                "phone": (visitor.get("phone") or "").strip(),
                "email": (visitor.get("email") or "").strip(),
                "preferred_channel": (visitor.get("preferred_channel") or "").strip(),
            }
            session_id = (visitor.get("session_id") or "").strip()
            pending_record = mod_learning.capture_pending(
                DATA_DIR, question=user_msg, asker=asker, session_id=session_id,
            )
            log.info("learning loop captured: token=%s question=%r",
                     pending_record["token"], user_msg[:60])
            # Notify the owner. The body includes the question token
            # ("Q_xxx: ...") so when the owner replies by text/email,
            # the /api/internal/owner_reply webhook can parse the
            # reply and link the answer back to this pending question.
            try:
                asker_label = (asker.get("name") or asker.get("phone")
                               or asker.get("email") or "a visitor")
                token = pending_record["token"]
                notify.send(
                    CONFIG, DATA_DIR,
                    event="new_question",
                    title=f"Question from {asker_label}",
                    body=(
                        f"{token}: {user_msg[:200]}\n\n"
                        f"Reply to this with your answer — text/email reply "
                        f"will save it and deliver to {asker_label}."
                    ),
                    url="/owner#learning",
                )
                mod_learning.mark_owner_notified(
                    DATA_DIR, token, channel="auto",
                )
            except Exception as e:
                log.warning(f"owner notify failed: {e}")
            # Override Orby's reply with the standard "I'll find out" ask.
            # If the visitor already gave us contact info, thank them; if
            # not, ask for it so we can deliver the owner's answer back.
            have_contact = bool(asker.get("phone") or asker.get("email"))
            if have_contact:
                resp_text_override = (
                    f"That's a great question — I'm not sure about that one, "
                    f"so I'm going to make sure the owner gets you the right "
                    f"answer. I've got your contact info, and I'll reach out "
                    f"to you the moment I hear back. Anything else?"
                )
            else:
                resp_text_override = (
                    "That's a great question — I'm not sure about that one, "
                    "so I'm going to make sure the owner gets you the right "
                    "answer. Can I get your name and the best way to reach "
                    "you — text, call, or email?"
                )
            resp = type(resp)(text=resp_text_override, **{
                k: getattr(resp, k, None)
                for k in ("tier", "model", "latency_ms", "error")
                if hasattr(resp, k)
            }) if hasattr(resp, "_replace") is False else resp
            # If resp is a namedtuple or dataclass, can't easily replace —
            # just patch the text field if writable, else build a stub.
            try:
                resp.text = resp_text_override
            except (AttributeError, TypeError):
                class _R:
                    def __init__(self, text):
                        self.text = text
                        self.tier = getattr(resp, "tier", "learning_loop")
                        self.error = None
                resp = _R(resp_text_override)
        except Exception as e:
            log.warning(f"learning-loop capture failed: {e}")

    # Capture lead / order / callback if visitor info is present.
    # If the chat widget hasn't collected name/phone in its form, try to
    # pull them out of the message body itself (e.g. "call me back at
    # 555-1234, this is Bob"). If we still can't find a phone OR email,
    # the LLM reply will ask for it on the next turn — we override the
    # reply below in that case so the visitor isn't left hanging while
    # their lead silently vaporizes.
    capture_kind = _detect_capture(user_msg, scope)
    if capture_kind:
        extracted_name  = visitor.get("name")
        extracted_phone = visitor.get("phone")
        extracted_email = visitor.get("email")
        # Always run extraction so widget data + body-extracted data merge.
        body_text = _conversation_text(history, user_msg)
        if not extracted_phone:
            extracted_phone = _extract_phone(body_text)
        if not extracted_email:
            extracted_email = _extract_email(body_text)
        if not extracted_name:
            extracted_name = _extract_name(body_text)
        has_contact = bool(extracted_phone or extracted_email)
        if has_contact:
            try:
                captured = mod_messages.capture(
                    DATA_DIR,
                    msg_type=capture_kind,
                    from_name=extracted_name,
                    from_phone=extracted_phone,
                    from_email=extracted_email,
                    body=user_msg,
                    source="chat",
                )
                event_map = {"order": "new_order", "lead": "new_lead",
                             "callback": "new_lead", "voicemail": "new_voicemail"}
                from_label = extracted_name or extracted_phone or extracted_email or 'Unknown'
                notify.send(
                    CONFIG, DATA_DIR,
                    event=event_map.get(capture_kind, "new_message"),
                    title=f"New {capture_kind} from {from_label}",
                    body=user_msg[:200],
                    url="/owner",
                )
            except Exception as e:
                log.warning(f"capture failed: {e}")
        else:
            # No contact info found — override the LLM reply with a direct
            # ask so the visitor knows we need their info, AND so the next
            # message they send (with their phone) actually completes the
            # capture instead of disappearing into the LLM's wording.
            log.info("capture intent (%s) but no contact info — asking for it",
                      capture_kind)
            ask = ("Of course — what's the best name and phone number "
                   "for the owner to reach you at?")
            return jsonify({
                "reply": ask, "tier": "local", "latency_ms": 0,
                "source": "capture_needs_contact",
                "capture_pending": capture_kind,
            })

    return jsonify({
        "reply": resp.text or (
            "I'm having trouble reaching my AI right now. "
            "Please call us or try again in a moment."
        ),
        "tier": resp.tier,
        "latency_ms": resp.latency_ms,
        "billing_warning": BILLING_STATUS.get("warning"),
        # If the chat has order intent + an extractable cart, the widget
        # gets a live cart breakdown to render alongside Orby's reply.
        # Math is server-computed (deterministic) — the widget just displays.
        "order_summary": _injected_totals,
        # Sales-bot signal: when the LLM emitted <<SCRAPE:url>>, the client
        # picks this up and fires /api/public/sales_scrape on the URL, then
        # auto-sends a follow-up /chat with prospect_url set.
        "scrape_request": _sales_scrape_request,
        # Sales-bot signal: when the LLM emitted <<NAV:url>>, the client
        # navigates the visitor's browser DIRECTLY to that URL (legal
        # acceptance page → Stripe checkout). No hyperlink for the
        # visitor to click — the chat just sends them there.
        "navigate_request": _sales_nav_request,
    })

def _detect_capture(user_msg: str, scope: dict) -> str | None:
    msg = user_msg.lower()
    if scope.get("public_can_take_orders") and any(
        kw in msg for kw in ("order", "i'll have", "i want to buy", "can i get")
    ):
        return "order"
    if scope.get("public_can_book_appointments") and any(
        kw in msg for kw in ("appointment", "book", "schedule")
    ):
        return "lead"
    if scope.get("public_can_request_callbacks") and any(
        kw in msg for kw in ("call me back", "callback", "call back",
                              "someone to call", "have someone call")
    ):
        return "callback"
    if scope.get("public_can_request_quotes") and any(
        kw in msg for kw in ("quote", "estimate", "how much would", "price for")
    ):
        return "lead"
    return None


# ── Contact-info extractors for public chat ──────────────────────────────
# Used when the chat widget doesn't pre-collect name/phone in a form. We
# pull contact details out of whatever the visitor typed in the message
# (or recent history) so leads aren't lost when someone says "call me
# back at 555-1234, name's Bob" without filling out a form.

_PHONE_RE = _re.compile(
    r"\b(?:\+?1[-.\s]?)?\(?\d{3}\)?[-.\s]?\d{3}[-.\s]?\d{4}\b"
)
_EMAIL_RE = _re.compile(
    r"\b[A-Za-z0-9._%+\-]+@[A-Za-z0-9.\-]+\.[A-Za-z]{2,}\b"
)
_NAME_INTRO_RE = _re.compile(
    # The intro phrase is case-insensitive ("My name is" / "my name is")
    # but the captured name must START WITH AN UPPERCASE LETTER so we
    # don't slurp trailing lowercase words like "reaching" in "this is
    # John Smith reaching out".
    r"(?i:(?:my\s+name\s+is|i\s+am|i'?m|this\s+is|it'?s|it\s+is|name'?s))\s+"
    r"([A-Z][a-z]{1,20}(?:\s+[A-Z][a-z]{1,20}){0,2})\b",
)


def _conversation_text(history: list, current_msg: str) -> str:
    """Concatenate visitor-side messages (history + current) into one
    string for regex scanning. Server-side responses aren't included —
    we only mine what the visitor said."""
    parts = []
    for h in history or []:
        if (h or {}).get("role") == "user":
            parts.append(str(h.get("content") or ""))
    parts.append(current_msg or "")
    return " ".join(parts)


def _extract_captured_sales_info(history: list) -> dict:
    """Scan the conversation history for name/business/email/phone that
    the visitor has already provided. Returns a dict with whatever was
    found. Used to pin captured values into the system prompt so the LLM
    can't re-ask. NOT exhaustive — picks the most recent confident match
    for each field."""
    out: dict = {}
    # Walk USER turns from oldest to newest so the NEWEST value wins
    # (visitors sometimes correct themselves: "wait, my email is X").
    for m in (history or []):
        if (m.get("role") or "") != "user":
            continue
        content = (m.get("content") or "").strip()
        if not content:
            continue
        # Email
        try:
            e = _extract_email(content)
            if e and "@" in e:
                out["email"] = e
        except Exception:
            pass
        # Phone
        try:
            p = _extract_phone(content)
            if p and len(_re.sub(r"\D", "", p)) >= 10:
                out["phone"] = p
        except Exception:
            pass
        # Name — only when the message looks like a name reply
        # ("my name is X", "I'm X", "this is X", or just a 1-3 word
        # capitalized response to a name question). Avoid grabbing
        # random capitalized words from mid-sentence.
        low = content.lower()
        name_match = _re.match(
            r"^(?:my\s+name(?:'?s)?\s+(?:is\s+)?|i'?m\s+|this\s+is\s+|name(?:'?s)?\s+)?"
            r"([A-Z][a-zA-Z]+(?:\s+[A-Z][a-zA-Z]+)?)\s*$",
            content,
        )
        if name_match:
            cand = name_match.group(1).strip()
            # Exclude common short answers that LOOK like a name (capital
            # word) but aren't — "Personal" / "Business" / "Restaurant"
            # are answers to the triage question, not someone's name.
            _NOT_A_NAME = {
                "personal", "business", "restaurant", "yes", "no", "yeah",
                "yep", "yup", "nope", "ok", "okay", "sure", "fine",
                "good", "great", "perfect", "deli", "cafe", "pizza",
                "bar", "diner", "thanks", "thank you",
            }
            if cand.lower() not in _NOT_A_NAME and len(cand) >= 2:
                out["name"] = cand
        # Business name — "my business is X" / "I run X" / "the business is X"
        biz_match = _re.search(
            r"(?:my\s+business\s+(?:is\s+)?(?:called\s+)?|i\s+run\s+|"
            r"i\s+own\s+|the\s+business\s+(?:is\s+)?(?:called\s+)?|"
            r"business\s+name\s+(?:is\s+)?)"
            r"([A-Z][A-Za-z0-9 &'\-]{1,60})",
            content,
        )
        if biz_match:
            out["business"] = biz_match.group(1).strip().rstrip(".,;")
    return out


def _extract_phone(text: str) -> str | None:
    m = _PHONE_RE.search(text or "")
    if not m:
        return None
    # Normalize to digits-only with a leading + if E.164-like, otherwise
    # keep formatting reasonable. Strip non-digit chars except leading +.
    raw = m.group(0)
    digits = _re.sub(r"\D", "", raw)
    if len(digits) == 11 and digits.startswith("1"):
        return "+" + digits
    if len(digits) == 10:
        return "+1" + digits
    return raw  # leave as-is for weird formats


def _extract_email(text: str) -> str | None:
    m = _EMAIL_RE.search(text or "")
    return m.group(0).lower() if m else None


def _extract_name(text: str) -> str | None:
    """Find a likely visitor name from intro phrases ('my name is X',
    'I'm X', 'this is X'). Capitalized 1-3 word run after the intro."""
    m = _NAME_INTRO_RE.search(text or "")
    if not m:
        return None
    candidate = m.group(1).strip()
    # Reject pronouns / very short / numeric-looking
    if not candidate or len(candidate) < 2:
        return None
    if candidate.lower() in {"good", "fine", "ok", "okay", "calling",
                              "interested", "looking", "wondering", "trying"}:
        return None
    return candidate

