@app.route("/owner/login")
def owner_login_page():
    return send_from_directory(DASHBOARD_DIR, "login.html")

@app.route("/owner")
def owner_dashboard_page():
    if not auth.current_owner(ORBI_DIR):
        from flask import redirect
        return redirect("/owner/login")
    return send_from_directory(DASHBOARD_DIR, "dashboard.html")

@app.route("/api/owner/login", methods=["POST"])
def owner_login():
    """Login accepts either {username, password} (multi-user) or legacy
    {email, password} (single-owner installs pre-multi-user).
    On first multi-user login, bootstrap the legacy CONFIG.owner into
    users.json so subsequent logins go through the proper registry."""
    data = request.get_json(silent=True) or {}
    raw_id = (data.get("username") or data.get("email") or "").strip()
    password = data.get("password") or ""
    ip = request.headers.get("X-Forwarded-For", request.remote_addr or "")
    if not raw_id or not password:
        return jsonify({"error": "Username and password required"}), 400

    # First-time multi-user bootstrap: legacy single-owner install with
    # an entry in CONFIG.owner but no users.json yet.
    legacy_owner = CONFIG.get("owner", {})
    existing_users = users_mod.load_users(DATA_DIR)
    if not existing_users and legacy_owner.get("email"):
        legacy_email = legacy_owner["email"].lower()
        if raw_id.lower() in (legacy_email, legacy_email.split("@")[0]) \
           and auth.verify_password(password, legacy_owner.get("_password_hash", "")):
            bootstrap_username = legacy_email.split("@")[0] or "owner"
            try:
                users_mod.add_user(DATA_DIR, bootstrap_username, password,
                                   role="owner", display_name=legacy_owner.get("name", bootstrap_username))
                log.info(f"bootstrapped owner from legacy CONFIG: {bootstrap_username}")
                audit.log_event(DATA_DIR, actor=bootstrap_username,
                                action="owner.bootstrap_from_config")
            except ValueError as e:
                log.warning(f"bootstrap failed: {e}")

    # Standard multi-user verify path
    username = raw_id.split("@")[0].lower() if "@" in raw_id else raw_id.lower()
    user_rec = users_mod.verify_user(DATA_DIR, username, password)
    if not user_rec:
        audit.log_event(DATA_DIR, actor=username, action="owner.login.failed",
                        ip=ip, meta={"reason": "bad_credentials"})
        return jsonify({"error": "Invalid username or password"}), 401

    token = auth.issue_session(ORBI_DIR, username=user_rec["username"],
                               role=user_rec.get("role", "staff"))
    # A user record with no `password_changed_at` is still on the
    # installer-generated temp password. The dashboard sees this flag
    # and forces a password reset before any onboarding starts so the
    # customer leaves with a password they actually know.
    must_change_password = not user_rec.get("password_changed_at")
    resp = make_response(jsonify({
        "status": "ok",
        "username": user_rec["username"],
        "role": user_rec["role"],
        "display_name": user_rec.get("display_name"),
        "must_change_password": must_change_password,
    }))
    auth.set_session_cookie(resp, token)
    audit.log_event(DATA_DIR, actor=username, action="owner.login.success", ip=ip)
    return resp

@app.route("/owner/magic-login")
def owner_magic_login():
    """Cloud v1 magic-link login.

    Customer clicks the post-Stripe-checkout email link
    (https://orbi.twickell.com/owner/magic-login?token=...). We verify the
    token against the brain's /api/verify endpoint (one-shot, consumes it),
    save the api_key + tier + enabled_modules into config so Orbi knows who
    she's serving, bootstrap an owner user record on first click, issue a
    session cookie, and redirect into the dashboard with welcome=1 so the
    onboarding wizard kicks in.

    Failure modes redirect to /owner/login?err=... so the customer can ask
    Orbi on the chat for help instead of being stuck on a blank page.
    """
    from flask import redirect
    import urllib.request, urllib.error
    global CONFIG

    token = (request.args.get("token") or "").strip()
    # Same input-validation discipline as the brain's /api/verify endpoint:
    # length cap + alphanumeric (+ underscore) only. Defense in depth.
    if (not token or len(token) > 80
            or not token.replace("_", "").isalnum()):
        return redirect("/owner/login?err=bad_link")

    brain_verify_base = (CONFIG.get("brain", {}).get("verify_url")
                         or "https://billing.twickell.com/api/verify")
    verify_url = f"{brain_verify_base.rstrip('/')}/{token}"

    try:
        req = urllib.request.Request(
            verify_url,
            headers={"User-Agent": "Mozilla/5.0 Orbi-magic-login"},
        )
        with urllib.request.urlopen(req, timeout=10) as resp:
            data = json.loads(resp.read().decode("utf-8"))
    except urllib.error.HTTPError as e:
        log.warning(f"magic-login: token verify HTTP {e.code} for {token[:14]}...")
        return redirect("/owner/login?err=link_expired")
    except Exception as e:
        log.error(f"magic-login: brain unreachable ({e!r})")
        return redirect("/owner/login?err=brain_unreachable")

    api_key = (data.get("api_key") or "").strip()
    owner_email = (data.get("owner_email") or "").strip().lower()
    tier = (data.get("tier") or "standard").strip()
    enabled_modules = data.get("enabled_modules") or []
    if not api_key or not owner_email:
        log.warning(f"magic-login: incomplete record from brain for {token[:14]}...")
        return redirect("/owner/login?err=incomplete_record")

    # Save the tenant identity into config.json so this Orbi installation
    # knows who she's serving on subsequent requests.
    cfg = load_config()
    cfg["api_key"] = api_key
    cfg["owner_email"] = owner_email
    cfg["tier"] = tier
    if enabled_modules:
        cfg["enabled_modules"] = [str(m).strip().lower()
                                  for m in enabled_modules if m]
    save_config(cfg)
    # Re-read CONFIG global so the rest of this process sees it.
    CONFIG = load_config()

    # Bootstrap an owner user record if one doesn't exist yet. We generate
    # a one-time random password — the dashboard's must_change_password
    # gate forces the customer to set their own on first visit.
    username = (owner_email.split("@")[0] or "owner").lower()
    if not users_mod.get_user(DATA_DIR, username):
        import secrets as _secrets
        import string as _string
        temp_pw = "".join(_secrets.choice(_string.ascii_letters + _string.digits)
                          for _ in range(20))
        try:
            users_mod.add_user(
                DATA_DIR, username, temp_pw,
                role="owner",
                display_name=username,
            )
        except Exception as e:
            log.error(f"magic-login: user bootstrap failed: {e}")
            return redirect("/owner/login?err=user_bootstrap")

    # Issue session, set cookie, redirect into the onboarding wizard.
    session_token = auth.issue_session(
        ORBI_DIR, username=username, role="owner")
    resp = make_response(redirect("/owner?welcome=1"))
    auth.set_session_cookie(resp, session_token)
    audit.log_event(
        DATA_DIR, actor=username, action="owner.magic_login.success",
        meta={"api_key_prefix": api_key[:14], "tier": tier})
    return resp


@app.route("/api/owner/logout", methods=["POST"])
def owner_logout():
    owner_session = auth.current_owner(ORBI_DIR)
    if owner_session:
        audit.log_event(DATA_DIR, actor=owner_session.get("email", "?"),
                        action="owner.logout")
    resp = make_response(jsonify({"status": "ok"}))
    auth.clear_session_cookie(resp)
    return resp


@app.route("/api/owner/report_issue", methods=["POST"])
def owner_report_issue():
    """Owner-initiated bug report from the dashboard. Forwards to the
    central brain server's customer_error_report endpoint so Frank sees
    it in his admin inbox alongside auto-captured exceptions."""
    user = auth.require_user(ORBI_DIR, DATA_DIR)
    data = request.get_json(silent=True) or {}
    description = (data.get("description") or "").strip()
    if len(description) < 5:
        return jsonify({"ok": False,
                        "error": "Description too short."}), 400
    page_url = (data.get("page_url") or "")[:300]
    ua       = (data.get("user_agent") or "")[:200]
    try:
        import error_reporter
        error_reporter.report_message(
            description,
            error_class="OwnerReport",
            context={
                "owner": user.get("username", "?"),
                "page_url": page_url,
                "user_agent": ua,
                "type": "manual_owner_report",
            },
        )
    except Exception as e:
        log.warning(f"owner report_issue forward failed: {e}")
        return jsonify({"ok": False,
                        "error": "Couldn't forward — try again."}), 503
    audit.log_event(DATA_DIR, actor=user.get("username", "?"),
                    action="owner.report_issue",
                    meta={"length": len(description),
                          "page_url": page_url[:100]})
    return jsonify({"ok": True, "status": "sent"})

