    r"|what(?:'s| is)?\s+(?:our|my|the)\s+(?:total\s+)?(?:accounts\s+receivable|a[/.\s]?r)(?:\s+balance|\s+total)?"
    r"|(?:total\s+)?accounts\s+receivable(?:\s+balance|\s+total)?"
