    r"|new\s+contact\s+(?:(?:named|called)\s+|for\s+)?(?P<name2>[A-Za-z][A-Za-z'\-]+(?:\s+[A-Za-z][A-Za-z'\-]+){0,3})"
    r"|create\s+(?:a\s+)?(?:new\s+)?contact\s+(?:named\s+|called\s+|for\s+)?(?P<name3>[A-Za-z][A-Za-z'\-]+(?:\s+[A-Za-z][A-Za-z'\-]+){0,3})"
    r")"
    r"(?:\s*[,—–-]\s*(?P<rest>.+?))?"
    r"\s*[?.!]?\s*$",
