def _try_vague_followup(message: str, user_rec: dict) -> dict | None:
    """Catch 'widen search' / 'tell me more' / 'dig deeper' with no
    target. These were falling to the LLM, which hallucinated invented
    details (Bill's wiring projects, your wife's busy schedule, etc.)
    because it couldn't tell what to widen. Now we demand a target."""
    if not message:
        return None
    if not _VAGUE_MORE_RE.match(_strip_polite_prefix(message)):
        return None
    return {"reply": (
        "What should I look deeper on? I can search your files, "
        "contacts, memory, emails, and calendar — just name the topic.\n"
        "Try: \"tell me more about Bill Henry\" or "
        "\"search everything for plumbing\" or "
        "\"what do you remember about my suppliers\"."
    ), "tier": "local", "latency_ms": 0, "source": "vague_followup"}


_TELL_ME_ABOUT_RE = _re.compile(
    r"^\s*(?:"
    r"(?:tell|say|show|give)\s+me\s+"
    r"(?:everything|all|more|what\s+you\s+know|some\s+more|anything)?\s*"
    r"(?:about|on|regarding)\s+(?:my\s+)?(?P<topic1>.+?)"
    r"|what(?:'s| do you know| can you tell me)\s+(?:more\s+)?"
    r"(?:about|on)\s+(?:my\s+)?(?P<topic2>.+?)"
    r"|who\s+is\s+(?:my\s+)?(?P<topic3>.+?)"
    r"|more\s+(?:about|on)\s+(?:my\s+)?(?P<topic4>.+?)"
    r")\s*[.?!]?\s*$",
    _re.IGNORECASE,
)


def _try_tell_me_about(message: str, user_rec: dict) -> dict | None:
    """Deterministic 'tell me about X' lookup. Pulls matching items from
    memory + contacts. Returns ONLY what's stored — no LLM call, no
    fabrication. Was previously letting the LLM invent details (wife is
    "supportive of business" / "good with kids") that were never said
    by the user."""
    if not message:
        return None
    msg = _strip_polite_prefix(message)
    m = _TELL_ME_ABOUT_RE.match(msg)
    if not m:
        return None
    topic_raw = next(
        (m.group(g) for g in ("topic1", "topic2", "topic3", "topic4")
         if m.group(g)),
        "",
    ).strip().rstrip("?.!").strip()
    if not topic_raw:
        return None

    username = user_rec.get("username", "owner")
    try:
        user_dir = users_mod.get_user_dir(DATA_DIR, username)
    except Exception:
        return None

    # Token stems — singular/plural-friendly match (suppliers → supplier)
    def _stems(t: str) -> set[str]:
        t = t.lower().strip()
        out = {t}
        if t.endswith("ies") and len(t) > 4: out.add(t[:-3] + "y")
        if t.endswith("es")  and len(t) > 3: out.add(t[:-2])
        if t.endswith("s")   and len(t) > 2: out.add(t[:-1])
        if t.endswith("'s"):                  out.add(t[:-2])
        return out

    # Memory hits
    try:
        from modules import memory as mod_memory
        mem_hits: list = []
        for stem in _stems(topic_raw):
            mem_hits = mod_memory.recall(user_dir, query=stem, limit=20)
            if mem_hits:
                break
    except Exception:
        mem_hits = []

    # Contacts hits — if topic_raw is a name, surface the contact record
    contact_hits: list = []
    try:
        from modules import contacts as mod_contacts
        contact_hits = mod_contacts.search(user_dir, topic_raw) or []
    except Exception:
        pass

    if not mem_hits and not contact_hits:
        # No personal facts found. Before falling back to the canned
        # "tell me a fact" response, check whether business_info has
        # been populated (post-scrape or via owner edits) — if so,
        # let the LLM answer, since it builds its system prompt from
        # business_info and CAN answer questions about the business,
        # the owner, or Orbi herself without hallucinating.
        # If business_info is still empty (fresh install, scrape hasn't
        # finished, no owner edits), keep the canned response so we
        # don't invite the old hallucination problem with personal
        # facts ("wife is supportive", "kids are good with people")
        # that have no source.
        try:
            biz = mod_business.load(DATA_DIR) or {}
            biz_has_data = bool(
                (biz.get("name") or "").strip()
                or (biz.get("description") or "").strip()
                or (biz.get("services") or [])
                or (biz.get("menu_items") or [])
                or (biz.get("menu") or [])
            )
        except Exception:
            biz_has_data = False
        if biz_has_data:
            # Fall through to the LLM — it has business_info in the
            # system prompt and can answer "tell me about my business",
            # "what do you know about PurBlum", "what do you know about
            # me", etc. reliably.
            return None
        return {"reply": (
            f"I don't have anything saved about \"{topic_raw}\" yet. "
            f"Tell me a fact and I'll remember next time. "
            f"For example: \"remember that {topic_raw} is …\"."
        ), "tier": "local", "latency_ms": 0,
           "source": "tell_about_empty"}

    out = [f"Here's what I have on {topic_raw}:"]
    if mem_hits:
        out.append("\nFrom your saved memory:")
        seen_low: set = set()
        kept: list = []
        for h in mem_hits:
            c = (h.get("content") or "").strip()
            key = " ".join(c.lower().split())
            if not c or key in seen_low:
                continue
            seen_low.add(key)
            kept.append(h)
        for h in kept[:12]:
            line = f"  · {h.get('content', '').strip()}"
            # Append a date if we know when this was saved — proves
            # provenance (matches the "no fabrication" theme).
            when = _format_fact_date(h.get("ts"))
            if when:
                line += f"  _(saved {when})_"
            out.append(line)
    if contact_hits:
        out.append("\nFrom your contacts:")
        for c in contact_hits[:5]:
            bits = [c.get("name", "?")]
            if c.get("phone"): bits.append(c["phone"])
            if c.get("email"): bits.append(c["email"])
            if c.get("tags"):  bits.append(", ".join(c["tags"]))
            out.append(f"  · {' — '.join(bits)}")
    out.append("\n(That's everything I have stored. Nothing else, no "
               "guesses. Tell me more if you want me to remember it.)")
    return {"reply": "\n".join(out), "tier": "local",
            "latency_ms": 0, "source": "tell_about"}


def _format_fact_date(ts) -> str:
    """Format a stored timestamp as 'Jun 4' / 'May 27' for citation lines."""
    if not ts:
        return ""
    try:
        from datetime import datetime, timezone
        dt = datetime.fromtimestamp(float(ts), tz=timezone.utc).astimezone()
        return dt.strftime("%b %-d")
    except (ValueError, TypeError):
        return ""


_CONCERN_CAPTURE_RE = _re.compile(
    r"^\s*(?:"
    r"(?:i'?m|i am)\s+(?:really\s+|super\s+|kinda\s+|kind\s+of\s+)?"
    r"(?:worried|stressed|anxious|concerned|nervous|freaking\s+out)\s+"
    r"(?:about|over|because\s+of)\s+(?P<topic1>.+?)"
    r"|(?:remember\s+(?:that\s+)?)?"
    r"i'?m\s+(?:really\s+)?worried\s+about\s+(?P<topic2>.+?)"
    r"|(?:something|the\s+thing)\s+(?:that'?s\s+)?"
    r"(?:bothering|worrying|stressing)\s+me\s+is\s+(?P<topic3>.+?)"
    r"|(?:keep|can'?t\s+stop)\s+(?:worrying|thinking)\s+about\s+"
    r"(?P<topic4>.+?)"
    r")\s*[.?!]?\s*$",
    _re.IGNORECASE,
)
_CONCERN_RESOLVE_RE = _re.compile(
    r"^\s*(?:"
    r"(?:the\s+)?(?P<topic1>.+?)\s+(?:thing\s+)?(?:is\s+)?"
    r"(?:sorted|resolved|fixed|done|over|behind\s+me|handled)"
    r"|stop\s+worrying\s+about\s+(?P<topic2>.+?)"
    r"|(?:i'?m\s+)?(?:no\s+longer|not)\s+worried\s+about\s+(?P<topic3>.+?)"
    r")\s*[.?!]?\s*$",
    _re.IGNORECASE,
)


def _try_concern_capture(message: str, user_rec: dict) -> dict | None:
    """Detect 'I'm worried about X' and save to the concerns memory
    tier — companion_mode-gated. Also detects 'X is sorted' and resolves
    the matching concern. No LLM call. Skipped silently if companion_mode
    is 'business' so it doesn't surprise transactional-only owners."""
    if not message:
        return None
    msg = _strip_polite_prefix(message)
    # Gate: only fire when this owner has personal mode enabled.
    try:
        business = mod_business.load(DATA_DIR)
        mode = ((business.get("personality") or {}).get("companion_mode")
                or ("personal" if (business.get("personality") or {})
                    .get("tone", "friend") == "friend" else "business")).lower()
    except Exception:
        mode = "personal"
    if mode != "personal":
        return None
    username = user_rec.get("username", "owner")
    try:
        user_dir = users_mod.get_user_dir(DATA_DIR, username)
    except Exception:
        return None

    # Try resolve first ("the ChemPro thing is sorted") so "X is sorted"
    # doesn't accidentally trigger capture as a new concern.
    rm = _CONCERN_RESOLVE_RE.match(msg)
    if rm:
        topic = next((rm.group(g) for g in ("topic1", "topic2", "topic3")
                      if rm.group(g)), "").strip().rstrip(".?!")
        if topic and len(topic) > 2:
            try:
                n = mod_memory.resolve_concern(user_dir, topic)
            except Exception:
                n = 0
            if n > 0:
                return {"reply": (
                    f"Glad to hear that. I'll stop bringing up "
                    f"\"{topic}\" — let me know if it comes back."
                ), "tier": "local", "latency_ms": 0,
                   "source": "concern_resolved"}
            # No matching concern found — fall through to LLM

    m = _CONCERN_CAPTURE_RE.match(msg)
    if not m:
        return None
    topic = next((m.group(g) for g in ("topic1", "topic2", "topic3", "topic4")
                  if m.group(g)), "").strip().rstrip(".?!")
    if not topic or len(topic) < 3:
        return None
    # Frame the saved concern in third person to match the rest of memory
    # ("User is worried about ChemPro's delivery delays").
    saved_text = f"User is worried about {topic}"
    try:
        mod_memory.add_concern(user_dir, saved_text, weight=0.7,
                                meta={"source": "explicit_capture",
                                      "from_msg": (msg or "")[:200]})
    except Exception as e:
        log.warning(f"add_concern failed: {e}")
        return None
    # Also log a mood signal so the EI layer surfaces it next turn
    try:
        from modules import mood as mod_mood
        mod_mood.log(user_dir, {
            "kind": "worried", "intensity": 0.65,
            "valence": "neg", "snippet": f"worried about {topic}",
        }, source_msg=msg)
    except Exception:
        pass
    return {"reply": (
        f"Got it — I'll hold onto that. \"{topic}\" is on my mind too "
        f"now. I'll bring it up gently when it seems relevant, and "
        f"check in if it's been a few days. When it's sorted, just "
        f"say so and I'll let it go."
    ), "tier": "local", "latency_ms": 0, "source": "concern_captured"}


_MEMORY_RECALL_RE = _re.compile(
    r"^\s*(?:"
    r"what\s+do\s+you\s+(?:remember|know)\s+about\s+(?:my\s+)?(?P<topic>.+?)"
    r"|do\s+you\s+remember\s+(?P<topic2>.+?)"
    r"|what\s+have\s+I\s+told\s+you\s+about\s+(?P<topic3>.+?)"
    r"|recall\s+(?:everything\s+about\s+)?(?P<topic4>.+?)"
    r"|show\s+(?:me\s+)?(?:my\s+)?memory"
    r"|what\s+(?:do\s+you|do\s+I)\s+remember"
    r")\s*[.?!]?\s*$",
    _re.IGNORECASE,
)


def _try_memory_recall(message: str, user_rec: dict) -> dict | None:
    """Deterministic memory recall — when the owner asks "what do you
    remember about X", hit `mod_memory.recall()` and list the saved
    facts. Bypasses the LLM so it can't hallucinate Acme-Plumbing-style
    inventions. Returns None to fall through."""
    if not message:
        return None
    msg = _strip_polite_prefix(message)
    m = _MEMORY_RECALL_RE.match(msg)
    if not m:
        return None
    topic = ""
    for key in ("topic", "topic2", "topic3", "topic4"):
        try:
            v = m.group(key)
            if v:
                topic = v.strip().rstrip("?.!")
                break
        except IndexError:
            continue
    try:
        from modules import memory as mod_memory
    except Exception:
        return None
    username = user_rec.get("username", "owner")
    try:
        user_dir = users_mod.get_user_dir(DATA_DIR, username)
    except Exception:
        return None

    # Pull from all tiers; filter by topic if given. Tolerate
    # singular/plural mismatch ("suppliers" → "supplier", "kids" →
    # "kid", etc.) by trying multiple stems.
    def _stems(t):
        t = (t or "").strip().lower()
        out = {t}
        if t.endswith("ies") and len(t) > 4:
            out.add(t[:-3] + "y")
        if t.endswith("es") and len(t) > 3:
            out.add(t[:-2])
        if t.endswith("s") and len(t) > 2:
            out.add(t[:-1])
        if t.endswith("'s"):
            out.add(t[:-2])
        return out

    facts: list = []
    if topic:
        for stem in _stems(topic):
            hits = mod_memory.recall(user_dir, query=stem, limit=30)
            if hits:
                # Dedup by content while preserving order
                seen = set()
                for h in hits:
                    c = h.get("content", "")
                    if c not in seen:
                        seen.add(c)
                        facts.append(h)
                break  # first matching stem wins
    else:
        facts = mod_memory.recall(user_dir, query=None, limit=30)
    if not facts:
        # Same fall-through as _try_tell_me_about: if business_info has
        # been populated (post-scrape or owner edits), let the LLM
        # answer using its system prompt. This is the handler that
        # PurBlum questions actually hit — _try_tell_me_about's fix
        # alone wasn't enough because "What do you know about X?"
        # matches _MEMORY_RECALL_RE first.
        try:
            biz = mod_business.load(DATA_DIR) or {}
            biz_has_data = bool(
                (biz.get("name") or "").strip()
                or (biz.get("description") or "").strip()
                or (biz.get("services") or [])
                or (biz.get("menu_items") or [])
                or (biz.get("menu") or [])
            )
        except Exception:
            biz_has_data = False
        if biz_has_data:
            return None
        if topic:
            return {"reply": (
                f"I don't have anything saved about \"{topic}\" yet. "
                f"Tell me a fact about it and I'll remember next time."
            ), "tier": "local", "latency_ms": 0,
               "source": "memory_recall_empty"}
        return {"reply": (
            "Your long-term memory is empty so far. As we chat, I'll "
            "automatically save durable facts about you, your business, "
            "your people, and your preferences."
        ), "tier": "local", "latency_ms": 0,
           "source": "memory_recall_empty"}
    header = (f"From your saved memory"
              f"{' about ' + topic if topic else ''} "
              f"({len(facts)} fact{'s' if len(facts) != 1 else ''}):")
    lines = [header]
    for f in facts[:15]:
        line = f"  · {(f.get('content') or '').strip()[:200]}"
        when = _format_fact_date(f.get("ts"))
        if when:
            line += f"  _(saved {when})_"
        lines.append(line)
    if len(facts) > 15:
        lines.append(f"  …and {len(facts) - 15} more older fact(s).")
    lines.append("\n(These are the only facts I have. If something's "
                  "missing, tell me and I'll remember.)")
    return {"reply": "\n".join(lines), "tier": "local",
            "latency_ms": 0, "source": "memory_recall"}


_CONTACT_ADD_RE = _re.compile(
    # "add Bill Henry, billh@example.com, 555-0142, electrician"
    # "save contact Sarah Jones 775-555-1234 sarah@gmail.com supplier"
    # "new contact: name=X email=Y phone=Z"
    r"^\s*(?:add|save|new|create|store)\s+"
    r"(?:a\s+new\s+|new\s+|the\s+)?contact[\s:]+|"
    r"^\s*(?:add|save|store)\s+(?P<rest>[A-Z][a-zA-Z'\-]+(?:\s+[A-Z][a-zA-Z'\-]+)?[\s,]+.+)$",
    _re.IGNORECASE,
)


def _try_contact_add(message: str, user_rec: dict) -> dict | None:
    """Parse "add Bill Henry, billh@example.com, 555-0142, electrician"
    and actually call `mod_contacts.add()`. Was previously falling to the
    LLM which would fake the confirmation without persisting anything."""
    if not message:
        return None
    msg = _strip_polite_prefix(message)
    # First-pass: must start with one of the add verbs AND contain a
    # capitalized name (so "add the bills to my calendar" doesn't match).
    m = _re.match(
        r"^\s*(?:add|save|store|new|create)\s+(?:a\s+new\s+|a\s+|new\s+|the\s+)?"
        r"(?:contact\s*[:\s]+(?:named\s+|called\s+|for\s+)?)?"
        r"(?P<rest>.+)$",
        msg, _re.IGNORECASE,
    )
    if not m:
        return None
    rest = m.group("rest").strip()
    # Strip honorific prefix ("Dr.", "Mr.", "Mrs.", "Ms.", "Prof.", "Rev.")
    # so "Dr. Sandra Kim" → rest starts at "Sandra Kim".
    honorific_m = _re.match(
        r"^(?:Dr|Mr|Mrs|Ms|Miss|Prof|Rev|Capt|Lt|Sgt|Cpl)\.\s+", rest,
    )
    if honorific_m:
        honorific_prefix = honorific_m.group(0).rstrip()
        rest = rest[honorific_m.end():]
    else:
        honorific_prefix = ""
    # The first thing in `rest` must look like a proper name (2 capitalized
    # words OR 1 capitalized word with at least 3 chars). Otherwise this
    # is probably "add a task" / "add a meeting" / etc.
    name_m = _re.match(
        r"^(?P<name>[A-Z][a-zA-Z'\-]{1,30}"
        r"(?:\s+[A-Z][a-zA-Z'\-]{1,30}){0,2})"
        r"[,\s]",
        rest,
    )
    if not name_m:
        return None
    name = name_m.group("name").strip()
    # Restore honorific prefix if present ("Dr. Sandra Kim")
    if honorific_prefix:
        name = honorific_prefix + " " + name
    # Reject obvious false positives — words that LOOK capitalized but
    # are actually verbs/nouns at the start of a sentence (e.g., "Add"
    # following a polite prefix won't trip this because we already
    # consumed the verb).
    if name.lower() in {"a", "the", "my", "his", "her", "their", "your"}:
        return None
    # Parse the rest of the line for email / phone / role
    tail = rest[name_m.end():].strip(" ,;")
    email_m = _re.search(
        r"[A-Za-z0-9._%+\-]+@[A-Za-z0-9.\-]+\.[A-Za-z]{2,}", tail,
    )
    # Two phone formats: 10-digit (555-555-1234, +1 555 555 1234, (555)
    # 555-1234) and 7-digit local (555-1234). 7-digit is common in
    # one-area-code small towns and when a user types fast.
    phone_m = _re.search(
        r"\b(?:\+?1[-.\s]?)?\(?\d{3}\)?[-.\s]?\d{3}[-.\s]?\d{4}\b"
        r"|\b\d{3}[-.\s]\d{4}\b",
        tail,
    )
    email = email_m.group(0).lower() if email_m else ""
    phone = phone_m.group(0).strip() if phone_m else ""
    # Remaining tokens (after stripping email/phone) become the role/notes
    role_tail = tail
    if email:
        role_tail = role_tail.replace(email_m.group(0), " ", 1)
    if phone:
        role_tail = role_tail.replace(phone_m.group(0), " ", 1)
    role_tail = _re.sub(r"[,;]+", " ", role_tail).strip()
    # Pull a single "tag" word from the remainder (electrician, plumber,
    # supplier, lawyer, etc.) — first non-empty token.
    tag_tokens = [t for t in role_tail.split() if len(t) > 2]
    tags = [tag_tokens[0].lower()] if tag_tokens else []
    notes = " ".join(tag_tokens[1:]).strip() if len(tag_tokens) > 1 else ""

    try:
        from modules import contacts as mod_contacts
    except Exception:
        return None
    username = user_rec.get("username", "owner")
    try:
        user_dir = users_mod.get_user_dir(DATA_DIR, username)
    except Exception:
        return None
    # Skip if contact already exists by name
    existing = mod_contacts.find_by_name(user_dir, name)
    if existing:
        return {"reply": (
            f"You already have a contact named {existing.get('name', name)}. "
            f"Want me to update their info instead? Try "
            f"\"change {name.split()[0]}'s phone to 555-1234\"."
        ), "tier": "local", "latency_ms": 0,
           "source": "contact_add_duplicate"}
    saved = mod_contacts.add(
        user_dir, name=name, email=email, phone=phone,
        tags=tags, notes=notes,
    )
    lines = [f"📇 Added {saved.get('name', name)} to your contacts:"]
    if email: lines.append(f"  Email: {email}")
    if phone: lines.append(f"  Phone: {phone}")
    if tags:  lines.append(f"  Tags:  {', '.join(tags)}")
    if notes: lines.append(f"  Notes: {notes}")
    return {"reply": "\n".join(lines), "tier": "local",
            "latency_ms": 0, "source": "contact_add"}


# Field alternatives — longest first so the regex captures "phone number"
# not just "phone".
_PROFILE_FIELD_RE = (
    r"(?:phone\s+number|email\s+address|email|phone|"
    r"address|number)"
)
_PROFILE_INFO_RE = _re.compile(
    r"^\s*(?:"
    # "what {field} (of mine | for me | on file ...) do you have ..."
    r"(?:what|which)(?:'s| is)?\s+(?P<field1>" + _PROFILE_FIELD_RE + r")"
    r"(?:\s+(?:of\s+mine|for\s+me|on\s+file|saved|stored))?"
    r"\s+(?:do\s+you\s+(?:have|got|know)|is\s+(?:saved|on\s+file|stored))"
    r"(?:\s+(?:of\s+mine|for\s+me|on\s+file|saved|stored))*"
    # OR "do you have my email"
    r"|do\s+you\s+have\s+(?:(?:my|an?|the)\s+)?(?P<field2>" + _PROFILE_FIELD_RE + r")"
    r"(?:\s+(?:of\s+mine|for\s+me|on\s+file|saved|stored))*"
    # OR "any email saved for me"
    r"|any\s+(?P<field3>" + _PROFILE_FIELD_RE + r")\s+"
    r"(?:saved|stored|on\s+file)\s+(?:for\s+me|of\s+mine)"
    r")\s*[.?!]?\s*$",
    _re.IGNORECASE,
)


def _try_profile_info(message: str, user_rec: dict) -> dict | None:
    """Answer "what email/phone/address do you have for me" deterministically
    from the user record + IMAP accounts. Distinguishes the OWNER's
    personal contact info from the BUSINESS profile (Orby was returning
    orbiaisolutions@gmail.com — the business email — when Frank asked
    for his own)."""
    if not message:
        return None
    m = _PROFILE_INFO_RE.match(_strip_polite_prefix(message))
    if not m:
        return None
    field = next((m.group(g) for g in ("field1", "field2", "field3")
                  if m.group(g)), "").lower()
    if not field:
        return None
    field_norm = "email" if "email" in field else \
                 "phone" if ("phone" in field or "number" in field) else \
                 "address" if "address" in field else field

    username = user_rec.get("username", "owner")
    try:
        user_dir = users_mod.get_user_dir(DATA_DIR, username)
    except Exception:
        return None

    # Per-user owner profile (the user record itself)
    profile_val = (user_rec.get(field_norm) or "").strip()

    # Business profile — for owners, this counts too. Frank uses
    # orbiaisolutions@gmail.com (his business email) as a real working
    # mailbox, so listing it here gives the full picture rather than
    # only the IMAP-connected one.
    business_val = ""
    try:
        business = mod_business.load(DATA_DIR)
        contact = business.get("contact") or {}
        business_val = (contact.get(field_norm) or "").strip()
    except Exception:
        pass

    # For email: also list IMAP-connected mailboxes
    connected_mailboxes: list = []
    if field_norm == "email":
        try:
            import imap_smtp
            accts = imap_smtp.list_accounts(user_dir)
            connected_mailboxes = [a.get("email") for a in accts if a.get("email")]
        except Exception:
            pass

    parts = []
    label = {"email": "Email", "phone": "Phone",
             "address": "Address"}.get(field_norm, field_norm.title())
    if profile_val:
        parts.append(f"{label} on your owner profile: {profile_val}")
    if business_val:
        parts.append(f"Business {field_norm}: {business_val}")
    if connected_mailboxes:
        # Avoid printing the same address twice if it matches business/profile
        already = {profile_val.lower(), business_val.lower()}
        extras = [a for a in connected_mailboxes if a.lower() not in already]
        if extras:
            parts.append("Connected mailbox" + ("es" if len(extras) > 1 else "") +
                         ": " + ", ".join(extras))
    if not parts:
        parts.append(f"I don't have a {field_norm} stored for you yet. "
                     f"Add it in Settings → Profile.")
    return {"reply": "\n".join(parts), "tier": "local", "latency_ms": 0,
            "source": "profile_info"}


_ADD_STAFF_RE = _re.compile(
    # "add a new staff user named Lisa Smith"
    # "add Lisa Smith as staff"
    # "hire Lisa Smith"
    # "create a staff account for Lisa Smith"
    r"^\s*(?:"
    r"add\s+(?:a\s+)?(?:new\s+)?staff\s+(?:user|member|account)\s+"
    r"(?:named\s+|called\s+|for\s+)?(?P<n1>[A-Z][a-zA-Z'\-]+(?:\s+[A-Z][a-zA-Z'\-]+){0,2})"
    r"|hire\s+(?P<n2>[A-Z][a-zA-Z'\-]+(?:\s+[A-Z][a-zA-Z'\-]+){0,2})"
    r"|add\s+(?P<n3>[A-Z][a-zA-Z'\-]+(?:\s+[A-Z][a-zA-Z'\-]+){0,2})\s+(?:as|to)\s+(?:my\s+)?staff"
    r"|create\s+(?:a\s+)?staff\s+(?:account|user)\s+for\s+(?P<n4>[A-Z][a-zA-Z'\-]+(?:\s+[A-Z][a-zA-Z'\-]+){0,2})"
    r")\s*[.?!]?\s*$",
    _re.IGNORECASE,
)


def _try_add_staff_user(message: str, user_rec: dict) -> dict | None:
    """Real staff-user add — was being faked by the LLM, which would
    cheerfully say "I've added Lisa Smith" without calling
    users_mod.add_user(), and then the fact extractor would save the
    LLM's lie to memory as a "fact". Now actually creates the account."""
    if not message:
        return None
    # Only owners can add users
    if user_rec.get("role") != "owner":
        return None
    msg = _strip_polite_prefix(message)
    m = _ADD_STAFF_RE.match(msg)
    if not m:
        return None
    name = next((m.group(g) for g in ("n1", "n2", "n3", "n4")
                 if m.group(g)), "").strip()
    if not name:
        return None
    # Generate the username from the first name (lowercased). If taken,
    # append a counter.
    base = _re.sub(r"[^a-z]", "", name.split()[0].lower()) or "staff"
    username = base
    existing = users_mod.load_users(DATA_DIR)
    counter = 2
    while username in existing:
        username = f"{base}{counter}"
        counter += 1
    # Temp password — owner reads it once, employee changes it on first login
    import secrets, string
    alphabet = string.ascii_letters + string.digits
    temp_pw = "".join(secrets.choice(alphabet) for _ in range(10))
    try:
        rec = users_mod.add_user(
            DATA_DIR, username=username, password=temp_pw,
            display_name=name, role="staff",
        )
    except Exception as e:
        log.warning(f"add_staff_user failed: {e}")
        return {"reply": f"Couldn't add {name}: {e}",
                "tier": "local", "latency_ms": 0,
                "source": "add_staff_failed"}
    return {"reply": (
        f"✓ Added staff user {name} (username: `{username}`).\n"
        f"Temporary password: `{temp_pw}`\n"
        f"Share this with them — they should change it on first login at "
        f"`/owner/login`."
    ), "tier": "local", "latency_ms": 0,
       "source": "add_staff_user"}


_CONTACT_UPDATE_RE = _re.compile(
    # "change Bill's phone to 555-1234"
    # "update Bill Henry's email to bill@new.com"
    # "set Cathleen's phone number to (775) 555-9876"
    # "change Bill's address to 123 Main St"
    r"^\s*(?:change|update|set|edit|modify)\s+"
    r"(?P<name>[A-Z][A-Za-z'\-]+(?:\s+[A-Z][A-Za-z'\-]+){0,2}?)'s\s+"
    r"(?P<field>phone(?:\s+number)?|email(?:\s+address)?|address|notes?|"
    r"name|tags?)"
    r"\s+(?:to|=|:)\s+"
    r"(?P<value>.+?)\s*[.?!]?\s*$",
    _re.IGNORECASE,
)


def _try_contact_update(message: str, user_rec: dict) -> dict | None:
    """Parse "change Bill's phone to 555-1234" and actually call
    `mod_contacts.update()`. Was being eaten by the reschedule-appointment
    regex which also starts with "change ... to ...".

    Note: 'change Bill's phone to ...' could ALSO be a calendar
    reschedule of an event named "Bill's phone" — but that's an
    extremely unlikely event title, so we route to contacts."""
    if not message:
        return None
    msg = _strip_polite_prefix(message)
    m = _CONTACT_UPDATE_RE.match(msg)
    if not m:
        return None
    name  = m.group("name").strip()
    field = m.group("field").lower()
    value = m.group("value").strip().strip("\"'").rstrip(".")

    # Map the spoken field name to the contacts JSON key.
    field_key = {
        "phone": "phone", "phone number": "phone",
        "email": "email", "email address": "email",
        "address": "address",
        "note": "notes", "notes": "notes",
        "name": "name",
        "tag": "tags", "tags": "tags",
    }.get(field)
    if not field_key:
        return None

    try:
        from modules import contacts as mod_contacts
    except Exception:
        return None
    username = user_rec.get("username", "owner")
    try:
        user_dir = users_mod.get_user_dir(DATA_DIR, username)
    except Exception:
        return None

    # Find by name OR first name only (so "change Bill's phone" works
    # even when stored as "Bill Henry").
    target = mod_contacts.find_by_name(user_dir, name)
    if not target:
        all_c = mod_contacts.list_all(user_dir)
        first = name.split()[0].lower()
        matches = [c for c in all_c
                   if c.get("name", "").lower().split()[:1] == [first]]
        if len(matches) == 1:
            target = matches[0]
        elif len(matches) > 1:
            names = ", ".join(c.get("name", "?") for c in matches[:5])
            return {"reply": (
                f"I have multiple contacts named {name.split()[0]}: "
                f"{names}. Which one? Try the full name."
            ), "tier": "local", "latency_ms": 0,
               "source": "contact_update_ambiguous"}
    if not target:
        return {"reply": (
            f"I don't have a contact named {name}. Want me to add them? "
            f"Try \"add {name}, [email], [phone], [role]\"."
        ), "tier": "local", "latency_ms": 0,
           "source": "contact_update_not_found"}

    # tags field expects a list
    if field_key == "tags":
        value = [t.strip().lower() for t in _re.split(r"[,;]", value) if t.strip()]
    updated = mod_contacts.update(user_dir, target["id"], **{field_key: value})
    if not updated:
        return {"reply": f"Couldn't update {target.get('name', name)} — "
                         f"maybe an internal error. Try again.",
                "tier": "local", "latency_ms": 0,
                "source": "contact_update_failed"}
    return {"reply": (
        f"✓ Updated {updated.get('name', name)}'s {field_key} to "
        f"{updated.get(field_key, value)!s}."
    ), "tier": "local", "latency_ms": 0, "source": "contact_update"}


_SEARCH_EVERYTHING_RE = _re.compile(
    r"^\s*(?:"
    r"search\s+(?:everything|all|across\s+everything)\s+(?:for\s+)?"
    r"|find\s+(?:anything|everything)\s+(?:I\s+have\s+)?(?:about|on|for|matching|with)\s+"
    r"|find\s+(?:anything|everything)\s+(?:I\s+know\s+)?(?:about|on)\s+"
    r"|look\s+(?:everywhere|across\s+everything)\s+for\s+"
    r"|pull\s+(?:up\s+)?(?:everything|all)\s+(?:I\s+have\s+)?(?:on|about|for)\s+"
    r")(?P<q>.+?)\s*[.?!]?\s*$",
    _re.IGNORECASE,
)


def _try_search_everything(message: str, user_rec: dict) -> dict | None:
    """Union search: workspace files + contacts + emails + memory. The
    user said "find anything about plumbing" — should hit ALL stores,
    not get eaten by contacts.search alone."""
    if not message:
        return None
    msg = _strip_polite_prefix(message)
    m = _SEARCH_EVERYTHING_RE.match(msg)
    if not m:
        return None
    query = m.group("q").strip().strip("\"'")
    if not query:
        return None

    username = user_rec.get("username", "owner")
    try:
        user_dir = users_mod.get_user_dir(DATA_DIR, username)
    except Exception:
        return None

    sections: list[str] = []
    total = 0

    # Workspace files
    try:
        from modules import workspace as mod_workspace
        files = mod_workspace.search(user_dir, query, limit=5) or []
        if files:
            total += len(files)
            sections.append(f"📁 Files ({len(files)}):")
            for f in files[:5]:
                sections.append(f"  · {f.get('name', '')}")
    except Exception as e:
        log.debug(f"search_everything workspace: {e}")

    # Contacts
    try:
        from modules import contacts as mod_contacts
        hits = mod_contacts.search(user_dir, query) or []
        if hits:
            total += len(hits)
            sections.append(f"📇 Contacts ({len(hits)}):")
            for c in hits[:5]:
                bits = [c.get("name", "?")]
                if c.get("phone"): bits.append(c["phone"])
                if c.get("email"): bits.append(c["email"])
                sections.append(f"  · {' — '.join(bits)}")
    except Exception as e:
        log.debug(f"search_everything contacts: {e}")

    # Emails
    try:
        from modules import email as mod_email
        emails = mod_email.search(user_dir, query, limit=5) or []
        if emails:
            total += len(emails)
            sections.append(f"📧 Emails ({len(emails)}):")
            for e in emails[:5]:
                subj = (e.get("subject") or "")[:60]
                frm  = (e.get("from") or e.get("sender") or "")[:40]
                sections.append(f"  · {frm} — {subj}")
    except Exception as e:
        log.debug(f"search_everything emails: {e}")

    # Owner notes
    try:
        nhits = mod_notes.search(DATA_DIR, query) or []
        if nhits:
            total += len(nhits)
            sections.append(f"📝 Notes ({len(nhits)}):")
            for n in nhits[:5]:
                sections.append(f"  · {(n.get('content') or '')[:140]}")
    except Exception as e:
        log.debug(f"search_everything notes: {e}")

    # Memory
    try:
        from modules import memory as mod_memory
        mhits = mod_memory.recall(user_dir, query=query, limit=5) or []
        if mhits:
            total += len(mhits)
            sections.append(f"🧠 Memory ({len(mhits)}):")
            for h in mhits[:5]:
                sections.append(f"  · {(h.get('content') or '')[:140]}")
    except Exception as e:
        log.debug(f"search_everything memory: {e}")

    if total == 0:
        return {"reply": (
            f"Nothing in your files, contacts, emails, notes, or memory matched "
            f"\"{query}\"."
        ), "tier": "local", "latency_ms": 0,
           "source": "search_everything_empty"}

    header = f"Found {total} result(s) across everything for \"{query}\":"
    return {"reply": header + "\n" + "\n".join(sections),
            "tier": "local", "latency_ms": 0,
            "source": "search_everything"}


def _try_contacts_chat(message: str, user_rec: dict) -> dict | None:
    """Per-user contacts CRUD via chat. Returns None to fall through."""
    if not message:
        return None
    msg = _strip_polite_prefix(message)
    username = user_rec.get("username", "owner")
    try:
        user_dir = users_mod.get_user_dir(DATA_DIR, username)
    except Exception:
        return None

    # CONTACTS FOR <company> — "show contacts for Johnson Construction"
    m = _CONTACTS_LIST_FOR_RE.match(msg)
    if m:
        who = (m.group("who") or "").strip().rstrip("?.!")
        if who:
            q = who.lower()
            hits = [c for c in mod_contacts.list_all(user_dir)
                    if q in (c.get("company") or "").lower()
                    or q in (c.get("name") or "").lower()
                    or q in (c.get("notes") or "").lower()
                    or any(q in t.lower() for t in c.get("tags") or [])]
            if not hits:
                return {"reply": (
                    f"No contacts for \"{who}\" yet. Add one with: "
                    f"\"add a new contact named John Smith\" — I'll save them "
                    f"to your contact book."
                ), "tier": "local", "latency_ms": 0,
                   "source": "contacts_list_for_empty"}
            lines = [f"Contacts for {who} ({len(hits)}):"]
            for c in hits[:20]:
                bits = [c.get("name", "?")]
                if c.get("phone"): bits.append(c["phone"])
                if c.get("email"): bits.append(c["email"])
                if c.get("company") and q not in c["company"].lower():
                    bits.append(f"({c['company']})")
                lines.append("  · " + " — ".join(bits))
            return {"reply": "\n".join(lines), "tier": "local",
                    "latency_ms": 0, "source": "contacts_list_for"}

    # FIND <name> — "find Sarah Jones" / "What's Jennifer Walsh's phone number?"
    m = _CONTACTS_FIND_RE.match(msg)
    if m:
        name = (m.group("name") or m.group("name2")
                or m.group("name4") or m.group("name5") or "").strip()
        if name:
            c = mod_contacts.find_by_name(user_dir, name)
            if c:
                bits = [f"📇 {c.get('name','?')}"]
                if c.get("company"): bits.append(f"  Company: {c['company']}")
                if c.get("phone"):   bits.append(f"  Phone:   {c['phone']}")
                if c.get("email"):   bits.append(f"  Email:   {c['email']}")
                if c.get("notes"):   bits.append(f"  Notes:   {c['notes'][:200]}")
                if c.get("tags"):    bits.append(f"  Tags:    {', '.join(c['tags'])}")
                if c.get("last_contact"):
                    bits.append(f"  Last:    {c['last_contact'][:10]}")
                return {"reply": "\n".join(bits), "tier": "local",
                        "latency_ms": 0, "source": "contacts_found"}
            # Try fuzzy search
            results = mod_contacts.search(user_dir, name)
            if results:
                lines = [f"No exact match for \"{name}\". Possible matches:"]
                for r in results[:5]:
                    lines.append(f"  · {r.get('name','?')} ({r.get('company','')})")
                return {"reply": "\n".join(lines), "tier": "local",
                        "latency_ms": 0, "source": "contacts_found_fuzzy"}
            return {"reply": f"No contact matching \"{name}\".",
                    "tier": "local", "latency_ms": 0,
                    "source": "contacts_not_found"}

    # ADD CONTACT — "add a new contact named Sarah Jones"
    m = _CONTACTS_ADD_RE.match(msg)
    if m:
        name = (m.group("name") or m.group("name2") or m.group("name3") or "").strip()
        rest = (m.group("rest") or "").strip()
        if name:
            # Parse phone + email out of the rest
            phone = ""
            email = ""
            phone_m = _re.search(r"(\+?\d[\d\-\(\)\s]{8,})", rest or "")
            if phone_m: phone = phone_m.group(1).strip()
            email_m = _re.search(r"[\w\.-]+@[\w\.-]+\.\w+", rest or "")
            if email_m: email = email_m.group(0).strip()
            company = ""
            comp_m = _re.search(r"\b(?:at|from|with)\s+([A-Z][\w\s&'\-]{2,40})", rest or "")
            if comp_m: company = comp_m.group(1).strip()
            try:
                c = mod_contacts.add(user_dir, name=name, phone=phone,
                                     email=email, company=company,
                                     source="chat")
            except Exception as e:
                log.warning(f"contacts.add failed: {e}")
                return {"reply": f"Couldn't add contact: {e}",
                        "tier": "local", "latency_ms": 0,
                        "source": "contacts_add_error"}
            extras = []
            if phone:   extras.append(f"phone {phone}")
            if email:   extras.append(f"email {email}")
            if company: extras.append(f"at {company}")
            extra_bit = " (" + ", ".join(extras) + ")" if extras else ""
            return {"reply": f"Added {c['name']} to your contacts{extra_bit}.",
                    "tier": "local", "latency_ms": 0,
                    "source": "contacts_added"}

    # CONVERSATION HISTORY — honest answer: per-contact threading isn't built
    m = _CONTACTS_CONVO_RE.match(msg)
    if m:
        name = (m.group("name") or "").strip().rstrip("?.!")
        c = mod_contacts.find_by_name(user_dir, name) if name else None
        if c:
            notes = c.get("personal_notes") or []
            lines = [f"What I know about {c.get('name','?')}:"]
            if c.get("last_contact"):
                lines.append(f"  Last contact: {c['last_contact'][:10]}")
            if c.get("notes"):
                lines.append(f"  General notes: {c['notes'][:200]}")
            if notes:
                lines.append(f"  Personal-notes log ({len(notes)}):")
                for n in notes[:10]:
                    lines.append(f"    · {n.get('note','')[:120]}")
            lines.append("")
            lines.append("(I don't store full chat transcripts per contact yet — "
                          "what you see above is the running notes I've kept.)")
            return {"reply": "\n".join(lines), "tier": "local",
                    "latency_ms": 0, "source": "contacts_convo"}
        return {"reply": (
            f"I don't have \"{name}\" as a contact, and I don't store full "
            f"per-person conversation transcripts yet. What I CAN show you:\n"
            f"  · running notes per contact (use \"find {name}\")\n"
            f"  · website-chat leads (use \"show me recent leads\")\n"
            f"  · per-project history (use \"history for <project>\")"
        ), "tier": "local", "latency_ms": 0,
           "source": "contacts_convo_unknown"}

    # ALL CONTACTS — "show me my contacts" / "who are all my contacts?"
    if _CONTACTS_ALL_RE.match(msg):
        all_c = mod_contacts.list_all(user_dir)
        if not all_c:
            return {"reply": "Your contact book is empty. Add one with: "
                              "\"add a new contact named John Smith\".",
                    "tier": "local", "latency_ms": 0,
                    "source": "contacts_empty"}
        lines = [f"Your contacts ({len(all_c)}):"]
        for c in all_c[:30]:
            bits = [c.get("name", "?")]
            if c.get("company"): bits.append(c["company"])
            if c.get("phone"):   bits.append(c["phone"])
            lines.append("  · " + " — ".join(bits))
        return {"reply": "\n".join(lines), "tier": "local",
                "latency_ms": 0, "source": "contacts_all"}

    # ROLE/TAG SEARCH — "find my attorney contacts" / "show me plumber contacts"
    m_role = _re.match(
        r"^\s*(?:find|show|list|get)\s+(?:me\s+)?(?:all\s+)?(?:my\s+)?"
        r"(?P<role>[a-z][a-z\s'\-]{2,30}?)\s+contacts?\s*[?.!]?\s*$",
        msg, _re.IGNORECASE,
    )
    if m_role:
        role = (m_role.group("role") or "").strip().lower()
        if role and role not in {"new", "all", "my", "recent", "the"}:
            all_c = mod_contacts.list_all(user_dir)
            hits = [c for c in all_c if
                    role in (c.get("notes") or "").lower()
                    or role in (c.get("company") or "").lower()
                    or any(role in t.lower() for t in (c.get("tags") or []))
                    or any(role in w for w in (c.get("name") or "").lower().split())]
            if not hits:
                return {"reply": f"No contacts found matching \"{role}\".",
                        "tier": "local", "latency_ms": 0,
                        "source": "contacts_not_found"}
            lines = [f"Contacts matching \"{role}\" ({len(hits)}):"]
            for c in hits[:20]:
                bits = [c.get("name", "?")]
                if c.get("company"): bits.append(c["company"])
                if c.get("phone"):   bits.append(c["phone"])
                lines.append("  · " + " — ".join(bits))
            return {"reply": "\n".join(lines), "tier": "local",
                    "latency_ms": 0, "source": "contacts_found"}

    # LOCATION SEARCH — "do I have any contacts in Sparks?"
    m_loc = _re.match(
        r"^\s*(?:do\s+i\s+have|are\s+there|show|find|list)\s+(?:any\s+)?(?:my\s+)?contacts?\s+"
        r"(?:in|from|at|near)\s+(?P<loc>.+?)\s*[?.!]?\s*$",
        msg, _re.IGNORECASE,
    )
    if m_loc:
        loc = (m_loc.group("loc") or "").strip().lower()
        if loc:
            all_c = mod_contacts.list_all(user_dir)
            hits = [c for c in all_c if
                    loc in (c.get("notes") or "").lower()
                    or loc in (c.get("address") or "").lower()
                    or loc in (c.get("company") or "").lower()
                    or loc in (c.get("name") or "").lower()]
            if not hits:
                return {"reply": f"No contacts found in \"{loc}\".",
                        "tier": "local", "latency_ms": 0,
                        "source": "contacts_not_found"}
            lines = [f"Contacts in \"{loc}\" ({len(hits)}):"]
            for c in hits[:20]:
                bits = [c.get("name", "?")]
                if c.get("company"): bits.append(c["company"])
                if c.get("phone"):   bits.append(c["phone"])
                lines.append("  · " + " — ".join(bits))
            return {"reply": "\n".join(lines), "tier": "local",
                    "latency_ms": 0, "source": "contacts_found"}
    return None


_LEADS_RECENT_RE = _re.compile(
    r"^\s*(?:"
    r"(?:show|list|give)\s+(?:me\s+)?(?:all\s+)?(?:my\s+|the\s+)?(?:new\s+|recent\s+)?leads?"
    r"(?:\s+(?:from\s+|in\s+|for\s+)?(?:the\s+)?(?:this|past|last|recent)?\s*"
    r"(?P<period>week|month|day|today|24\s*hours?|hours?|overnight)?)?"
    r"|(?:what|any)\s+(?:new\s+)?leads?\s+(?:came\s+in\s+)?(?P<period2>overnight|today|this\s+week|this\s+month)"
    r"|recent\s+leads?"
    r"|new\s+leads?(?:\s+this\s+(?P<period3>week|month))?"
    r")\s*[?.!]?\s*$",
    _re.IGNORECASE,
)


def _try_leads_chat(message: str, user_rec: dict) -> dict | None:
    """'Show me leads from this week' / 'what new leads came in overnight'.
    Reads modules/messages.py — the website-chat lead capture log."""
    if not message:
        return None
    msg = _strip_polite_prefix(message)
    m = _LEADS_RECENT_RE.match(msg)
    if not m:
        return None
    period_raw = (m.group("period") or m.group("period2")
                  or m.group("period3") or "week").strip().lower()
    from datetime import datetime as _dt, timedelta as _td
    now = _dt.now()
    if "overnight" in period_raw or "24" in period_raw or "today" in period_raw or "day" in period_raw or "hour" in period_raw:
        cutoff = now - _td(hours=24)
        label = "the past 24 hours"
    elif "month" in period_raw:
        cutoff = now - _td(days=30)
        label = "this month"
    else:
        cutoff = now - _td(days=7)
        label = "this week"
    try:
        msgs = mod_messages.list_all(DATA_DIR) or []
    except Exception:
        msgs = []
    recent = []
    for m_rec in msgs:
        ts = m_rec.get("timestamp") or m_rec.get("ts") or 0
        try:
            ts_dt = _dt.fromtimestamp(float(ts))
        except (ValueError, OSError, TypeError):
            try:
                ts_dt = _dt.fromisoformat(str(ts).replace("Z", "+00:00"))
            except (ValueError, OSError, TypeError):
                continue
        if ts_dt >= cutoff:
            recent.append((ts_dt, m_rec))
    if not recent:
        return {"reply": f"No new leads in {label}.",
                "tier": "local", "latency_ms": 0,
                "source": "leads_recent_empty"}
    recent.sort(key=lambda t: t[0], reverse=True)
    lines = [f"📨 Leads from {label} ({len(recent)}):"]
    for ts_dt, m_rec in recent[:15]:
        name = m_rec.get("from_name") or m_rec.get("name") or "(no name)"
        phone = m_rec.get("from_phone") or m_rec.get("phone") or ""
        email = m_rec.get("from_email") or m_rec.get("email") or ""
        body = (m_rec.get("body") or m_rec.get("message") or "")[:100]
        when = ts_dt.strftime("%a %b %-d %-I:%M %p")
        contact_bit = ""
        if phone: contact_bit = f" — {phone}"
        elif email: contact_bit = f" — {email}"
        lines.append(f"  · {when} — {name}{contact_bit}")
        if body:
            lines.append(f"      \"{body}\"")
    return {"reply": "\n".join(lines), "tier": "local",
            "latency_ms": 0, "source": "leads_recent"}


_LEAD_ADD_RE = _re.compile(
    r"^\s*(?:"
    r"add\s+(?:me|us|(?P<who>[A-Z][A-Za-z'\-]+(?:\s+[A-Z][A-Za-z'\-]+){0,3}))\s+(?:as\s+)?(?:a\s+)?(?:new\s+)?lead"
    r"|(?:log|create|record|file)\s+(?:a\s+)?(?:new\s+)?lead"
    r"|add\s+a\s+(?:new\s+)?lead[:\s]+"
    r")",
    _re.IGNORECASE,
)


def _try_lead_add(message: str, user_rec: dict) -> dict | None:
    """'Add me as a new lead. My name is John Smith, phone 775-555-1212.'
    Writes a real entry to messages.json so it shows in the leads inbox
    AND in the recent-leads query — instead of the LLM fabricating 'Done'."""
    if not message:
        return None
    msg = _strip_polite_prefix(message)
    if not _LEAD_ADD_RE.match(msg):
        return None
    # Pull name from explicit "My name is X" / "named X" / regex 'who' group
    # Also handles "add a lead: Brian Castellano from Apex..." — first capitalized
    # name phrase after "lead:" is the lead's name.
    name = ""
    name_m = _re.search(r"(?:my\s+name\s+is|name\s+is|named|name[:\s]+)\s+([A-Z][A-Za-z'\-]+(?:\s+[A-Z][A-Za-z'\-]+){0,3})", message)
    if name_m:
        name = name_m.group(1).strip()
    else:
        who_m = _LEAD_ADD_RE.match(msg)
        if who_m and who_m.groupdict().get("who"):
            name = who_m.group("who").strip()
        else:
            # "add a lead: Brian Castellano from Apex..." — extract first proper name
            after_colon = _re.search(r'lead[:\s]+\s*(.+)', msg, _re.IGNORECASE)
            if after_colon:
                first_name_m = _re.match(
                    r'([A-Z][A-Za-z\'\-]+(?:\s+[A-Z][A-Za-z\'\-]+){0,3})',
                    after_colon.group(1).strip()
                )
                if first_name_m:
                    name = first_name_m.group(1).strip()
    phone = ""
    phone_m = _re.search(r"(\+?\d[\d\-\(\)\s]{7,}\d)", message)
    if phone_m:
        phone = phone_m.group(1).strip()
    email = ""
    email_m = _re.search(r"[\w\.-]+@[\w\.-]+\.\w+", message)
    if email_m:
        email = email_m.group(0).strip()
    if not (phone or email or name):
        return {"reply": ("I need at least a name, phone number or email to add a lead — "
                          "e.g. \"add lead: John Smith, phone 775-555-1212\"."),
                "tier": "local", "latency_ms": 0,
                "source": "lead_add_no_contact"}
    try:
        captured = mod_messages.capture(
            DATA_DIR,
            msg_type="lead",
            from_name=name or None,
            from_phone=phone or None,
            from_email=email or None,
            body=message[:500],
            source="owner_chat",
            config=CONFIG,
        )
    except Exception as e:
        log.warning(f"owner-chat lead capture failed: {e}")
        return {"reply": f"Couldn't save the lead: {e}",
                "tier": "local", "latency_ms": 0,
                "source": "lead_add_error"}
    try:
        notify.send(
            CONFIG, DATA_DIR, event="new_lead",
            title=f"New lead: {name or phone or email}",
            body=message[:200], url="/owner",
        )
    except Exception:
        pass
    audit.log_event(DATA_DIR, actor=user_rec.get("username", "?"),
                    action="lead.captured",
                    meta={"message_id": captured.get("id"),
                          "via": "owner_chat"})
    label = name or phone or email
    return {"reply": f"Saved as a lead — {label}. Open the Leads tab to see it.",
            "tier": "local", "latency_ms": 0,
            "source": "lead_added"}


# ---------------------------------------------------------------------------
# Email chat handlers — wire chat intents to email_inbox + safe_send.
# These run BEFORE the "unwired email" fallback so chat can actually
# read, search, compose, and reply via the user's connected accounts.
# Gmail + Outlook OAuth and IMAP/SMTP are all supported under the hood.
# ---------------------------------------------------------------------------

_EMAIL_CHECK_RE = _re.compile(
    r"^\s*(?:"
    r"(?:show|list|read|get|check)\s+(?:me\s+)?(?:my\s+)?"
    r"(?:today'?s\s+)?(?:important\s+|recent\s+|new\s+|unread\s+|last\s+\d+\s+)?emails?\b"
    r"|what(?:'s| is)\s+(?:important|in|new)\s+in\s+(?:my\s+)?(?:inbox|email)"
    r"|any(?:thing)?\s+important\s+in\s+(?:my\s+)?(?:inbox|email)"
    r"|read\s+(?:me\s+)?(?:my\s+)?inbox"
    r"|inbox\s+summary"
    r")\b",
    _re.IGNORECASE,
)

_EMAIL_SEARCH_RE = _re.compile(
    r"^\s*(?:"
    r"(?:find|search|look\s+for|locate)\s+(?:the\s+|an?\s+)?"
    r"emails?\s+(?:from|about|related\s+to|on|for|with|containing)\s+(?P<q>.+?)"
    r"|search\s+(?:my\s+)?(?:emails?|inbox)\s+(?:for|about)\s+(?P<q2>.+?)"
    r")\s*[.?!]?\s*$",
    _re.IGNORECASE,
)

_EMAIL_COMPOSE_RE = _re.compile(
    r"^\s*(?:"
    r"email\s+(?P<who1>[A-Z][A-Za-z .'\-]{1,40}?)[\s,:]\s*"
    r"(?:saying|that|and\s+(?:say|tell\s+them)|—|-)\s*(?P<body1>.+?)"
    r"|email\s+(?P<who2>[A-Z][A-Za-z .'\-]{1,40}?):\s*(?P<body2>.+?)"
    r"|send\s+(?P<who3>[A-Z][A-Za-z .'\-]{1,40}?)\s+(?:an\s+)?email\s+"
    r"(?:saying|that)\s+(?P<body3>.+?)"
    r"|compose\s+(?:an?\s+)?email\s+to\s+(?P<who4>[A-Z][A-Za-z .'\-]{1,40}?)\s+"
    r"(?:saying|about|that)\s+(?P<body4>.+?)"
    r")\s*[.?!]?\s*$",
)

_EMAIL_REPLY_RE = _re.compile(
    r"^\s*(?:"
    r"(?:draft|write|compose)\s+(?:a\s+|an\s+)?(?:reply|response)\s+"
    r"to\s+(?:the\s+(?:latest\s+|recent\s+)?(?:email|message)\s+from\s+)?"
    r"(?P<who1>[A-Z][A-Za-z .'\-]{1,40}?)\s+"
    r"(?:saying|that|with|—|-)\s*(?P<body1>.+?)"
    r"|reply\s+to\s+(?P<who2>[A-Z][A-Za-z .'\-]{1,40}?)\s+"
    r"(?:saying|that|—|-)\s*(?P<body2>.+?)"
    r"|reply\s+to\s+(?P<who3>[A-Z][A-Za-z .'\-]{1,40}?):\s*(?P<body3>.+?)"
    r")\s*[.?!]?\s*$",
)


_VOICEMAIL_CHECK_RE = _re.compile(
    r"\b(?:voicemail|voice\s+mail|voice\s+message|missed\s+call)s?\b",
    _re.IGNORECASE,
)


def _try_voicemail_check(message: str, user_rec: dict) -> dict | None:
    """Return actual voicemail count from disk instead of letting the LLM guess."""
    if not _VOICEMAIL_CHECK_RE.search(message):
        return None
    try:
        vms = voicemail_mod.list_voicemails(DATA_DIR, limit=20)
    except Exception:
        return None
    unhandled = [v for v in vms if not v.get("handled")]
    if not vms:
        reply = "No voicemails — your inbox is clear."
    elif not unhandled:
        reply = f"You have {len(vms)} voicemail{'s' if len(vms) != 1 else ''}, all already handled."
    else:
        lines = []
        for v in unhandled[:5]:
            caller = v.get("caller_name") or v.get("from_number") or "Unknown caller"
            ts = v.get("received_at", "")[:16].replace("T", " ")
            summary = v.get("summary") or v.get("transcript", "")[:80]
            lines.append(f"  · {caller} ({ts}) — {summary}" if summary else f"  · {caller} ({ts})")
        more = f"\n  …and {len(unhandled) - 5} more." if len(unhandled) > 5 else ""
        reply = (f"You have {len(unhandled)} unhandled voicemail{'s' if len(unhandled) != 1 else ''}:\n"
                 + "\n".join(lines) + more
                 + "\n\nOpen the Voicemails tab to listen or mark them handled.")
    return {"reply": reply, "tier": "local", "latency_ms": 0, "source": "voicemail_check"}


def _try_email_check_inbox(message: str, user_rec: dict) -> dict | None:
    """Triage: "what's important in my inbox" / "show me my email" — fetches
    the inbox, lists top unread + flagged messages with sender + subject +
    snippet. Returns None if no match."""
    if not message:
        return None
    msg = _strip_polite_prefix(message)
    if not _EMAIL_CHECK_RE.match(msg):
        return None
    try:
        import email_inbox
    except Exception:
        return None
    username = user_rec.get("username", "owner")
    try:
        user_dir = users_mod.get_user_dir(DATA_DIR, username)
    except Exception:
        return None
    try:
        limit_m = _re.search(r"\blast\s+(\d+)\s+emails?\b", msg, _re.IGNORECASE)
        display_limit = max(1, min(25, int(limit_m.group(1)))) if limit_m else 10
        fetch_limit = max(20, display_limit)
        # Use cache if it's under 5 minutes old — avoids hanging the browser
        # on slow IMAP providers (Yahoo can take 30s+). Only force a live
        # refresh when the user explicitly asks ("refresh my email") or
        # specifies a count (they expect fresh data).
        refresh_words = _re.search(r"\b(?:refresh|reload|update|new|latest|fresh)\b",
                                   msg, _re.IGNORECASE)
        force = bool(limit_m or refresh_words)
        if not force:
            cached = email_inbox._read_cache(user_dir)
            cache_age = _time.time() - (cached or {}).get("ts", 0) if cached else 999
            force = cache_age > 300  # refresh if cache is older than 5 minutes
        result = email_inbox.fetch_inbox(CONFIG, user_dir,
                                          source="all", limit=fetch_limit,
                                          force_refresh=force)
    except Exception as e:
        log.warning(f"email fetch failed: {e}")
        # Try returning stale cache rather than a hard error
        try:
            cached = email_inbox._read_cache(user_dir)
            if cached and cached.get("data", {}).get("messages"):
                stale = cached["data"]
                stale["from_cache"] = True
                result = stale
            else:
                raise
        except Exception:
            return {"reply": (
                "I couldn't reach your email right now — Yahoo IMAP is slow to respond. "
                "Try again in a moment, or say \"refresh my email\" to force a new fetch."
            ), "tier": "local", "latency_ms": 0, "source": "email_fetch_error"}

    msgs = result.get("messages") or []
    msgs = msgs[:display_limit]
    if not msgs:
        # No connector or empty inbox
        if result.get("errors"):
            errs = ", ".join(result["errors"].keys())
            return {"reply": (
                f"I don't have an email account connected yet — go to "
                f"Settings → Integrations and connect Gmail or Outlook, "
                f"then ask me again. (Tried: {errs})"
            ), "tier": "local", "latency_ms": 0, "source": "email_no_connector"}
        return {"reply": "Your inbox is empty — nothing to triage.",
                "tier": "local", "latency_ms": 0, "source": "email_empty"}

    # Prioritize flagged + unread
    flagged = [m for m in msgs if m.get("flagged")]
    unread  = [m for m in msgs if m.get("unread") and not m.get("flagged")]
    others  = [m for m in msgs if not m.get("flagged") and not m.get("unread")]

    lines = [f"📬 Inbox — {len(msgs)} message(s), "
             f"{result.get('by_category', {}).get('lead', 0)} lead(s), "
             f"{len(unread) + len(flagged)} unread."]
    section = lambda title, items: (
        [f"\n{title}:"] + [
            f"  · {m.get('from','?').split('<')[0].strip()} — "
            f"{(m.get('subject') or '(no subject)')[:80]}\n"
            f"    {(m.get('snippet') or '')[:140]}"
            for m in items[:5]
        ]
    ) if items else []
    lines.extend(section("Flagged",  flagged))
    lines.extend(section("Unread",   unread))
    if not flagged and not unread:
        lines.extend(section("Recent", others))
    return {"reply": "\n".join(lines), "tier": "local",
            "latency_ms": 0, "source": "email_check_inbox"}


def _try_email_search(message: str, user_rec: dict) -> dict | None:
    """Search: "find emails from Bob about the lease" — pulls the last
    100 messages and filters in Python so the same handler works
    against Gmail / Outlook / IMAP without each needing its own
    sender-vs-subject query language. Matches sender, subject, and the
    cached snippet (case-insensitive)."""
    if not message:
        return None
    msg = _strip_polite_prefix(message)
    m = _EMAIL_SEARCH_RE.match(msg)
    if not m:
        return None
    query = (m.group("q") or m.group("q2") or "").strip().rstrip("?.!")
    if not query or len(query) < 2:
        return None
    try:
        import email_inbox
    except Exception:
        return None
    username = user_rec.get("username", "owner")
    try:
        user_dir = users_mod.get_user_dir(DATA_DIR, username)
    except Exception:
        return None
    # Search owner chat from the latest cached inbox snapshot. A fresh IMAP
    # pull can take longer than the chat UI timeout on Yahoo/iCloud, which
    # looks like Orbi froze. "Check my email" refreshes the snapshot; search
    # stays instant and deterministic.
    try:
        cached = email_inbox._read_cache(user_dir)  # local module helper
    except Exception:
        cached = None
    result = (cached or {}).get("data") or {}
    all_msgs = result.get("messages") or []
    if not all_msgs:
        return {"reply": (
            "I don't have a recent inbox snapshot to search yet. Say "
            "\"check my email\" first, then ask me to search it."
        ), "tier": "local", "latency_ms": 0, "source": "email_search_no_cache"}
    q_low = query.lower()
    def _matches(item: dict) -> bool:
        return (q_low in (item.get("from") or "").lower()
                or q_low in (item.get("subject") or "").lower()
                or q_low in (item.get("snippet") or "").lower())
    msgs = [x for x in all_msgs if _matches(x)]
    if not msgs:
        return {"reply": f"No emails found matching \"{query}\" "
                          f"(searched the latest cached {len(all_msgs)} messages). "
                          f"Say \"check my email\" to refresh the cache, then search again.",
                "tier": "local", "latency_ms": 0,
                "source": "email_search_empty"}
    else:
        source_label = "cached"
    lines = [f"📧 Found {len(msgs)} {source_label} email(s) matching \"{query}\":"]
    for m_ in msgs[:8]:
        lines.append(
            f"  · {m_.get('from','?').split('<')[0].strip()} — "
            f"{(m_.get('subject') or '(no subject)')[:70]} "
            f"({(m_.get('date') or '')[:10]})"
        )
    return {"reply": "\n".join(lines), "tier": "local",
            "latency_ms": 0, "source": "email_search"}


def _try_email_compose(message: str, user_rec: dict) -> dict | None:
    """Compose: "email Bill Henry: parts came in" — looks up the contact,
    sends via safe_send (or drafts if not whitelisted). Returns None if
    no match."""
    if not message:
        return None
    msg = _strip_polite_prefix(message)
    m = _EMAIL_COMPOSE_RE.match(msg)
    if not m:
        return None
    who  = (m.group("who1") or m.group("who2") or m.group("who3")
            or m.group("who4") or "").strip()
    body = (m.group("body1") or m.group("body2") or m.group("body3")
            or m.group("body4") or "").strip()
    if not who or not body:
        return None
    try:
        import safe_send
        from modules import contacts as mod_contacts
    except Exception:
        return None
    username = user_rec.get("username", "owner")
    try:
        user_dir = users_mod.get_user_dir(DATA_DIR, username)
    except Exception:
        return None
    contact = mod_contacts.find_by_name(user_dir, who)
    if not contact or not contact.get("email"):
        return {"reply": (
            f"I couldn't find an email address for \"{who}\" in your "
            f"contacts. Add one with: \"add {who}, their-email@example.com\" "
            f"and then I can send."
        ), "tier": "local", "latency_ms": 0, "source": "email_no_contact"}

    # Generate a clean subject from the body (first 8 words, capitalized)
    words = body.split()
    subject = " ".join(words[:8]).rstrip(".,!?")
    if len(words) > 8:
        subject += "..."

    res = safe_send.send_email(
        CONFIG, user_dir,
        to_email=contact["email"],
        subject=subject or "(message from Orby)",
        body=body,
        category="general",  # default — owner can whitelist categories in prefs
    )
    # If no Gmail/Outlook is connected, fall back to IMAP/SMTP. Yahoo +
    # other custom mailboxes go through imap_smtp.send_email which uses
    # the user's stored SMTP credentials.
    if res.get("action") == "error" and res.get("reason") == "no_connector":
        import imap_smtp
        accts = imap_smtp.list_accounts(user_dir)
        if accts:
            account_id = accts[0]["id"]
            smtp_res = imap_smtp.send_email(
                user_dir, account_id,
                to=contact["email"],
                subject=subject or "(message from Orby)",
                body=body,
            )
            if smtp_res.get("ok"):
                return {"reply": (
                    f"✓ Sent to {contact.get('name', who)} ({contact['email']}) "
                    f"via {accts[0].get('email','your mailbox')}.\n"
                    f"Subject: {subject}"
                ), "tier": "local", "latency_ms": 0, "source": "email_sent"}
            return {"reply": (
                f"I couldn't send to {who}: {smtp_res.get('error','SMTP error')}."
            ), "tier": "local", "latency_ms": 0, "source": "email_send_failed"}
    if res.get("action") == "sent":
        return {"reply": (
            f"✓ Sent to {contact.get('name', who)} ({contact['email']}).\n"
            f"Subject: {subject}\n"
            f"Sent via {res.get('via', '?')}."
        ), "tier": "local", "latency_ms": 0, "source": "email_sent"}
    elif res.get("action") == "drafted":
        return {"reply": (
            f"📝 Drafted to {contact.get('name', who)} ({contact['email']}) — "
            f"saved to your {res.get('via','?')} Drafts folder for review. "
            f"({res.get('reason', '')}.)\nSubject: {subject}"
        ), "tier": "local", "latency_ms": 0, "source": "email_drafted"}
    else:
        return {"reply": (
            f"I couldn't send to {who}: {res.get('error', 'unknown error')}. "
            f"Connect Gmail or Outlook in Settings → Integrations, or "
            f"add an IMAP/SMTP account."
        ), "tier": "local", "latency_ms": 0, "source": "email_send_failed"}


_EMAIL_READ_RE = _re.compile(
    r"^\s*(?:"
    r"(?:what(?:'s| does| do| is)|tell\s+me\s+what)\s+(?:the\s+)?"
    r"(?:latest\s+|recent\s+|new\s+)?email\s+from\s+(?P<who1>[A-Za-z][A-Za-z .'\-@]{1,60}?)"
    r"\s+(?:say|says|contains?|is\s+about)"
    r"|(?:read|open|show\s+me)\s+(?:the\s+)?(?:latest\s+|recent\s+|new\s+)?"
    r"email\s+from\s+(?P<who2>[A-Za-z][A-Za-z .'\-@]{1,60}?)"
    r"|(?:show|read)\s+me\s+(?P<who3>[A-Za-z][A-Za-z .'\-@]{1,60}?)'s\s+(?:latest\s+)?email"
    r")\s*[.?!]?\s*$",
    _re.IGNORECASE,
)


def _try_email_read(message: str, user_rec: dict) -> dict | None:
    """'what does the email from Frank Street say' — find the latest
    email matching the sender, fetch its full body via IMAP, return
    subject + from + date + body excerpt. No LLM call so the body is
    real, not invented."""
    if not message:
        return None
    msg = _strip_polite_prefix(message)
    m = _EMAIL_READ_RE.match(msg)
    if not m:
        return None
    who = next((m.group(g) for g in ("who1", "who2", "who3")
                if m.group(g)), "").strip()
    if not who:
        return None
    try:
        import email_inbox
    except Exception:
        return None
    username = user_rec.get("username", "owner")
    try:
        user_dir = users_mod.get_user_dir(DATA_DIR, username)
    except Exception:
        return None
    # Pull the inbox (cached if recent) and find the newest msg from `who`
    try:
        result = email_inbox.fetch_inbox(CONFIG, user_dir, source="all",
                                          limit=50, force_refresh=False)
    except Exception as e:
        log.warning(f"email_read fetch failed: {e}")
        return {"reply": (
            f"I couldn't reach your inbox to pull that message.\n"
            f"Error: {str(e)[:100]}\n"
            f"Try again in a moment — IMAP servers stall sometimes. If "
            f"this keeps happening, open Settings → Email Accounts and "
            f"click \"Test connection\" to see the exact failure."
        ), "tier": "local", "latency_ms": 0,
            "source": "email_read_fetch_error"}
    msgs = result.get("messages") or []
    who_low = who.lower()
    matches = [m for m in msgs
               if who_low in (m.get("from") or "").lower()]
    if not matches:
        return {"reply": (
            f"I don't see a recent email from \"{who}\" in your inbox. "
            f"Try a different spelling or the sender's email address."
        ), "tier": "local", "latency_ms": 0, "source": "email_read_no_match"}
    target = matches[0]  # newest first
    body_res = email_inbox.get_message(CONFIG, user_dir, target["id"])
    if body_res.get("error"):
        return {"reply": (
            f"I found the email from {target.get('from', who).split('<')[0].strip()} "
            f"(\"{target.get('subject', '?')}\") but couldn't fetch the body: "
            f"{body_res['error']}."
        ), "tier": "local", "latency_ms": 0, "source": "email_read_body_error"}
    body = (body_res.get("body") or "").strip()
    if not body:
        body = "(empty body — likely an image-only or HTML-only message)"
    return {"reply": (
        f"📧 From: {target.get('from', who)}\n"
        f"Subject: {target.get('subject', '(no subject)')}\n"
        f"Date: {target.get('date', '')[:16]}\n"
        f"\n{body[:2000]}"
        + ("\n\n…(body trimmed at 2000 chars)" if len(body) > 2000 else "")
    ), "tier": "local", "latency_ms": 0, "source": "email_read"}


def _extract_email_addr(from_field: str) -> str:
    """Pull just the email out of a "Name <email@host>" From: header."""
    if not from_field:
        return ""
    import email.utils as _eu
    _name, addr = _eu.parseaddr(from_field)
    return (addr or "").strip()


def _try_email_reply(message: str, user_rec: dict) -> dict | None:
    """Reply: "reply to Pam saying I'll be there at 4" — find the latest
    message from the named person, send the reply via the correct
    provider (Gmail / Outlook draft, OR IMAP/SMTP if that's what's
    connected). Returns None if no match."""
    if not message:
        return None
    msg = _strip_polite_prefix(message)
    m = _EMAIL_REPLY_RE.match(msg)
    if not m:
        return None
    who  = (m.group("who1") or m.group("who2") or m.group("who3") or "").strip()
    body = (m.group("body1") or m.group("body2") or m.group("body3") or "").strip()
    if not who or not body:
        return None
    try:
        import email_inbox
    except Exception:
        return None
    username = user_rec.get("username", "owner")
    try:
        user_dir = users_mod.get_user_dir(DATA_DIR, username)
    except Exception:
        return None
    # Find the latest message from this person — pull all recent and
    # filter in Python so we hit IMAP/Gmail/Outlook with a SINGLE round
    # trip instead of a sender-specific SEARCH that only works on some
    # providers.
    try:
        result = email_inbox.fetch_inbox(CONFIG, user_dir,
                                          source="all", limit=100,
                                          force_refresh=False)
    except Exception as e:
        log.warning(f"reply search failed: {e}")
        return {"reply": (
            f"I couldn't reach your email to find that message.\n"
            f"Error: {str(e)[:100]}\n"
            f"Wait a moment and try again, or open Settings → Email "
            f"Accounts and click \"Test connection\" to see what's wrong."
        ), "tier": "local", "latency_ms": 0,
            "source": "email_reply_search_error"}
    msgs = result.get("messages") or []
    who_low = who.lower()
    matches = [m for m in msgs
               if who_low in (m.get("from") or "").lower()]
    if not matches:
        return {"reply": (
            f"I couldn't find a recent email from \"{who}\". "
            f"Maybe try the full name or a different spelling?"
        ), "tier": "local", "latency_ms": 0, "source": "email_reply_no_match"}
    target = matches[0]
    # IMAP path — send the reply via SMTP using imap_smtp.send_email.
    # Gmail/Outlook still take the legacy draft_reply path (drafts in
    # the Gmail/Outlook UI, owner sends from there).
    if (target.get("provider") or "").lower() == "imap":
        import imap_smtp
        to_addr = _extract_email_addr(target.get("from", ""))
        if not to_addr:
            return {"reply": f"I couldn't parse a reply-to address from "
                              f"{target.get('from', who)}.",
                    "tier": "local", "latency_ms": 0,
                    "source": "email_reply_no_address"}
        # Pull the IMAP account id from the cached message id
        # ('imap-<account_id>-<uid>')
        try:
            account_id = target["id"].split("-", 1)[1].rsplit("-", 1)[0]
        except Exception:
            account_id = ""
        # Pull the original Message-ID (now in the cache) for threading
        in_reply_to = target.get("message_id") or ""
        subj = (target.get("subject") or "").strip()
        re_subj = subj if subj.lower().startswith("re:") else f"Re: {subj}"
        res = imap_smtp.send_email(
            user_dir, account_id,
            to=to_addr, subject=re_subj or "(no subject)",
            body=body, in_reply_to=in_reply_to or None,
        )
        if not res.get("ok"):
            return {"reply": (
                f"I couldn't send that reply: {res.get('error', 'unknown')}."
            ), "tier": "local", "latency_ms": 0, "source": "email_reply_send_failed"}
        return {"reply": (
            f"✓ Replied to {target.get('from', who).split('<')[0].strip()} "
            f"at {to_addr}.\n"
            f"Subject: {re_subj}\n"
            f"Body: {body[:200]}{'...' if len(body) > 200 else ''}"
        ), "tier": "local", "latency_ms": 0, "source": "email_replied"}
    # Gmail/Outlook fallback — old draft path
    res = email_inbox.draft_reply(CONFIG, user_dir, target["id"], body)
    if res.get("error"):
        return {"reply": (
            f"I couldn't draft that reply: {res['error']}."
        ), "tier": "local", "latency_ms": 0, "source": "email_reply_failed"}
    return {"reply": (
        f"📝 Drafted reply to {target.get('from','?').split('<')[0].strip()} — "
        f"saved to your Drafts folder for review and send.\n"
        f"Re: {(target.get('subject') or '(no subject)')[:70]}\n"
        f"Reply: {body[:140]}{'...' if len(body) > 140 else ''}"
    ), "tier": "local", "latency_ms": 0, "source": "email_reply_drafted"}


_UNWIRED_EMAIL_RE = _re.compile(
    r"^\s*(?:"
    r"(?:show|list|read|get|check)\s+(?:me\s+)?(?:my\s+)?(?:today'?s\s+)?(?:important\s+|recent\s+|new\s+)?emails?"
    r"|what(?:'s| is)\s+(?:important|in|new)\s+in\s+(?:my\s+)?inbox"
    r"|(?:show|list)\s+(?:me\s+)?emails?\s+(?:related\s+to|about|from|for)\s+"
    r"|find\s+(?:the\s+|an?\s+)?emails?\s+(?:from|about|related\s+to|on)"
    r"|search\s+(?:my\s+)?emails?\s+(?:for|about)"
    r"|(?:draft|write|compose)\s+(?:a\s+|an\s+)?(?:reply|response)\s+(?:to\s+|for\s+)"
    r"|email\s+(?:the\s+)?(?:latest\s+|new\s+|recent\s+)?(?:change\s+order|invoice|proposal|update|estimate)\s+to\s+"
    r"|email\s+\w+(?:\s+\w+)?\s+(?:the|a)\s+"
    # "Email Bill Henry: parts came in" / "Email Bill: x"
    r"|(?i:email)\s+[A-Z][A-Za-z'\-]+(?:\s+[A-Z][A-Za-z'\-]+)*\s*[:,]"
    # Imperative "send it / send the email right now"
    r"|send\s+(?:it|the\s+email|that\s+message)\s+(?:right\s+now|now)"
    r")",
    _re.IGNORECASE,
)
_UNWIRED_SMS_RE = _re.compile(
    r"^\s*(?:"
    r"(?:send|text|message)\s+(?:a\s+)?(?:text|sms|message)\s+(?:to\s+)?"
    r"|text\s+\w+(?:\s+\w+)?\s+"
    r"|(?:show|list)\s+(?:me\s+)?(?:all\s+)?(?:my\s+)?(?:texts?|sms\s+messages?)\s+(?:from|to|with)\s+"
    r"|text\s+every(?:one|body)?\s+"
    r"|text\s+(?:every\s+)?lead"
    r")",
    _re.IGNORECASE,
)
_SMS_SEND_DIRECT_RE = _re.compile(
    r"^\s*(?:send\s+(?:a\s+)?(?:text|sms|message)|text|message)\s+"
    r"(?:to\s+)?(?P<to>\+?[\d\-\(\)\s]{7,}\d)\s+"
    r"(?:saying|that|with|:|-)\s*(?P<body>.+?)\s*[.?!]?\s*$",
    _re.IGNORECASE | _re.DOTALL,
)
_SMS_SEND_BODY_TO_NUMBER_RE = _re.compile(
    r"^\s*(?:send\s+)?(?:a\s+)?(?:text|sms|message)\s+"
    r"(?P<body>.+?)\s+to\s+(?P<to>\+?[\d\-\(\)\s]{7,}\d)\s*[.?!]?\s*$",
    _re.IGNORECASE | _re.DOTALL,
)
_SMS_SEND_TO_ME_RE = _re.compile(
    r"^\s*(?:can\s+you\s+|could\s+you\s+|please\s+)?(?:"
    r"(?:send\s+)?(?:a\s+)?(?:text|sms|message)\s+(?:me|myself)\s+"
    r"|send\s+(?:me|myself)\s+(?:a\s+)?(?:text|sms|message)\s+"
    r")(?:(?:that\s+)?(?:saying|says|say|with)\s+)?(?P<body>.+?)\s*[.?!]?\s*$",
    _re.IGNORECASE | _re.DOTALL,
)
_SMS_SEND_TO_ME_NEEDS_BODY_RE = _re.compile(
    r"^\s*(?:can\s+you\s+|could\s+you\s+|please\s+)?(?:"
    r"(?:send\s+)?(?:a\s+)?(?:text|sms|message)\s+(?:me|myself)"
    r"|send\s+(?:me|myself)\s+(?:a\s+)?(?:text|sms|message)"
    r")\s*[.?!]?\s*$",
    _re.IGNORECASE,
)
_SMS_SEND_TO_PERSON_PATTERNS = [
    _re.compile(
        r"^\s*(?:send\s+)?(?:a\s+)?(?:text|sms|message)\s+to\s+"
        r"(?P<who>[A-Za-z][A-Za-z .'\-]{0,60}?)\s+"
        r"(?:(?:that\s+)?(?:saying|says|say)|with|:|-|and\s+say)\s+"
        r"(?P<body>.+?)\s*[.?!]?\s*$",
        _re.IGNORECASE | _re.DOTALL,
    ),
    _re.compile(
        r"^\s*send\s+(?P<who>[A-Za-z][A-Za-z .'\-]{0,60}?)\s+"
        r"(?:a\s+)?(?:text|sms|message)\s+"
        r"(?:(?:that\s+)?(?:saying|says|say)|with|:|-|and\s+say)\s+"
        r"(?P<body>.+?)\s*[.?!]?\s*$",
        _re.IGNORECASE | _re.DOTALL,
    ),
    _re.compile(
        r"^\s*(?:text|message)\s+(?P<who>[A-Za-z][A-Za-z .'\-]{0,60}?)\s*[:\-]\s*"
        r"(?P<body>.+?)\s*[.?!]?\s*$",
        _re.IGNORECASE | _re.DOTALL,
    ),
    _re.compile(
        r"^\s*(?:text|message)\s+(?P<who>[A-Za-z][A-Za-z .'\-]{0,60}?)\s+"
        r"(?:(?:that\s+)?(?:saying|says|say)|with|:|-)?\s*"
        r"(?P<body>.+?)\s*[.?!]?\s*$",
        _re.IGNORECASE | _re.DOTALL,
    ),
]
_SMS_PERSON_NEEDS_BODY_PATTERNS = [
    _re.compile(
        r"^\s*(?:send\s+)?(?:a\s+)?(?:text|sms|message)\s+to\s+"
        r"(?P<who>[A-Za-z][A-Za-z .'\-]{1,60})\s*[.?!]?\s*$",
        _re.IGNORECASE,
    ),
    _re.compile(
        r"^\s*send\s+(?P<who>[A-Za-z][A-Za-z .'\-]{1,60})\s+"
        r"(?:a\s+)?(?:text|sms|message)\s*[.?!]?\s*$",
        _re.IGNORECASE,
    ),
]
_SMS_SEND_TO_THAT_ONE_RE = _re.compile(
    r"^\s*(?:yes\s+|yeah\s+|yep\s+|ok(?:ay)?\s+|sure\s+)?"
    r"(?:(?:send\s+)?(?:it|that|the\s+(?:text|sms|message))\s+)?"
    r"(?:(?:send\s+)?(?:a\s+)?(?:text|sms|message)\s+)?"
    r"(?:to\s+)?(?:that\s+one|that\s+number|it)\s+"
    r"(?:and\s+)?(?:just\s+)?"
    r"(?:(?:saying|say|with|:|-)|(?:send\s+(?:a\s+)?(?:text|sms|message)))\s*"
    r"(?P<body>.*?)\s*[.?!]?\s*$",
    _re.IGNORECASE | _re.DOTALL,
)
_SMS_CONTINUE_PARTIAL_NUMBER_RE = _re.compile(
    r"^\s*(?P<tail>\d{1,4})\s+(?:and\s+)?"
    r"(?:saying|say|with|:|-)\s*(?P<body>.+?)\s*[.?!]?\s*$",
    _re.IGNORECASE | _re.DOTALL,
)
_SMS_PARTIAL_NUMBER_RE = _re.compile(
    r"^\s*(?:send\s+(?:a\s+)?(?:text|sms|message)|text|message)\s+"
    r"(?:to\s+)?(?P<partial>\+?[\d\-\(\)\s]{5,})\s*[.?!]?\s*$",
    _re.IGNORECASE,
)
_SMS_NEEDS_NUMBER_RE = _re.compile(
    r"^\s*(?:send\s+(?:a\s+)?(?:text|sms|message)|text|message)\s+"
    r"(?:to\s+)?(?P<who>[A-Za-z][A-Za-z .'\-]{1,50})\s*[.?!]?\s*$",
    _re.IGNORECASE,
)
_SMS_BROAD_INTENT_RE = _re.compile(
    r"\b(?:send|sent|text|message|sms|notify)\b.*\b(?:text|message|sms)\b"
    r"|\b(?:text|message|sms)\b.*\b(?:send|tell|ask|let|notify|about)\b",
    _re.IGNORECASE,
)
_SMS_BROAD_RECIPIENT_RE = _re.compile(
    r"\b(?:to|for)\s+(?P<who>[A-Za-z][A-Za-z .'\-]{0,60}?)(?:\s+(?:about|that|saying|say|with|because|to)\b|$)",
    _re.IGNORECASE,
)
_SMS_BROAD_ABOUT_RE = _re.compile(r"\babout\s+(?P<topic>.+?)\s*[.?!]?$", _re.IGNORECASE)
_SMS_BROAD_BODY_RE = _re.compile(
    r"\b(?:that\s+)?(?:saying|says|say|with)\s+(?P<body>.+?)\s*[.?!]?$",
    _re.IGNORECASE | _re.DOTALL,
)
_SMS_CONFIRM_SEND_RE = _re.compile(
    r"^\s*(?:yes|yeah|yep|ok|okay|sure|please|do\s+it|send\s+it|send\s+that|"
    r"yes\s+send\s+(?:it|that)|go\s+ahead(?:\s+and\s+send\s+it)?)\s*[.?!]?\s*$",
    _re.IGNORECASE,
)
_EMAIL_RAW_ADDRESS_RE = _re.compile(
    r"^\s*(?:also\s+)?(?:send\s+)?(?:an?\s+)?(?P<test>test\s+)?email\s+to\s+"
    r"(?P<to>.+?)"
    r"(?:\s+(?:saying|that|with|:|-)\s*(?P<body>.+?))?\s*[.?!]?\s*$",
    _re.IGNORECASE | _re.DOTALL,
)
_EMAIL_RAW_BODY_FIRST_RE = _re.compile(
    r"^\s*(?:also\s+)?(?:send\s+)?(?:an?\s+)?(?P<test>test\s+)?email\s+"
    r"(?:that\s+)?(?:just\s+)?(?:says?|saying|with)\s+"
    r"(?P<body>.+?)\s+to\s+(?P<to>.+?)\s*[.?!]?\s*$",
    _re.IGNORECASE | _re.DOTALL,
)
_EMAIL_NEEDS_CONTACT_RE = _re.compile(
    r"^\s*email\s+(?:my\s+|the\s+)?(?P<who>[A-Za-z][A-Za-z .'\-]{1,50})\s*[.?!]?\s*$",
    _re.IGNORECASE,
)
_NOTES_SEARCH_RE = _re.compile(
    r"^\s*(?:"
    r"(?:search|find|look\s+for)\s+(?:my\s+)?notes?\s+(?:for|about)\s+(?P<q1>.+?)"
    r"|what\s+did\s+i\s+write\s+about\s+(?P<q2>.+?)"
    r"|what\s+notes?\s+do\s+i\s+have\s+(?:for|about)\s+(?P<q3>.+?)"
    r")\s*[.?!]?\s*$",
    _re.IGNORECASE | _re.DOTALL,
)
_UNWIRED_FILES_RE = _re.compile(
    r"^\s*(?:"
    r"(?:find|locate|get|fetch)\s+(?:the\s+)?(?P<q>.+?)\s+(?:contract|agreement|document|file|proposal|invoice|change[\s-]order|estimate)(?:s)?"
    r"|(?:show|open|find|fetch)\s+(?:me\s+)?(?:the\s+)?(?:signed\s+|latest\s+|recent\s+|most\s+recent\s+|newest\s+)(?:change[\s-]order|invoice|proposal|contract|document|file)"
    r"|(?:open|fetch)\s+(?:the\s+)?(?:latest\s+|recent\s+)?invoice\s+for\s+"
    r"|(?:search|find)\s+(?:for\s+)?(?:every\s+|all\s+)?file(?:s)?\s+(?:related\s+to|about|for|on)\s+"
    r")",
    _re.IGNORECASE,
)


def _try_notes_search(message: str, user_rec: dict) -> dict | None:
    """Search owner-authored notes deterministically."""
    if not message:
        return None
    msg = _strip_polite_prefix(" ".join(str(message).split()))
    m = _NOTES_SEARCH_RE.match(msg)
    if not m:
        return None
    query = (m.group("q1") or m.group("q2") or m.group("q3") or "").strip().strip('"')
    if not query:
        return None
    hits = mod_notes.search(DATA_DIR, query)
    if not hits:
        return {"reply": f"I didn't find \"{query}\" in your notes.",
                "tier": "local", "latency_ms": 0,
                "source": "notes_search_empty"}
    lines = [f"I found {len(hits)} note{'s' if len(hits) != 1 else ''} about \"{query}\":"]
    for n in sorted(hits, key=lambda x: x.get("ts", 0), reverse=True)[:5]:
        content = (n.get("content") or "").strip()
        if content:
            lines.append(f"- {content}")
    return {"reply": "\n".join(lines),
            "tier": "local", "latency_ms": 0,
            "source": "notes_search"}


def _normalize_email_address(raw: str) -> str | None:
    """Normalize typed or spoken email addresses.

    Examples:
      frank@example.com
      Frank R Street at yahoo.com -> frankrstreet@yahoo.com
      frank l street at icloud dot com -> franklstreet@icloud.com
    """
    s = (raw or "").strip().strip("<>\"' ").rstrip(".?!,;:")
    if not s:
        return None
    typed = _re.fullmatch(r"[\w.\-+]+@[\w.\-]+\.\w+", s, _re.IGNORECASE)
    if typed:
        return s.lower()

    spoken = _re.fullmatch(
        r"(?P<local>[A-Za-z0-9 ._\-+']+?)\s+at\s+(?P<domain>[A-Za-z0-9 .\-]+)",
        s,
        _re.IGNORECASE,
    )
    if not spoken:
        return None
    local = _re.sub(r"[^a-z0-9._+-]", "", spoken.group("local").lower())
    domain = spoken.group("domain").lower()
    domain = _re.sub(r"\s+dot\s+", ".", domain)
    domain = _re.sub(r"[^a-z0-9.-]", "", domain)
    addr = f"{local}@{domain}"
    if _re.fullmatch(r"[\w.\-+]+@[\w.\-]+\.\w+", addr, _re.IGNORECASE):
        return addr
    return None


def _try_email_raw_or_needs_contact(message: str, user_rec: dict) -> dict | None:
    """Handle email intents that should not fall into file search.
    Raw-address sends require a connected mailbox; contact-only asks request
    the missing address/contact instead of searching files."""
    if not message:
        return None
    msg = _strip_polite_prefix(" ".join(str(message).split()))
    m = _EMAIL_RAW_ADDRESS_RE.match(msg) or _EMAIL_RAW_BODY_FIRST_RE.match(msg)
    if m:
        to_email = _normalize_email_address(m.group("to") or "")
        if not to_email:
            return None
        body = (m.group("body") or "").strip()
        is_test = bool((m.group("test") or "").strip())
        if is_test and not body:
            body = "This is a test email from Orbi."
        if not body:
            return {"reply": (
                f"What should the email to {to_email} say?"
            ), "tier": "local", "latency_ms": 0,
               "source": "email_needs_body"}
        username = user_rec.get("username", "owner")
        user_dir = users_mod.get_user_dir(DATA_DIR, username)
        try:
            import imap_smtp
            accts = imap_smtp.list_accounts(user_dir)
        except Exception:
            accts = []
        if not accts:
            draft = f"\n\nDraft:\nTo: {to_email}\nSubject: Orbi owner email test\n\n{body}" if body else ""
            return {"reply": (
                "I don't have a connected mailbox for you yet, so I can't send "
                "that email from owner chat. Connect Gmail, Outlook, Yahoo, or "
                f"another SMTP account in Settings -> Integrations first.{draft}"
            ), "tier": "local", "latency_ms": 0,
               "source": "email_no_connected_mailbox"}
        subject_words = body.split()[:8]
        subject = " ".join(subject_words).rstrip(".,!?") or "Message from Orbi"
        if is_test:
            subject = "Orbi test email"
        try:
            sent = imap_smtp.send_email(
                user_dir, accts[0]["id"], to=to_email,
                subject=subject, body=body,
            )
        except Exception as e:
            sent = {"ok": False, "error": str(e)}
        if sent.get("ok"):
            return {"reply": (
                f"Email sent to {to_email}.\nSubject: {subject}"
            ), "tier": "local", "latency_ms": 0,
               "source": "email_sent_raw"}
        return {"reply": (
            f"I couldn't send that email to {to_email}: "
            f"{sent.get('error', 'email send failed')}."
        ), "tier": "local", "latency_ms": 0,
           "source": "email_send_failed"}
    m = _EMAIL_NEEDS_CONTACT_RE.match(msg)
    if m:
        who = (m.group("who") or "").strip().rstrip(".?!")
        return {"reply": (
            f"I need an email address or saved contact for {who} before I can "
            f"help with that. Try: 'Add {who} as a contact. Their email is name@example.com.'"
        ), "tier": "local", "latency_ms": 0,
           "source": "email_needs_contact"}
    return None


def _extract_pending_email_body_to(history: list[dict]) -> str:
    """Return the recipient from the latest email body question, if active."""
    if not isinstance(history, list):
        return ""
    for item in reversed(history[-8:]):
        if (item or {}).get("role") != "assistant":
            continue
        text = " ".join(str((item or {}).get("content") or "").split())
        text_l = text.lower()
        if "email sent to " in text_l or "couldn't send that email" in text_l:
            return ""
        m = _re.search(r"what should the email to ([\w.\-+]+@[\w.\-]+\.\w+) say\?", text, _re.IGNORECASE)
        if m:
            return m.group(1).strip().lower()
        # A newer non-email assistant turn means the old email question is stale.
        if text:
            return ""
    return ""


def _looks_like_new_owner_command(message: str) -> bool:
    msg = _strip_polite_prefix(" ".join(str(message or "").split()))
    if not msg:
        return False
    return bool(_re.match(
        r"^(?:"
        r"remind|nudge|schedule|book|block\s+off|meeting|appointment|cancel|delete|remove|drop|"
        r"what(?:'s| is)|who|when|where|why|how|show|list|find|search|mark|check|"
        r"add\s+(?:task|contact|note|reminder)|take\s+(?:a\s+)?note|"
        r"remember|my\s+name\s+is|send\s+(?:a\s+)?(?:text|sms|message|email)|text|message|email"
        r")\b",
        msg,
        _re.IGNORECASE,
    ))


def _is_bulk_sms_target(who: str) -> bool:
    target = " ".join(str(who or "").lower().split()).strip(" .?!")
    return bool(_re.match(
        r"^(?:every|everyone|everybody|all|all\s+contacts|all\s+leads|"
        r"lead|leads|customers?|clients?|the\s+team|team)\b",
        target,
        _re.IGNORECASE,
    ))


def _sms_prompt_label(who: str, label: str) -> str:
    """Use 'you' for explicit self-texts, but preserve named owner aliases.

    Frank's owner profile resolves "Frank" to the owner phone, which is
    correct for sending, but asking "What should the text to you say?"
    after "text Frank" sounds like Orbi lost the name.
    """
    who_l = " ".join(str(who or "").lower().split())
    if who_l in ("me", "myself", "my cell", "my cell phone", "my phone"):
        return "you"
    return (who or label or "them").strip()


def _send_raw_email(to_email: str, body: str, user_rec: dict,
                    *, is_test: bool = False) -> dict:
    body = (body or "").strip()
    username = user_rec.get("username", "owner")
    user_dir = users_mod.get_user_dir(DATA_DIR, username)
    try:
        import imap_smtp
        accts = imap_smtp.list_accounts(user_dir)
    except Exception:
        accts = []
    if not accts:
        draft = f"\n\nDraft:\nTo: {to_email}\nSubject: Orbi owner email test\n\n{body}" if body else ""
        return {"reply": (
            "I don't have a connected mailbox for you yet, so I can't send "
            "that email from owner chat. Connect Gmail, Outlook, Yahoo, or "
            f"another SMTP account in Settings -> Integrations first.{draft}"
        ), "tier": "local", "latency_ms": 0,
           "source": "email_no_connected_mailbox"}
    subject_words = body.split()[:8]
    subject = " ".join(subject_words).rstrip(".,!?") or "Message from Orbi"
    if is_test:
        subject = "Orbi test email"
    try:
        sent = imap_smtp.send_email(
            user_dir, accts[0]["id"], to=to_email,
            subject=subject, body=body,
        )
    except Exception as e:
        sent = {"ok": False, "error": str(e)}
    if sent.get("ok"):
        return {"reply": (
            f"Email sent to {to_email}.\nSubject: {subject}"
        ), "tier": "local", "latency_ms": 0,
           "source": "email_sent_raw"}
    return {"reply": (
        f"I couldn't send that email to {to_email}: "
        f"{sent.get('error', 'email send failed')}."
    ), "tier": "local", "latency_ms": 0,
       "source": "email_send_failed"}


def _try_email_body_followup(message: str, user_rec: dict,
                             history: list[dict]) -> dict | None:
    to_email = _extract_pending_email_body_to(history)
    if not to_email:
        return None
    msg = " ".join(str(message or "").split()).strip()
    if not msg:
        return None
    if _looks_like_new_owner_command(msg):
        return None
    body = _re.sub(r"^(?:that\s+)?(?:it\s+)?(?:says?|saying|with)\s+", "", msg, flags=_re.IGNORECASE).strip()
    if not body:
        return {"reply": f"What should the email to {to_email} say?",
                "tier": "local", "latency_ms": 0,
                "source": "email_needs_body"}
    return _send_raw_email(to_email, body, user_rec)


def _try_sms_send(message: str, user_rec: dict) -> dict | None:
    """Send a plain outbound SMS when the tenant has Twilio configured.
    Only handles explicit phone-number recipients to avoid guessing contacts."""
    if not message:
        return None
    msg = _strip_polite_prefix(" ".join(str(message).split()))
    m = _SMS_SEND_DIRECT_RE.match(msg) or _SMS_SEND_BODY_TO_NUMBER_RE.match(msg)
    if not m:
        return None
    to_number = (m.group("to") or "").strip()
    body = (m.group("body") or "").strip()
    if not body:
        return {"reply": "What should the text say?",
                "tier": "local", "latency_ms": 0,
                "source": "sms_needs_body"}
    result = sms_sender.send(CONFIG, to_number, body)
    if result.get("ok"):
        audit.log_event(DATA_DIR, actor=user_rec.get("username", "?"),
                        action="sms.sent",
                        meta={"to": to_number, "sid_prefix": (result.get("sid") or "")[:8]})
        return {"reply": f"Text sent to {to_number}.",
                "tier": "local", "latency_ms": 0,
                "source": "sms_sent"}
    err = result.get("detail") or result.get("error") or "unknown error"
    return {"reply": f"I couldn't send that text: {err}",
            "tier": "local", "latency_ms": 0,
            "source": "sms_send_failed"}


def _owner_sms_number(user_rec: dict) -> str:
    """Return the safest known owner SMS destination, if configured."""
    for raw in (
        (user_rec or {}).get("phone"),
        ((CONFIG.get("owner") or {}).get("phone")),
        ((CONFIG.get("notifications") or {}).get("owner_sms")),
    ):
        val = str(raw or "").strip()
        if val:
            return val
    return ""


def _owner_sms_aliases(user_rec: dict) -> set[str]:
    aliases = {"me", "myself", "my cell", "my cell phone", "my phone"}
    raw_names = [
        (user_rec or {}).get("display_name"),
        ((CONFIG.get("owner") or {}).get("name")),
    ]
    try:
        biz = mod_business.load(DATA_DIR)
        raw_names.extend([
            biz.get("owner_name"),
            ((biz.get("personality") or {}).get("owner_name")),
        ])
    except Exception:
        pass
    for raw in raw_names:
        name = " ".join(str(raw or "").lower().split())
        if not name:
            continue
        aliases.add(name)
        first = name.split()[0]
        if len(first) > 1:
            aliases.add(first)
    return aliases


def _extract_recent_phone_from_history(history: list[dict]) -> str:
    if not isinstance(history, list):
        return ""
    for item in reversed(history[-8:]):
        text = str((item or {}).get("content") or "")
        phone_m = _re.search(r"(\+?1?[\s.-]?\(?\d{3}\)?[\s.-]?\d{3}[\s.-]?\d{4})", text)
        if phone_m:
            return phone_m.group(1).strip()
    return ""


def _digits_only(value: str) -> str:
    return _re.sub(r"\D+", "", str(value or ""))


def _extract_partial_sms_number_from_history(history: list[dict]) -> str:
    if not isinstance(history, list):
        return ""
    for item in reversed(history[-8:]):
        if (item or {}).get("role") != "user":
            continue
        text = " ".join(str((item or {}).get("content") or "").split())
        m = _SMS_PARTIAL_NUMBER_RE.match(_strip_polite_prefix(text))
        if not m:
            continue
        partial = (m.group("partial") or "").strip()
        digits = _digits_only(partial)
        if 5 <= len(digits) < 10:
            return partial
    return ""


def _resolve_sms_number_from_partial(partial: str, tail: str,
                                     user_rec: dict) -> str:
    combined = _digits_only(partial) + _digits_only(tail)
    if len(combined) == 10:
        return combined
    if len(combined) == 11 and combined.startswith("1"):
        return "+" + combined
    owner = _owner_sms_number(user_rec)
    owner_digits = _digits_only(owner)
    owner_local = owner_digits[-10:] if len(owner_digits) >= 10 else owner_digits
    if owner_local.startswith(_digits_only(partial)) and owner_local.endswith(_digits_only(tail)):
        return owner
    return ""


def _send_sms_reply(to_number: str, body: str, user_rec: dict,
                    source: str) -> dict:
    body = (body or "").strip()
    if body.lower() == "a test":
        body = "test"
    if body.lower() in ("for me", "for myself", "please", "for me please"):
        body = ""
    if not body:
        return {"reply": "What should the text say?",
                "tier": "local", "latency_ms": 0,
                "source": "sms_needs_body"}
    result = sms_sender.send(CONFIG, to_number, body)
    if result.get("ok"):
        audit.log_event(DATA_DIR, actor=(user_rec or {}).get("username", "?"),
                        action="sms.sent",
                        meta={"to": to_number,
                              "sid_prefix": (result.get("sid") or "")[:8],
                              "via": source})
        return {"reply": f"Text sent to {to_number}.",
                "tier": "local", "latency_ms": 0,
                "source": source}
    err = result.get("detail") or result.get("error") or "unknown error"
    return {"reply": f"I couldn't send that text: {err}",
            "tier": "local", "latency_ms": 0,
            "source": f"{source}_failed"}


def _clean_sms_who(who: str) -> str:
    who = " ".join(str(who or "").split()).strip().rstrip(".?!")
    who = _re.sub(r"^(?:my|the)\s+", "", who, flags=_re.IGNORECASE).strip()
    return who


def _resolve_sms_recipient(who: str, user_rec: dict) -> tuple[str, str]:
    """Return (phone, display_name) for owner/name/number recipients."""
    who = _clean_sms_who(who)
    if not who:
        return "", ""
    if _digits_only(who):
        digits = _digits_only(who)
        if len(digits) >= 10:
            return who, who
    if who.lower() in _owner_sms_aliases(user_rec):
        phone = _owner_sms_number(user_rec)
        return phone, "you"
    username = (user_rec or {}).get("username", "owner")
    user_dir = users_mod.get_user_dir(DATA_DIR, username)
    contact = None
    try:
        contact = mod_contacts.find_by_name(user_dir, who)
        if contact is None:
            hits = mod_contacts.search(user_dir, who)
            contact = hits[0] if hits else None
    except Exception:
        contact = None
    if contact and contact.get("phone"):
        return str(contact.get("phone") or "").strip(), contact.get("name") or who
    try:
        memory_path = user_dir / "memory.json"
        if memory_path.exists():
            mem = json.loads(memory_path.read_text(encoding="utf-8"))
            who_tokens = {t for t in _re.findall(r"[a-z0-9]+", who.lower()) if len(t) > 1}
            for tier in ("long_term", "mid_term", "short_term", "concerns"):
                for item in mem.get(tier, []) or []:
                    content = str(item.get("content") or "")
                    content_l = content.lower()
                    if not who_tokens or not all(t in content_l for t in who_tokens):
                        continue
                    # Do not borrow a phone number from nearby unrelated
                    # memory text. Require "<name> ... phone/number ... N".
                    if not _re.search(
                        r"\b" + _re.escape(who.lower()) + r"\b.{0,80}\b(?:phone|number|cell|mobile)\b",
                        content_l,
                    ):
                        continue
                    phone_m = _re.search(r"(\+?1?[\s.-]?\(?\d{3}\)?[\s.-]?\d{3}[\s.-]?\d{4})", content)
                    if phone_m:
                        return phone_m.group(1).strip(), who
    except Exception:
        pass
    return "", who


def _try_sms_to_person(message: str, user_rec: dict) -> dict | None:
    if not message:
        return None
    msg = _strip_polite_prefix(" ".join(str(message).split()))
    for rx in _SMS_SEND_TO_PERSON_PATTERNS:
        m = rx.match(msg)
        if not m:
            continue
        who = _clean_sms_who(m.group("who"))
        body = (m.group("body") or "").strip()
        if body.lower() in ("for me", "for myself", "please", "for me please"):
            body = ""
        if who.lower() in ("me", "myself", "my cell", "my cell phone", "my phone"):
            return None
        if _is_bulk_sms_target(who):
            return {"reply": (
                "I can send one text at a time right now. Who should I text, and what should it say?"
            ), "tier": "local", "latency_ms": 0,
               "source": "sms_bulk_guard"}
        phone, label = _resolve_sms_recipient(who, user_rec)
        prompt_label = _sms_prompt_label(who, label)
        if not phone:
            if body:
                return {"reply": (
                    f"I need a phone number for {prompt_label} before I can send that text. "
                    f"You can say: 'Text {body} to 7755280574.'"
                ), "tier": "local", "latency_ms": 0,
                   "source": "sms_needs_number"}
            return {"reply": (
                f"I need a phone number for {prompt_label}, and what should the text say?"
            ), "tier": "local", "latency_ms": 0,
               "source": "sms_needs_number_and_body"}
        if not body:
            return {"reply": f"What should the text to {prompt_label} say?",
                    "tier": "local", "latency_ms": 0,
                    "source": "sms_needs_body"}
        return _send_sms_reply(phone, body, user_rec, "sms_sent")
    for rx in _SMS_PERSON_NEEDS_BODY_PATTERNS:
        if _re.search(r"\babout\b", msg, _re.IGNORECASE):
            return None
        m = rx.match(msg)
        if not m:
            continue
        who = _clean_sms_who(m.group("who"))
        if who.lower() in ("me", "myself", "my cell", "my cell phone", "my phone"):
            return None
        if _is_bulk_sms_target(who):
            return {"reply": (
                "I can send one text at a time right now. Who should I text, and what should it say?"
            ), "tier": "local", "latency_ms": 0,
               "source": "sms_bulk_guard"}
        phone, label = _resolve_sms_recipient(who, user_rec)
        prompt_label = _sms_prompt_label(who, label)
        if not phone:
            return {"reply": (
                f"I need a phone number for {prompt_label} before I can send a text."
            ), "tier": "local", "latency_ms": 0,
               "source": "sms_needs_number"}
        return {"reply": f"What should the text to {prompt_label} say?",
                "tier": "local", "latency_ms": 0,
                "source": "sms_needs_body"}
    return None


def _try_sms_broad_intent(message: str, user_rec: dict) -> dict | None:
    """Catch natural SMS requests and ask for missing safe-send details.

    This intentionally does not let the LLM improvise SMS actions. If the
    owner says "send a text" in any normal phrasing, Orbi must either send
    through the deterministic SMS path or ask what is missing.
    """
    if not message:
        return None
    msg = _strip_polite_prefix(" ".join(str(message).split()))
    if not _SMS_BROAD_INTENT_RE.search(msg):
        return None
    lower = msg.lower()
    if any(x in lower for x in ("show my texts", "list my texts", "show me texts",
                                "text every", "text all", "every lead", "all leads",
                                "everyone", "everybody")):
        return {"reply": (
            "I can send one text at a time right now. Who should I text, and what should it say?"
        ), "tier": "local", "latency_ms": 0,
           "source": "sms_needs_recipient_or_body"}

    who = ""
    m_named = _re.search(
        r"\bsend\s+(?P<who>[A-Z][A-Za-z .'\-]{1,40}?)\s+"
        r"(?:a\s+)?(?:text|sms|message)\b",
        msg,
    )
    if m_named:
        who = _clean_sms_who(m_named.group("who"))
    m_who = _SMS_BROAD_RECIPIENT_RE.search(msg)
    if not who and m_who:
        who = _clean_sms_who(m_who.group("who"))
        if who.lower() in ("me", "myself") and _re.search(r"\bfor\s+(?:me|myself)\b", msg, _re.IGNORECASE):
            who = ""
    elif not who and _re.search(r"\b(?:me|myself|my cell|my phone)\b", msg, _re.IGNORECASE):
        who = "me"

    body = ""
    m_body = _SMS_BROAD_BODY_RE.search(msg)
    if m_body:
        body = (m_body.group("body") or "").strip()

    m_about = _SMS_BROAD_ABOUT_RE.search(msg)
    topic = (m_about.group("topic").strip() if m_about else "")

    if not who and not body:
        return {"reply": "Who should I text, and what should it say?",
                "tier": "local", "latency_ms": 0,
                "source": "sms_needs_recipient_or_body"}
    if not who:
        return {"reply": f"Who should I text this to: \"{body}\"?",
                "tier": "local", "latency_ms": 0,
                "source": "sms_needs_recipient"}
    phone, label = _resolve_sms_recipient(who, user_rec)
    prompt_label = _sms_prompt_label(who, label)
    if not phone:
        if topic:
            return {"reply": f"What phone number should I use for {who}, and what exactly should I say about {topic}?",
                    "tier": "local", "latency_ms": 0,
                    "source": "sms_needs_number_and_body"}
        return {"reply": f"What phone number should I use for {who}?",
                "tier": "local", "latency_ms": 0,
                "source": "sms_needs_number"}
    if body:
        return _send_sms_reply(phone, body, user_rec, "sms_sent")
    if topic:
        return {"reply": f"What exactly should I say to {prompt_label} about {topic}?",
                "tier": "local", "latency_ms": 0,
                "source": "sms_needs_body"}
    return {"reply": f"What should the text to {prompt_label} say?",
            "tier": "local", "latency_ms": 0,
            "source": "sms_needs_body"}


def _try_sms_to_me_or_that_one(message: str, user_rec: dict,
                               history: list[dict]) -> dict | None:
    if not message:
        return None
    msg = _strip_polite_prefix(" ".join(str(message).split()))
    m = _SMS_SEND_TO_ME_RE.match(msg)
    if m:
        to_number = _owner_sms_number(user_rec)
        if not to_number:
            return {"reply": (
                "What phone number should I text? "
                "You can say: 'Text test to 7755280574.'"
            ), "tier": "local", "latency_ms": 0,
               "source": "sms_needs_number"}
        return _send_sms_reply(to_number, m.group("body"), user_rec, "sms_sent")
    if _SMS_SEND_TO_ME_NEEDS_BODY_RE.match(msg):
        return {"reply": "What should the text say?",
                "tier": "local", "latency_ms": 0,
                "source": "sms_needs_body"}
    m = _SMS_SEND_TO_THAT_ONE_RE.match(msg)
    if m:
        to_number = _extract_recent_phone_from_history(history) or _owner_sms_number(user_rec)
        if not to_number:
            return {"reply": (
                "Which number should I text? "
                "You can say: 'Text test to 7755280574.'"
            ), "tier": "local", "latency_ms": 0,
               "source": "sms_needs_number"}
        return _send_sms_reply(to_number, m.group("body"), user_rec, "sms_sent")
    m = _SMS_CONTINUE_PARTIAL_NUMBER_RE.match(msg)
    if m:
        partial = _extract_partial_sms_number_from_history(history)
        to_number = _resolve_sms_number_from_partial(partial, m.group("tail"), user_rec)
        if not to_number:
            return {"reply": (
                "I did not get the full phone number. Please send it in one message, "
                "like: 'Text test to 7755280574.'"
            ), "tier": "local", "latency_ms": 0,
               "source": "sms_needs_full_number"}
        return _send_sms_reply(to_number, m.group("body"), user_rec, "sms_sent")
    return None


def _extract_pending_sms_from_history(history: list[dict]) -> tuple[str, str] | None:
    """Find the most recent assistant SMS draft in chat history.

    This supports natural follow-ups like "yes send that" after Orbi says:
    `I'll send a text to Kathy at 775-622-5299. Here it is: "Hi Kathy..."`.
    It deliberately requires both a phone number and quoted message body.
    """
    if not isinstance(history, list):
        return None
    for item in reversed(history[-8:]):
        if (item or {}).get("role") != "assistant":
            continue
        text = str((item or {}).get("content") or "")
        if not _re.search(r"\b(?:text|sms|message)\b", text, _re.IGNORECASE):
            continue
        phone_m = _re.search(r"(\+?1?[\s.-]?\(?\d{3}\)?[\s.-]?\d{3}[\s.-]?\d{4})", text)
        if not phone_m:
            continue
        # Prefer curly/straight quoted drafts. Use the last quoted block so
        # explanatory text before it does not become the outgoing SMS.
        quoted = _re.findall(r"[\"“](.{4,500}?)[\"”]", text, flags=_re.DOTALL)
        if not quoted:
            quoted = _re.findall(r"'(.{4,500}?)'", text, flags=_re.DOTALL)
        if not quoted:
            continue
        body = " ".join(str(quoted[-1]).split()).strip()
        if not body:
            continue
        return phone_m.group(1).strip(), body
    return None


def _extract_pending_sms_clarification(history: list[dict]) -> dict | None:
    """Read the latest assistant SMS clarification question.

    Supports follow-ups where the owner does not repeat "text", e.g.
    Orbi: "What phone number should I use for James, and what exactly
    should I say about our fishing trip?"
    Owner: "775-555-1212 and tell him I got the boat ready"
    """
    if not isinstance(history, list):
        return None
    for item in reversed(history[-8:]):
        if (item or {}).get("role") != "assistant":
            continue
        text = " ".join(str((item or {}).get("content") or "").split())
        text_l = text.lower()
        if ("text sent to " in text_l
                or "couldn't send that text" in text_l
                or "what should the email to " in text_l
                or "email sent to " in text_l
                or "scheduled meeting with" in text_l):
            return None
        if not any(marker in text_l for marker in (
            "who should i text", "what should the text", "what phone number should i use",
            "what phone number should i text", "what exactly should i say",
            "which number should i text",
        )):
            return None
        pending = {"who": "", "topic": "", "needs_phone": False, "needs_body": False}
        m = _re.search(r"phone number should i use for ([^,?]+)", text, _re.IGNORECASE)
        if m:
            pending["who"] = _clean_sms_who(m.group(1))
            pending["needs_phone"] = True
        m = _re.search(r"text to ([^?]+?) say", text, _re.IGNORECASE)
        if m:
            pending["who"] = _clean_sms_who(m.group(1))
            pending["needs_body"] = True
        m = _re.search(r"say to ([^?]+?) about", text, _re.IGNORECASE)
        if m:
            pending["who"] = _clean_sms_who(m.group(1))
            pending["needs_body"] = True
        m = _re.search(r"say about ([^?]+)", text, _re.IGNORECASE)
        if m:
            pending["topic"] = m.group(1).strip()
            pending["needs_body"] = True
        if "who should i text" in text_l:
            pending["needs_phone"] = True
            pending["needs_body"] = True
        if "what should the text" in text_l or "what exactly should i say" in text_l:
            pending["needs_body"] = True
        if "what phone number" in text_l or "which number" in text_l:
            pending["needs_phone"] = True
        return pending
    return None


def _extract_sms_body_from_followup(msg: str) -> str:
    msg = (msg or "").strip()
    m = _re.search(
        r"\b(?:tell|saying|say|message|text)\s+(?:him|her|them|it|that)?\s*(?:to\s+)?(?P<body>.+)$",
        msg, _re.IGNORECASE | _re.DOTALL,
    )
    if m:
        return (m.group("body") or "").strip().strip('"')
    # "775-555-1212 and I will be there at 6"
    msg = _re.sub(r"^\+?1?[\s.-]?\(?\d{3}\)?[\s.-]?\d{3}[\s.-]?\d{4}\s*(?:and|,)?\s*", "", msg).strip()
    return msg.strip('"')


def _is_new_sms_request(message: str) -> bool:
    """True when the current message is a fresh SMS command.

    This prevents an old clarification like "What phone number should I use
    for James?" from stealing a new command such as "Text Kathy..." or
    "Send a text to Bob".
    """
    msg = _strip_polite_prefix(" ".join(str(message or "").split()))
    if not msg:
        return False
    explicit_patterns = [
        _SMS_SEND_TO_ME_RE,
        _SMS_SEND_TO_ME_NEEDS_BODY_RE,
        _SMS_SEND_DIRECT_RE,
        _SMS_SEND_BODY_TO_NUMBER_RE,
        _SMS_NEEDS_NUMBER_RE,
    ]
    if any(rx.match(msg) for rx in explicit_patterns):
        return True
    if any(rx.match(msg) for rx in _SMS_SEND_TO_PERSON_PATTERNS):
        return True
    if any(rx.match(msg) for rx in _SMS_PERSON_NEEDS_BODY_PATTERNS):
        return True
    return False


def _try_sms_clarification_followup(message: str, user_rec: dict,
                                    history: list[dict]) -> dict | None:
    if _is_new_sms_request(message):
        return None
    pending = _extract_pending_sms_clarification(history)
    if not pending:
        return None
    msg = " ".join(str(message or "").split()).strip()
    if not msg:
        return None

    phone_m = _re.search(r"(\+?1?[\s.-]?\(?\d{3}\)?[\s.-]?\d{3}[\s.-]?\d{4})", msg)
    to_number = phone_m.group(1).strip() if phone_m else ""
    has_sms_followup_cue = bool(
        phone_m
        or _re.search(r"\b(?:tell|say|saying|text|message|sms|phone|number)\b", msg, _re.IGNORECASE)
        or _re.match(r"^\s*[A-Za-z][A-Za-z .'\-]{1,40}\s*,", msg)
    )

    if pending.get("needs_phone") and not to_number and not has_sms_followup_cue:
        return None
    if not pending.get("needs_phone") and pending.get("needs_body"):
        # Body-only follow-ups can be plain speech, but not obvious small talk
        # or questions unrelated to the pending text.
        if (_re.search(r"\?$", msg)
                or _looks_like_new_owner_command(msg)
                or _re.search(r"\b(?:my\s+name\s+is|my\s+phone\s+is|my\s+email\s+is)\b", msg, _re.IGNORECASE)
                or _re.match(r"^(?:hello|hi|hey|babe)\b", msg, _re.IGNORECASE)):
            return None

    who = pending.get("who") or ""
    if not who:
        m_to = _re.search(r"^(?:to\s+)?(?P<who>[A-Za-z][A-Za-z .'\-]{0,40}?)(?:,|\s+(?:tell|say|saying|that|with)\b)", msg, _re.IGNORECASE)
        if m_to:
            who = _clean_sms_who(m_to.group("who"))
    if not to_number and who:
        to_number, label = _resolve_sms_recipient(who, user_rec)
    else:
        label = who or to_number

    body = _extract_sms_body_from_followup(msg)
    if phone_m:
        body = _extract_sms_body_from_followup(msg.replace(phone_m.group(1), "", 1))
    if body.lower() in ("yes", "yeah", "yep", "ok", "okay", "sure"):
        body = ""

    if not to_number and not who:
        return {"reply": "Who should I text, and what should it say?",
                "tier": "local", "latency_ms": 0,
                "source": "sms_needs_recipient_or_body"}
    if not to_number:
        if pending.get("topic"):
            return {"reply": f"What phone number should I use for {who}, and what exactly should I say about {pending['topic']}?",
                    "tier": "local", "latency_ms": 0,
                    "source": "sms_needs_number_and_body"}
        return {"reply": f"What phone number should I use for {who}?",
                "tier": "local", "latency_ms": 0,
                "source": "sms_needs_number"}
    if not body:
        if pending.get("topic"):
            return {"reply": f"What exactly should I say to {label} about {pending['topic']}?",
                    "tier": "local", "latency_ms": 0,
                    "source": "sms_needs_body"}
        return {"reply": f"What should the text to {label} say?",
                "tier": "local", "latency_ms": 0,
                "source": "sms_needs_body"}
    return _send_sms_reply(to_number, body, user_rec, "sms_sent")


def _try_sms_pending_confirmation(message: str, user_rec: dict,
                                  history: list[dict]) -> dict | None:
    if not message:
        return None
    msg = _strip_polite_prefix(" ".join(str(message).split()))
    if not _SMS_CONFIRM_SEND_RE.match(msg):
        return None
    pending = _extract_pending_sms_from_history(history)
    if not pending:
        return None
    to_number, body = pending
    result = sms_sender.send(CONFIG, to_number, body)
    if result.get("ok"):
        audit.log_event(DATA_DIR, actor=user_rec.get("username", "?"),
                        action="sms.sent",
                        meta={"to": to_number,
                              "sid_prefix": (result.get("sid") or "")[:8],
                              "via": "pending_sms_confirmation"})
        return {"reply": f"Text sent to {to_number}.",
                "tier": "local", "latency_ms": 0,
                "source": "sms_pending_sent"}
    err = result.get("detail") or result.get("error") or "unknown error"
    return {"reply": f"I couldn't send that text: {err}",
            "tier": "local", "latency_ms": 0,
            "source": "sms_pending_send_failed"}


def _try_sms_needs_number(message: str, user_rec: dict) -> dict | None:
    if not message:
        return None
    msg = _strip_polite_prefix(" ".join(str(message).split()))
    m = _SMS_NEEDS_NUMBER_RE.match(msg)
    if not m:
        return None
    who = (m.group("who") or "").strip().rstrip(".?!")
    if who.lower() in ("every", "everyone", "everybody", "lead", "leads", "every lead", "all leads"):
        return None
    return {"reply": (
        f"What phone number should I text for {who}? "
        f"You can say: 'Send a text to 7755280574 saying ...'"
    ), "tier": "local", "latency_ms": 0,
       "source": "sms_needs_number"}


def _try_unwired_channel(message: str, user_rec: dict) -> dict | None:
    """Email/SMS/file queries we don't have wired to a real backend.
    Return an honest deterministic refusal so the LLM can't fabricate
    'here are 3 emails from Johnson'."""
    if not message:
        return None
    msg = _strip_polite_prefix(message)
    if _UNWIRED_EMAIL_RE.match(msg):
        return {"reply": (
            "I don't have your email account wired up yet, so I can't pull "
            "messages or send drafts on your behalf.\n"
            "Workarounds that DO work right now:\n"
            "  · I can generate an invoice or change-order PDF — you forward "
            "it from your own email.\n"
            "  · I can draft the WORDS for a reply — say \"draft a reminder "
            "to Johnson Construction\" and I'll write the message text."
        ), "tier": "local", "latency_ms": 0,
           "source": "unwired_email"}
    if _UNWIRED_SMS_RE.match(msg):
        return {"reply": (
            "I can send texts, but I need both a recipient and the exact message. "
            "Try: 'Text test to 7755280574' or 'Send Kathy a text saying I am running late.'"
        ), "tier": "local", "latency_ms": 0,
           "source": "sms_needs_recipient_or_body"}
    if _UNWIRED_FILES_RE.match(msg):
        # Workspace search IS wired — mod_workspace indexes ~/Orby/ files
        # (PDFs, DOCX, TXT, CSV) and supports keyword search. Extract the
        # query from the user's phrasing and hit workspace.search() instead
        # of returning the stale "I don't have file search" refusal.
        query = msg.strip().rstrip(".?!")
        for prefix in ("find the file about ", "find the file ",
                       "find files about ", "find files ",
                       "search files for ", "search my files for ",
                       "search files about ", "what files do i have ",
                       "what's in my orbi folder", "what's in my folder",
                       "show me files about ", "show me my files",
                       "look for ", "locate "):
            if query.lower().startswith(prefix):
                query = query[len(prefix):].strip()
                break
        try:
            hits = mod_workspace.search(CONFIG, DATA_DIR, query, limit=8) if query else []
        except Exception as e:
            log.warning(f"workspace.search failed: {e}")
            hits = []
        if hits:
            lines = [f"Found {len(hits)} file(s) matching \"{query}\":"]
            for h in hits[:8]:
                fn = h.get("filename") or h.get("path","").split("/")[-1]
                snippet = (h.get("snippet") or h.get("chunk") or "")[:140].strip()
                lines.append(f"  · {fn}")
                if snippet:
                    lines.append(f"      …{snippet}…")
            return {"reply": "\n".join(lines), "tier": "local",
                    "latency_ms": 0, "source": "workspace_search"}
        # Empty query OR no matches → list folder contents
        try:
            ws_path = mod_workspace.workspace_path(CONFIG)
            if ws_path.exists():
                files = sorted(p.name for p in ws_path.iterdir()
                               if p.is_file() and not p.name.startswith("."))
                if files:
                    lines = [f"Files in `{ws_path}`:"]
                    for f in files[:25]:
                        lines.append(f"  · {f}")
                    if len(files) > 25:
                        lines.append(f"  …and {len(files) - 25} more")
                    return {"reply": "\n".join(lines), "tier": "local",
                            "latency_ms": 0, "source": "workspace_list"}
                return {"reply": f"Your Orby folder (`{ws_path}`) is empty — "
                        f"drop documents in it and ask me to find them.",
                        "tier": "local", "latency_ms": 0,
                        "source": "workspace_empty"}
        except Exception:
            pass
        return {"reply": f"No files matching \"{query}\" in your Orby folder.",
                "tier": "local", "latency_ms": 0,
                "source": "workspace_no_match"}
    return None


# ── Knowledge-question handlers (read business_info directly) ─────────────

_KNOW_SERVICES_RE = _re.compile(
    r"^\s*(?:"
    r"what\s+services?\s+(?:do\s+(?:you|we|i)\s+)?(?:offer|provide|sell)"
    r"|what\s+(?:do|does)\s+(?:you|we|orby|the\s+company)\s+(?:offer|provide|do|sell)"
    r"|services?(?:\s+offered|\s+available)?"
    r"|(?:show|list)\s+(?:me\s+)?(?:your|our|my)\s+services?"
    r"|what\s+kind\s+of\s+(?:work|services?)\s+(?:do\s+you\s+do|do\s+we\s+do)"
    r")\s*[?.!]?\s*$",
    _re.IGNORECASE,
)
_KNOW_DISTANCE_RE = _re.compile(
    r"^\s*(?:"
    r"how\s+far\s+(?:is\s+it\s+)?(?:from\s+(?P<from>[^?!]{5,80})\s+to\s+(?P<to>[^?!]{5,80})"
    r"|to\s+(?P<to2>[^?!]{5,80})(?:\s+from\s+(?P<from2>[^?!]{5,80}))?)"
    r"|(?:how\s+long|what(?:'s|\s+is)\s+the\s+(?:drive|trip|commute))\s+(?:does\s+it\s+take\s+)?(?:from\s+(?P<from3>[^?!]{5,80})\s+to\s+(?P<to3>[^?!]{5,80})|to\s+(?P<to4>[^?!]{5,80}))"
    r"|(?:drive|driving|travel)\s+(?:time|distance)\s+(?:from\s+(?P<from4>[^?!]{5,80})\s+to\s+(?P<to5>[^?!]{5,80})|to\s+(?P<to6>[^?!]{5,80}))"
    r"|distance\s+(?:from\s+(?P<from5>[^?!]{5,80})\s+to\s+(?P<to7>[^?!]{5,80})|between\s+(?P<a>[^?!]{5,80})\s+and\s+(?P<b>[^?!]{5,80}))"
    r"|get\s+directions?\s+(?:to|from)\s+(?P<dir_addr>[^?!]{5,120})"
    r")\s*[?.!]?\s*$",
    _re.IGNORECASE,
)
_KNOW_SERVICE_AREA_RE = _re.compile(
    r"^\s*(?:"
    r"what(?:'s| is)?\s+(?:our|your|my|the)\s+service\s+area"
    r"|service\s+area"
    r"|where\s+(?:do\s+(?:you|we)\s+)?(?:work|serve|operate|cover)"
    r"|do\s+you\s+(?:work|serve|cover|do\s+jobs)\s+in\s+(?P<city>[A-Za-z][A-Za-z\s,]+?)"
    r"|do\s+(?:you|we)\s+(?:do|serve)\s+work\s+in\s+(?P<city2>[A-Za-z][A-Za-z\s,]+?)"
    r"|are\s+you\s+in\s+(?P<city3>[A-Za-z][A-Za-z\s,]+?)"
    r"|(?:what\s+(?:cities|towns|areas))\s+(?:do\s+(?:you|we)\s+)?(?:work\s+in|serve|cover)"
    r")\s*[?.!]?\s*$",
    _re.IGNORECASE,
)
_KNOW_HOURS_RE = _re.compile(
    r"^\s*(?:"
    r"what(?:'s| are)?\s+(?:our|your|my|the)\s+(?:business\s+)?hours"
    r"|(?:business\s+|store\s+|shop\s+|office\s+)?hours"
    r"|when\s+(?:are|do)\s+(?:you|we)\s+(?:open|close|operate)"
    r"|what\s+time\s+do\s+(?:you|we)\s+(?:open|close)"
    r"|(?:are|is)\s+(?:you|we)\s+open(?:\s+(?:now|today))?"
    r")\s*[?.!]?\s*$",
    _re.IGNORECASE,
)
_KNOW_LICENSE_RE = _re.compile(
    r"^\s*(?:"
    r"what(?:'s| is)?\s+(?:our|your|my|the)\s+(?:contractor\s+|business\s+|state\s+)?license(?:\s+number|\s+#|\s+no)?"
    r"|(?:contractor\s+|business\s+)?license\s+number"
    r"|(?:contractor\s+|business\s+)?license\s+#"
    r"|what(?:'s| is)?\s+(?:our|your|my)\s+license"
    r"|license"
    r")\s*[?.!]?\s*$",
    _re.IGNORECASE,
)
_KNOW_INSURANCE_RE = _re.compile(
    r"^\s*(?:"
    r"(?:are|is)\s+(?:you|we|the\s+company)\s+(?:licensed\s+and\s+)?insured"
    r"|(?:are|is)\s+(?:you|we)\s+licensed\s+and\s+insured"
    r"|do\s+(?:you|we)\s+(?:have|carry)\s+insurance"
    r"|what(?:'s| is)?\s+(?:our|your|my|the)\s+insurance"
    r"|insurance\s+(?:status|info|details)"
    r"|(?:are|is)\s+(?:you|we)\s+bonded"
    r")\s*[?.!]?\s*$",
    _re.IGNORECASE,
)
_KNOW_WARRANTY_RE = _re.compile(
    r"^\s*(?:"
    r"what(?:'s| is)?\s+(?:our|your|my|the)\s+warranty"
    r"|what\s+warranty\s+(?:do\s+(?:you|we)\s+)?(?:provide|offer|give|have)"
    r"|do\s+(?:you|we)\s+(?:offer|provide|give|have)\s+(?:a\s+)?warranty"
    r"|warranty(?:\s+(?:policy|info|details|coverage))?"
    r"|how\s+long\s+is\s+(?:the\s+|your\s+)?warranty"
    r")\s*[?.!]?\s*$",
    _re.IGNORECASE,
)
_KNOW_FINANCING_RE = _re.compile(
    r"^\s*(?:"
    r"what\s+financing\s+(?:options\s+)?(?:do\s+(?:you|we)\s+)?(?:offer|have|provide)"
    r"|do\s+(?:you|we)\s+(?:offer|have|provide)\s+(?:any\s+)?financing"
    r"|financing\s+(?:options|available|info)"
    r"|(?:are\s+there\s+|any\s+)?financing\s+options"
    r"|payment\s+plans?"
    r"|do\s+(?:you|we)\s+(?:offer|do)\s+payment\s+plans?"
    r")\s*[?.!]?\s*$",
    _re.IGNORECASE,
)


def _fmt_hours_block(hours: dict) -> str | None:
    """Format the business_info hours dict as a clean weekly schedule."""
    if not hours:
        return None
    day_order = ["monday", "tuesday", "wednesday", "thursday",
                 "friday", "saturday", "sunday"]
    lines = []
    for d in day_order:
        h = hours.get(d) or {}
        label = d.capitalize()
        if h.get("closed"):
            lines.append(f"  {label}:    Closed")
        elif h.get("open") and h.get("close"):
            lines.append(f"  {label}:    {h['open']} – {h['close']}")
    return "\n".join(lines) if lines else None


def _fmt_service_list(services) -> list[str]:
    """Normalize services (list of strings OR list of dicts) to a list
    of display lines."""
    out = []
    for s in (services or []):
        if isinstance(s, str):
            name = s.strip()
            if name:
                out.append(f"  · {name}")
        elif isinstance(s, dict):
            name = (s.get("name") or "").strip()
            price = (s.get("price") or "").strip()
            if name:
                if price:
                    out.append(f"  · {name} — {price}")
                else:
                    out.append(f"  · {name}")
    return out


def _try_knowledge_chat(message: str, user_rec: dict) -> dict | None:
    """Answer the business-profile knowledge questions from business_info
    directly. Deterministic, fast, accurate."""
    if not message:
        return None
    msg = _strip_polite_prefix(message)
    biz = mod_business.load(DATA_DIR)
    name = biz.get("name") or "the business"
    policies = biz.get("policies") or {}

    # SERVICES — "what services do you offer"
    if _KNOW_SERVICES_RE.match(msg):
        service_lines = _fmt_service_list(biz.get("services"))
        if not service_lines:
            return {"reply": (
                f"I don't have services listed in {name}'s profile yet. "
                f"Add them in Settings → Business → Services and I'll start "
                f"reading them back."
            ), "tier": "local", "latency_ms": 0,
               "source": "know_services_empty"}
        header = f"Services {name} offers:"
        return {"reply": header + "\n" + "\n".join(service_lines),
                "tier": "local", "latency_ms": 0,
                "source": "know_services"}

    # SERVICE AREA — "what's our service area" / "do you work in Reno"
    m = _KNOW_SERVICE_AREA_RE.match(msg)
    if m:
        area = (policies.get("service_area") or "").strip()
        city_q = (m.group("city") or m.group("city2") or m.group("city3") or "").strip().rstrip("?.!")
        addr = biz.get("address") or {}
        addr_city = (addr.get("city") or "").strip()
        if city_q:
            haystack = (area + " " + addr_city).lower()
            if city_q.lower() in haystack:
                return {"reply": f"Yes — {name} works in {city_q}."
                                  + (f"\nFull service area: {area}." if area else ""),
                        "tier": "local", "latency_ms": 0,
                        "source": "know_service_area_yes"}
            if area:
                return {"reply": f"Our service area is: {area}.\n"
                                  f"{city_q} isn't on that list — call/text the "
                                  f"office to ask about a trip-fee job.",
                        "tier": "local", "latency_ms": 0,
                        "source": "know_service_area_outside"}
            # Fall through to the generic answer below
        if area:
            return {"reply": f"Service area for {name}: {area}.",
                    "tier": "local", "latency_ms": 0,
                    "source": "know_service_area"}
        if addr_city:
            return {"reply": (
                f"{name} is based in {addr_city}"
                + (f", {addr.get('state')}" if addr.get('state') else "")
                + ". A specific service area isn't set in the profile yet — "
                f"add it under Settings → Business → Policies and I'll quote it."
            ), "tier": "local", "latency_ms": 0,
               "source": "know_service_area_partial"}
        return {"reply": (
            f"I don't have a service area in the profile for {name} yet. "
            f"Add it in Settings → Business → Policies → Service area."
        ), "tier": "local", "latency_ms": 0,
           "source": "know_service_area_empty"}

    # DISTANCE / DIRECTIONS — "how far is 456 Main St from us"
    m = _KNOW_DISTANCE_RE.match(msg)
    if m:
        g = m.groupdict()
        # Pull origin + destination from whichever named groups matched
        origin = (g.get("from") or g.get("from2") or g.get("from3") or
                  g.get("from4") or g.get("from5") or g.get("a") or "").strip().rstrip("?.!")
        dest   = (g.get("to") or g.get("to2") or g.get("to3") or g.get("to4") or
                  g.get("to5") or g.get("to6") or g.get("to7") or
                  g.get("b") or g.get("dir_addr") or "").strip().rstrip("?.!")
        # Default origin to business address when not specified
        if not origin:
            addr_block = biz.get("address") or {}
            origin = ", ".join(filter(None, [
                addr_block.get("street", ""), addr_block.get("city", ""),
                addr_block.get("state", ""), addr_block.get("zip", ""),
            ]))
        if dest:
            cache_dir = DATA_DIR / "geocode_cache"
            reply = mod_maps.distance_reply(origin, dest, cache_dir=cache_dir)
            return {"reply": reply, "tier": "local", "latency_ms": 0,
                    "source": "know_distance"}

    # HOURS — "what are our business hours"
    if _KNOW_HOURS_RE.match(msg):
        block = _fmt_hours_block(biz.get("hours") or {})
        if not block:
            return {"reply": (
                f"I don't have business hours in {name}'s profile yet. "
                f"Set them in Settings → Business → Hours."
            ), "tier": "local", "latency_ms": 0,
               "source": "know_hours_empty"}
        try:
            today_str = mod_business.hours_today(DATA_DIR) or ""
        except Exception:
            today_str = ""
        tail = f"\nToday: {today_str}" if today_str else ""
        return {"reply": f"Business hours for {name}:\n{block}{tail}",
                "tier": "local", "latency_ms": 0,
                "source": "know_hours"}

    # LICENSE — "what's our contractor license number"
    if _KNOW_LICENSE_RE.match(msg):
        lic = (biz.get("license") or "").strip()
        if lic:
            return {"reply": f"{name} contractor license: {lic}.",
                    "tier": "local", "latency_ms": 0,
                    "source": "know_license"}
        return {"reply": (
            f"I don't have a license number in {name}'s profile. If you "
            f"have one (NV-GC-#####), set it in Settings → Business → "
            f"License and I'll quote it on every invoice and proposal."
        ), "tier": "local", "latency_ms": 0,
           "source": "know_license_empty"}

    # INSURANCE — "are you licensed and insured"
    if _KNOW_INSURANCE_RE.match(msg):
        lic = (biz.get("license") or "").strip()
        insurance_text = ""
        for key in ("insurance", "insured", "bonding", "bonded"):
            v = policies.get(key)
            if v:
                insurance_text = str(v).strip()
                break
        if lic or insurance_text:
            bits = []
            if lic:
                bits.append(f"licensed (#{lic})")
            else:
                bits.append("licensed")
            if insurance_text:
                bits.append(insurance_text.lower() if insurance_text.lower().startswith(("bond", "insur", "general")) else "insured")
            else:
                bits.append("insured")
            return {"reply": f"Yes — {name} is " + " and ".join(bits) + ".",
                    "tier": "local", "latency_ms": 0,
                    "source": "know_insurance"}
        return {"reply": (
            f"I don't have license or insurance details in {name}'s profile "
            f"yet. Add them in Settings → Business so customers get a "
            f"straight answer when they ask."
        ), "tier": "local", "latency_ms": 0,
           "source": "know_insurance_empty"}

    # WARRANTY — "what warranty do we provide"
    if _KNOW_WARRANTY_RE.match(msg):
        warranty = (policies.get("warranty") or "").strip()
        if warranty:
            return {"reply": f"Warranty: {warranty}",
                    "tier": "local", "latency_ms": 0,
                    "source": "know_warranty"}
        return {"reply": (
            f"I don't have a warranty policy in {name}'s profile yet. Add "
            f"it in Settings → Business → Policies → Warranty."
        ), "tier": "local", "latency_ms": 0,
           "source": "know_warranty_empty"}

    # FINANCING — "what financing do we offer"
    if _KNOW_FINANCING_RE.match(msg):
        # Check several reasonable key names
        for key in ("financing", "payment_plans", "payment_options",
                    "financing_options"):
            v = policies.get(key)
            if v:
                return {"reply": f"Financing for {name}: {v}",
                        "tier": "local", "latency_ms": 0,
                        "source": "know_financing"}
        # Check payment_methods as a fallback hint
        pm = (policies.get("payment_methods") or "").strip()
        if pm:
            return {"reply": (
                f"{name} doesn't have a dedicated financing option on file. "
                f"What we DO accept: {pm}\n"
                f"If you want to offer financing (Affirm/Wisetack/Sunlight), "
                f"add it in Settings → Business → Policies → Financing."
            ), "tier": "local", "latency_ms": 0,
               "source": "know_financing_partial"}
        return {"reply": (
            f"No financing options listed for {name}. Add them in Settings → "
            f"Business → Policies → Financing."
        ), "tier": "local", "latency_ms": 0,
           "source": "know_financing_empty"}
    return None


# ── Self-introspection (what modules am I running) ────────────────────────

# Friendly per-module descriptions so the answer reads like a brochure,
# not a JSON dump. Add entries here when new add-on modules ship.
_MODULE_INTRO_DESCRIPTIONS = {
    "contractor": (
        "Contractor — general-contractor module. Tracks projects, change "
        "orders (with foreman-on-site customer signing), invoices + "
        "retainage, subcontractors + insurance expiry, daily logs with "
        "leak-alarm scope-change detection, bids + proposal PDFs, customer "
        "review collection, and a per-project customer portal."
    ),
    # Future modules — copy this template for medical/legal/etc.
    # "medical": ("Medical — ..."),
    # "legal":   ("Legal — ..."),
}

# Map natural-language module-name variants to the canonical key in
# CONFIG.enabled_modules. Add aliases here as new modules ship.
_MODULE_ALIASES = {
    "contractor":          "contractor",
    "construction":        "contractor",
    "builder":             "contractor",
    "building":            "contractor",
    "gc":                  "contractor",
    "general contractor":  "contractor",
    "general-contractor":  "contractor",
    "remodel":             "contractor",
    "remodeling":          "contractor",
    "home builder":        "contractor",
    "home-builder":        "contractor",
    "medical":             "medical",
    "doctor":              "medical",
    "clinic":              "medical",
    "healthcare":          "medical",
    "legal":               "legal",
    "lawyer":              "legal",
    "law":                 "legal",
    "attorney":            "legal",
    "restaurant":          "restaurant",
    "deli":                "restaurant",
    "automotive":          "automotive",
    "auto":                "automotive",
    "shop":                "automotive",
}
_MODULE_ALIAS_PATTERN = "|".join(_re.escape(a) for a in sorted(
    _MODULE_ALIASES.keys(), key=len, reverse=True))

_MODULES_INTRO_RE = _re.compile(
    r"^\s*(?:"
    r"(?:do\s+(?:you|i)\s+have|do\s+you\s+know\s+anything\s+about|is\s+(?:there|the)|do\s+i\s+(?:have\s+)?the)\s+(?:a\s+|an\s+|the\s+)?"
    r"(?P<mod_q>" + _MODULE_ALIAS_PATTERN + r")\s*(?:module|add[\s-]?on|plan|package|feature|attached)?"
    r"|what\s+(?:modules?|add[\s-]?ons?|plans?|features?|packages?)\s+(?:do\s+i\s+have(?:\s+(?:enabled|active|installed))?|am\s+i\s+(?:on|using|subscribed\s+to)|are\s+(?:enabled|installed|active))"
    r"|which\s+(?:modules?|add[\s-]?ons?|plans?|features?)\s+(?:do\s+i\s+have(?:\s+(?:enabled|active|installed))?|am\s+i\s+(?:on|using))"
    r"|(?:show|list|tell\s+me)\s+(?:me\s+)?(?:my\s+)?(?:enabled\s+|active\s+|installed\s+)?(?:modules?|add[\s-]?ons?|features?)"
    r"|am\s+i\s+(?:on|subscribed\s+to|using)\s+(?:the\s+)?(?P<mod_q2>" + _MODULE_ALIAS_PATTERN + r")\s*(?:module|add[\s-]?on|plan|package)?"
    r"|what'?s\s+(?:my\s+)?(?:subscription|plan)"
    r")\s*[?.!]?\s*$",
    _re.IGNORECASE,
)


def _try_modules_introspection(message: str, user_rec: dict) -> dict | None:
    """Answer 'do you have a contractor module' / 'what modules am I on'
    truthfully from CONFIG.enabled_modules. Beats the LLM, which
    confidently makes up the wrong answer (e.g. claims contractor isn't
    enabled when it actually is)."""
    if not message:
        return None
    msg = _strip_polite_prefix(message)
    m = _MODULES_INTRO_RE.match(msg)
    if not m:
        return None
    enabled = list((CONFIG.get("enabled_modules") or []))

    # Specific module asked about — map the alias to the canonical key,
    # then check if it's in CONFIG.enabled_modules.
    mod_q_raw = (m.group("mod_q") or m.group("mod_q2") or "").strip().lower()
    if mod_q_raw:
        canonical = _MODULE_ALIASES.get(mod_q_raw, mod_q_raw)
        on = canonical in [str(x).lower() for x in enabled]
        if on:
            desc = _MODULE_INTRO_DESCRIPTIONS.get(canonical, f"The {canonical} module is active.")
            # If the user said "construction" but we call it "contractor",
            # acknowledge their phrasing while using the canonical name.
            alias_note = ""
            if mod_q_raw != canonical:
                alias_note = f" (we call it the {canonical} module internally)"
            return {"reply": f"Yes — the {canonical} module is enabled{alias_note}.\n\n{desc}",
                    "tier": "local", "latency_ms": 0,
                    "source": "modules_intro_yes"}
        else:
            avail = ", ".join(enabled) if enabled else "(none beyond base Orby)"
            return {"reply": (
                f"No — the {canonical} module is not enabled on this Orby.\n"
                f"Currently active add-ons: {avail}.\n"
                f"You can add modules from Settings → Plan & Add-ons "
                f"(Stripe billing controls which are active)."
            ), "tier": "local", "latency_ms": 0,
               "source": "modules_intro_no"}

    # Generic "what modules / add-ons do I have"
    if not enabled:
        return {"reply": (
            "Just base Orby right now — no paid add-on modules enabled.\n"
            "Available add-ons you could activate from Settings → Plan & "
            "Add-ons: contractor (and more coming)."
        ), "tier": "local", "latency_ms": 0,
           "source": "modules_intro_base_only"}
    lines = [f"You have {len(enabled)} add-on module{'s' if len(enabled) != 1 else ''} active on top of base Orby:"]
    for m_name in enabled:
        desc = _MODULE_INTRO_DESCRIPTIONS.get(str(m_name).lower(),
                                                f"  · {m_name} — active")
        if desc.lstrip().startswith("·"):
            lines.append(desc)
        else:
            # Friendly multi-line entry
            lines.append(f"  · {desc}")
    return {"reply": "\n".join(lines), "tier": "local",
            "latency_ms": 0, "source": "modules_intro_list"}


# ── Public-chat referral: "where can I get one of these for my business?" ───
#
# Fires ONLY on direct visitor ask. Returns a one-sentence URL + redirect
# to the host business's flow. Never volunteers. Toggleable per-customer
# via CONFIG["referral_enabled"] (defaults True). URL comes from
# CONFIG["referral_url"], defaults to twickell.com until myorby.com is
# registered.

_REFERRAL_DEFAULT_URL = "twickell.com"

_REFERRAL_RE = _re.compile(
    r"^\s*(?:"
    # "Where can I get/buy one of these (for my business)?" — the noun phrase
    # is REQUIRED (no trailing ?), otherwise innocent ordering speech like
    # "where can I order food" would falsely trigger as a referral question.
    r"(?:where|how)\s+(?:can|do|would|could)\s+i\s+"
    r"(?:get|buy|find|sign\s+up\s+for|order|download|install|purchase|use|try)\s+"
    r"(?:my\s+own\s+|one\s+of\s+these\s*|an?\s+|the\s+|some(?:thing)?\s+like\s+this\s*)?"
    r"(?:orby|orbi|orbeez|this\s+(?:ai|thing|assistant|service|software|chatbot|bot|system|tool)|"
    r"one\s+of\s+(?:these|those)|something\s+like\s+this|an?\s+(?:ai|chatbot|receptionist))"
    # "I want one of these / I want Orby / I need an AI like this" — same fix:
    # noun phrase REQUIRED. Otherwise "I want it toasted" or "I would like
    # the 12-inch" falsely matches as a request for an AI product.
    r"|i\s+(?:want|need|would\s+like|gotta\s+get|am\s+looking\s+for)\s+(?:my\s+own\s+|one\s+of\s+these\s*|an?\s+|the\s+|some(?:thing)?\s+like\s+this\s*)?"
    r"(?:orby|orbi|this\s+(?:ai|thing|assistant|chatbot)|one\s+of\s+(?:these|those)|something\s+like\s+this|an?\s+(?:ai|chatbot|receptionist))"
    # "What AI is this / who made you / what's this app"
    r"|(?:what|which)\s+(?:ai|software|app|chatbot|assistant|service|company|program|product|system)\s+(?:is\s+)?this"
    r"|who\s+(?:made|built|created|owns|sells|developed|wrote)\s+(?:you|this)"
    r"|who\s+(?:is|are|made|built|owns)\s+(?:orby|orbi|orbeez)"
    r"|are\s+you\s+(?:built|made|powered)\s+by\s+(?:openai|chatgpt|claude|gemini|anthropic|google)"
    # "How much does Orby cost?" / "What's the price of Orby?"
    r"|how\s+much\s+(?:does|is)\s+(?:orby|orbi|this(?:\s+(?:ai|service|software))?)\s*(?:cost|price)?"
    r"|what(?:'s|\s+is)\s+(?:the\s+)?(?:price|cost)\s+(?:of|for)\s+(?:orby|orbi|this)"
    # "Can my business get Orby?" / "Do you sell Orby?"
    r"|can\s+(?:my|a)\s+business\s+(?:get|have|use|buy|sign\s+up\s+for)\s+(?:orby|orbi|one\s+of\s+these|something\s+like\s+this)"
    r"|do\s+you\s+sell\s+(?:orby|orbi|this(?:\s+(?:ai|service|software))?)"
    # "Is this Orby?" / "Are you Orby?" — visitor recognized the product
    r"|(?:is\s+this|are\s+you)\s+(?:orby|orbi|orbeez)"
    # "Tell me about Orby" / "What is Orby?"
    r"|(?:tell\s+me\s+about|what(?:'s|\s+is))\s+orby"
    r")\b",
    _re.IGNORECASE,
)


def _try_orby_referral(message: str, business: dict) -> dict | None:
    """When a visitor on a customer's Orby asks where to get their own
    Orby, give the URL and immediately return focus to the host business.
    Never volunteers — only fires on direct ask."""
    if not message:
        return None
    # Honor the kill switch — owner can turn this off per-customer
    if CONFIG.get("referral_enabled") is False:
        return None
    msg = message.strip()
    if not _REFERRAL_RE.match(msg):
        return None
    url = (CONFIG.get("referral_url") or _REFERRAL_DEFAULT_URL).strip()
    biz_name = (business.get("name") or "").strip() or "this business"
    audit.log_event(DATA_DIR, actor="public_visitor",
                    action="referral.shown",
                    meta={"url": url, "host_business": biz_name,
                          "message": message[:200]})
    return {"reply": (
        f"You can find everything about Orby at **{url}** — I'm not "
        f"allowed to say more from here since I'm working for "
        f"{biz_name} right now. Anything else I can help you with?"
    ), "tier": "local", "latency_ms": 0,
       "source": "orby_referral"}


_FORMS_INTRO_RE = _re.compile(
    r"^\s*(?:"
    r"what\s+(?:forms?|templates?|paperwork)\s+(?:do\s+i\s+have|are\s+(?:uploaded|loaded|on\s+file)|am\s+i\s+using)"
    r"|which\s+(?:forms?|templates?)\s+(?:do\s+i\s+have|am\s+i\s+using)"
    r"|(?:show|list|tell\s+me)\s+(?:me\s+)?(?:my\s+|the\s+|all\s+)?(?:forms?|templates?|paperwork)"
    r"|(?:do\s+i\s+have|have\s+i\s+uploaded)\s+(?:a\s+|an\s+|the\s+)?"
    r"(?P<kind_q>change[\s-]?order|co|contract|msa|lien\s+waiver|w[\s-]?9|coi(?:\s+request)?|subcontractor\s+agreement|punch\s+list|proposal)"
    r"\s*(?:form|template|paperwork|uploaded)?"
    r"|how\s+do\s+i\s+upload\s+(?:a\s+)?(?:form|template)"
    r")\s*[?.!]?\s*$",
    _re.IGNORECASE,
)

# Normalized chat-kind → canonical mod_forms.VALID_KINDS key
_FORM_KIND_ALIASES = {
    "change order": "change_order",
    "change-order": "change_order",
    "changeorder": "change_order",
    "co": "change_order",
    "contract": "contract",
    "msa": "msa",
    "lien waiver": "lien_waiver_partial_cond",  # default to most common
    "w9": "w9",
    "w-9": "w9",
    "w 9": "w9",
    "coi": "coi_request",
    "coi request": "coi_request",
    "subcontractor agreement": "subcontractor_agreement",
    "punch list": "punch_list",
    "proposal": "proposal",
}


def _try_forms_introspection(message: str, user_rec: dict) -> dict | None:
    """'What forms do I have' / 'show me my templates' / 'do I have a
    change order template uploaded' / 'how do I upload a form'."""
    if not message:
        return None
    msg = _strip_polite_prefix(message)
    m = _FORMS_INTRO_RE.match(msg)
    if not m:
        return None
    # Specific kind asked about
    kind_q = (m.group("kind_q") or "").strip().lower()
    if kind_q:
        canonical = _FORM_KIND_ALIASES.get(kind_q, kind_q.replace("-", "_").replace(" ", "_"))
        tpl = mod_forms.get_default(DATA_DIR, canonical)
        if tpl:
            field_count = len(tpl.get("detected_fields", []) or [])
            mapped = sum(1 for f in tpl.get("detected_fields", []) or []
                          if f.get("mapped_to"))
            return {"reply": (
                f"Yes — you have a {canonical.replace('_',' ')} template on file:\n"
                f"  · {tpl['display_name']} (uploaded {time.strftime('%b %-d', time.localtime(tpl.get('uploaded_at', 0)))})\n"
                f"  · {field_count} fillable fields detected, {mapped} auto-mapped to Orby data\n"
                f"  · Default: {'yes' if tpl.get('is_default') else 'no'}\n\n"
                f"To swap or update, upload a new one from the Forms tab."
            ), "tier": "local", "latency_ms": 0,
               "source": "forms_intro_yes"}
        else:
            return {"reply": (
                f"No {canonical.replace('_',' ')} template uploaded yet.\n"
                f"To add one: open the Forms tab → + Upload Template → "
                f"pick your blank PDF or Word doc → label kind as "
                f"\"{canonical}\". I'll auto-detect the fields and map "
                f"them to project data."
            ), "tier": "local", "latency_ms": 0,
               "source": "forms_intro_no"}
    # Generic list
    all_tpls = mod_forms.list_all(DATA_DIR)
    if not all_tpls:
        return {"reply": (
            "No form templates uploaded yet. The Forms tab in your "
            "dashboard lets you upload your own change orders, contracts, "
            "lien waivers, W-9s, etc. Orby reads each one, detects the "
            "fillable fields, and learns how to fill them from your "
            "project data."
        ), "tier": "local", "latency_ms": 0,
           "source": "forms_intro_empty"}
    by_kind = {}
    for t in all_tpls:
        by_kind.setdefault(t.get("kind", "?"), []).append(t)
    lines = [f"You have {len(all_tpls)} form template{'s' if len(all_tpls) != 1 else ''} on file:"]
    for kind, tpls in sorted(by_kind.items()):
        default = next((t for t in tpls if t.get("is_default")), tpls[0])
        extra = f" ({len(tpls)-1} other version{'s' if len(tpls) > 2 else ''})" if len(tpls) > 1 else ""
        fields = len(default.get("detected_fields", []) or [])
        lines.append(f"  · {kind.replace('_',' ').upper()}: \"{default['display_name']}\" "
                     f"({fields} fields){extra}")
    lines.append("\nManage in the Forms tab. Upload new ones the same place.")
    return {"reply": "\n".join(lines), "tier": "local",
            "latency_ms": 0, "source": "forms_intro_list"}


# ── Owner-simulating-customer-lead handlers ───────────────────────────────

_SIM_LEAD_NEED_RE = _re.compile(
    r"^\s*(?:i\s+need|i'?d\s+like|i\s+want|looking\s+for)\s+(?:a\s+|an\s+|some\s+)?"
    r"(?P<what>.+?)"
    r"[.!]?\s*(?:can\s+you\s+(?:schedule|book|set\s+up)|please\s+(?:schedule|book)|(?:can\s+you\s+)?give\s+me\s+(?:an?\s+)?(?:estimate|quote))"
    r".*?\s*[?.!]?\s*$",
    _re.IGNORECASE,
)
_SIM_LEAD_BUDGET_RE = _re.compile(
    r"^\s*(?:my\s+budget\s+is|i\s+have\s+a\s+budget\s+of)\s+(?:around\s+|about\s+|roughly\s+|~\s*)?"
    r"\$?[\d,]+(?:k|K|\s*thousand)?"
    r".*?(?:next\s+steps?|what(?:'s| do\s+i\s+do)\s+next|how\s+do\s+(?:i|we)\s+(?:start|begin|proceed))"
    r"\s*[?.!]?\s*$",
    _re.IGNORECASE,
)


def _try_owner_simulated_lead(message: str, user_rec: dict) -> dict | None:
    """In owner_chat, the owner sometimes simulates a customer to test the
    flow ('I need a kitchen remodel. Can you schedule an estimate?').
    Public_chat would auto-capture as a lead; here we acknowledge
    deterministically and point at the right entry path."""
    if not message:
        return None
    msg = _strip_polite_prefix(message)
    biz = mod_business.load(DATA_DIR)
    name = biz.get("name") or "us"
    contact = biz.get("contact") or {}
    phone = (contact.get("phone") or "").strip()
    email = (contact.get("email") or "").strip()
    contact_bit = ""
    if phone or email:
        bits = []
        if phone: bits.append(f"call/text {phone}")
        if email: bits.append(f"email {email}")
        contact_bit = " (a real customer would " + " or ".join(bits) + ")"

    m = _SIM_LEAD_NEED_RE.match(msg)
    if m:
        what = (m.group("what") or "").strip()
        return {"reply": (
            f"Got it — you'd like {what or 'work'} and want to schedule an "
            f"estimate. That's the kind of request that hits the WEBSITE "
            f"chat or phone receptionist, where I auto-capture the lead "
            f"and notify you{contact_bit}.\n"
            f"From the owner side, log it as a real lead with: "
            f"\"add a new lead, name <theirs>, phone <theirs>\" — I'll save "
            f"it to your messages inbox and flag it for follow-up."
        ), "tier": "local", "latency_ms": 0,
           "source": "sim_lead_need"}

    if _SIM_LEAD_BUDGET_RE.match(msg):
        return {"reply": (
            f"That budget context belongs on the customer's lead record. "
            f"In the live flow, a customer who types this in your website "
            f"chat or calls in: I'd capture their contact info, tag the "
            f"lead with their budget range, and notify you to schedule the "
            f"in-home estimate.\n"
            f"Owner-side action: \"add a new lead, name <theirs>, phone "
            f"<theirs>, $40k budget kitchen remodel\" and I'll log it."
        ), "tier": "local", "latency_ms": 0,
           "source": "sim_lead_budget"}
    return None


_SAFETY_SIGN_FOR_RE = _re.compile(
    # Anchored at start but no end-of-string requirement — catches the
    # leading command even when followed by justifications:
    # "go ahead and sign for them — the customer said it's fine"
    r"^\s*(?:"
    r"(?:go\s+ahead\s+and\s+)?sign\s+(?:a\s+|the\s+)?(?:contract|agreement|change[\s-]order|c\.?o\.?|document|proposal|paperwork|form)?\s*(?:for|on\s+behalf\s+of|in\s+place\s+of|as)\s+(?:the\s+|me|us|them)?\s*(?:customer|client|homeowner|him|her)"
    r"|(?:e[\s-]?sign|electronically\s+sign|forge|fake|just\s+sign)\s+(?:.+?\s+)?(?:for|on\s+behalf\s+of|as|in\s+place\s+of)\s+(?:the\s+)?(?:customer|client|him|her|them)"
    r"|(?:go\s+ahead\s+and\s+)?sign\s+(?:it\s+|that\s+)?(?:for|on\s+behalf\s+of)\s+(?:them|him|her|the\s+customer|the\s+client)"
    # "the customer told me (on the phone) to sign for them — go ahead and sign"
    # Allow arbitrary intermediate words between "told me" and "to sign".
    r"|.+?told\s+me\s+(?:.+?\s+)?to\s+sign\s+(?:.+?\s+)?(?:for|as|on\s+behalf\s+of)\s+(?:them|him|her|me|us|the\s+(?:customer|client))"
    # "the customer is fine with me signing for them"
    r"|.+?(?:said|told\s+me|told\s+us)\s+(?:.+?\s+)?(?:i|we|you|orby)\s+(?:can|could|should|might)\s+sign\s+(?:.+?\s+)?(?:for|as)\s+(?:them|him|her|the\s+customer)"
    # Trailing "— go ahead and sign" anywhere in the message
    r"|.+?go\s+ahead\s+and\s+sign\s+(?:.+?\s+)?(?:for|as|on\s+behalf\s+of)\s+(?:them|him|her|me|us|the\s+customer|the\s+client)"
    r")\b",
    _re.IGNORECASE,
)
_SAFETY_MODIFY_SIGNED_CO_RE = _re.compile(
    # Anchored at start; no end-of-string requirement.
    # Catches: "modify a signed CO", "edit CO #1", "bump CO #1 from $X to $Y",
    # "adjust the CO", "change CO #2 amount", "skip X in CO #1 but add Y".
    # Optional leading polite/hedge words: "just", "go ahead and", "please".
    r"^\s*(?:just\s+|please\s+|go\s+ahead\s+and\s+|can\s+you\s+|could\s+you\s+|i\s+need\s+(?:you\s+)?to\s+)?(?:"
    r"(?:modify|edit|change|alter|update|revise|adjust|bump|raise|lower|tweak|increase|decrease)\s+(?:a\s+|the\s+|that\s+)?(?:signed\s+)?(?:change[\s-]order|c\.?o\.?)(?:\s*#\s*\d+)?"
    r"|edit\s+(?:a\s+|the\s+)?(?:c\.?o\.?|change[\s-]order)\s+(?:that(?:'s| is)\s+(?:been\s+)?)?signed"
    r"|(?:.+?\s+)?(?:wants?|wanting)\s+to\s+(?:skip|drop|remove|swap|exchange)\s+(?:.+?\s+)?(?:in|from|on)\s+(?:c\.?o\.?|change[\s-]order)(?:\s*#\s*\d+)?"
    # "adjust the contract of sale (CO)" type misinterpretations
    r"|adjust\s+(?:a\s+|the\s+)?co\b"
    r")\b",
    _re.IGNORECASE,
)
_SAFETY_DELETE_FILES_RE = _re.compile(
    r"^\s*(?:"
    r"(?:delete|remove|trash|nuke|wipe|purge|erase)\s+(?:all\s+|every\s+|the\s+)?(?P<who>.+?)\s+(?:project\s+)?files?"
    r"|delete\s+(?:every|all)\s+file\s+(?:for|on|in)\s+(?P<who2>.+?)"
    r")\s*[?.!]?\s*$",
    _re.IGNORECASE,
)
_SAFETY_INCREASE_UNAUTHORIZED_RE = _re.compile(
    r"^\s*(?:"
    r"increase\s+(?:a\s+|the\s+)?(?:.+?\s+)?contract\s+(?:amount\s+)?by\s+\$?[\d,]+(?:\.\d+)?(?:k|K)?\s+"
    r"(?:without\s+(?:client\s+|customer\s+|homeowner\s+|their\s+)?(?:authorization|approval|sign[\s-]off|consent))"
    r"|inflate\s+(?:the\s+)?contract\s+by\s+\$?[\d,]+"
    r")\s*[?.!]?\s*$",
    _re.IGNORECASE,
)
_SAFETY_IMPERSONATE_RE = _re.compile(
    r"^\s*(?:"
    r"log\s+(?:me|us|him|her|them)\s+in\s+as\s+\w+"
    r"|sign\s+(?:me|us|him|her|them)\s+in\s+as\s+\w+"
    r"|impersonate\s+\w+"
    r"|switch\s+(?:my\s+)?(?:user|account|login|session)\s+to\s+\w+"
    r"|pretend\s+(?:i'?m|to\s+be|you'?re)\s+\w+"
    r")\b",
    _re.IGNORECASE,
)
_SAFETY_FAKE_PAID_RE = _re.compile(
    # Anchored at start; no end-of-string requirement.
    # Catches: "mark all unpaid invoices paid", "mark INV-X paid" (no
    # payment), "fake a payment", "say everyone paid".
    r"^\s*(?:"
    r"mark\s+(?:all\s+(?:my\s+|the\s+)?(?:unpaid\s+|outstanding\s+|open\s+)?invoices?)\s+(?:as\s+)?paid"
    r"|mark\s+(?:everyone|every(?:one|body))\s+(?:as\s+)?paid"
    r"|mark\s+(?:an?\s+|the\s+)?invoice\s+(?:as\s+)?paid\s+(?:when|even\s+(?:though|if))\s+no\s+payment\s+(?:exists|was\s+made|received)"
    r"|(?:fake|forge|fabricate|invent|make\s+up)\s+(?:a\s+|the\s+|some\s+)?payments?"
    r"|(?:say|pretend|act\s+like)\s+(?:everyone\s+|they\s+|the\s+customer\s+)?paid"
    r")\b",
    _re.IGNORECASE,
)
# Recording a real partial payment without an amount — e.g. "Sarah paid
# half of INV-XXXX in cash today". Should ASK for the amount instead of
# silently inventing one (or LLM falsely confirming).
_SAFETY_PARTIAL_NO_AMOUNT_RE = _re.compile(
    r"^\s*(?:.+?\s+)?paid\s+(?:half|part|some|the\s+rest|a\s+chunk|a\s+portion)\s+(?:of\s+)?(?:INV-[\w-]+)?",
    _re.IGNORECASE,
)
_SAFETY_SEND_WITHOUT_APPROVAL_RE = _re.compile(
    r"^\s*(?:"
    r"(?:create|draft|build|make)\s+(?:a\s+|the\s+)?(?:change[\s-]order|c\.?o\.?)\s+and\s+(?:send|email|fire)\s+(?:it\s+)?"
    r"(?:out\s+)?(?:without|with\s+no)\s+(?:my\s+|the\s+|getting\s+|owner\s+|gc\s+|prior\s+)?approval"
    r"|(?:send|fire|push)\s+(?:a\s+|the\s+)?(?:change[\s-]order|c\.?o\.?)\s+(?:out\s+)?(?:without|with\s+no)\s+(?:my\s+|the\s+|getting\s+|owner\s+|gc\s+|prior\s+)?approval"
    r"|skip\s+(?:my\s+|gc\s+|the\s+|owner\s+)?approval"
    r")\s*[?.!]?\s*$",
    _re.IGNORECASE,
)
# Catches "charge Sarah $500", "refund the deposit to Bob", "run the
# card on file", "process a payment from X", "take a $100 deposit from Y".
# Stripe is READ-ONLY per the shipped capabilities doc — Orby never moves
# money. The LLM tends to hallucinate compliance here, so deterministic
# refusal beats trusting the prompt.
_SAFETY_CHARGE_RE = _re.compile(
    # Matches the verb-phrase at the START of the message. Doesn't require
    # end-of-string so "Refund $200 to Bob" / "Run the card on file for $50"
    # / "Process a payment from Joe Maxwell" all match the leading command.
    # Allows optional polite/authority prefixes like "I authorize you to ...",
    # "please ...", "go ahead and ...", "I need you to ...".
    r"^\s*(?:"
    r"(?:i\s+)?(?:authorize|am\s+authorizing|approve|am\s+approving|need|want|am\s+telling)\s+(?:you\s+)?to\s+"
    r"|please\s+|go\s+ahead\s+and\s+|just\s+|can\s+you\s+|could\s+you\s+"
    r")?(?:"
    r"charge\s+(?:.+?\s+)?\$?[\d,]+(?:\.\d{1,2})?"
    r"|charge\s+(?:.+?\s+)?(?:on|to|using|with)\s+(?:her|his|their|the)\s+(?:card|credit\s+card|debit\s+card|account)"
    r"|charge\s+(?:.+?\s+)?card(?:\s+on\s+file)?"
    r"|(?:run|swipe|put\s+through)\s+(?:the\s+|her\s+|his\s+|their\s+|a\s+)?(?:card|credit\s+card|debit\s+card)"
    r"|process\s+(?:a\s+|the\s+)?(?:payment|charge|transaction|refund)"
    r"|(?:refund|reverse|void)\s+(?:.+?\s+)?\$?[\d,]+(?:\.\d{1,2})?"
    r"|(?:issue|give)\s+(?:a\s+|the\s+)?refund"
    r"|take\s+(?:a\s+|the\s+)?\$?[\d,]+\s+deposit\s+(?:from|off)"
    r"|bill\s+(?:.+?\s+)?(?:card|credit\s+card)"
    r"|move\s+(?:money|funds|\$[\d,]+)\s+(?:from|to)"
    r"|withdraw\s+(?:from|money\s+from)"
    r")\b",
    _re.IGNORECASE,
)


def _try_safety_refusal(message: str, user_rec: dict) -> dict | None:
    """Hard refusals for actions that would hurt the contractor or their
    customer. Logged to audit so there's a record someone TRIED."""
    if not message:
        return None
    msg = _strip_polite_prefix(message)

    if _SAFETY_SIGN_FOR_RE.match(msg):
        audit.log_event(DATA_DIR, actor=user_rec.get("username", "?"),
                        action="safety.refused.sign_for_customer",
                        meta={"message": message[:200]})
        return {"reply": (
            "I won't sign anything on behalf of the customer — that would "
            "void the contract and could be construed as forgery. The "
            "customer has to sign their own change orders.\n"
            "What I CAN do: mint a one-time sign link for them.\n"
            "  · \"add CO on <project> — $<amount> for <description>\"\n"
            "  → I'll create the CO and give you a link to hand to them on "
            "site (foreman's iPad works, or text the link)."
        ), "tier": "local", "latency_ms": 0,
           "source": "safety_refused_sign_for"}

    if _SAFETY_MODIFY_SIGNED_CO_RE.match(msg):
        audit.log_event(DATA_DIR, actor=user_rec.get("username", "?"),
                        action="safety.refused.modify_signed_co",
                        meta={"message": message[:200]})
        return {"reply": (
            "Signed change orders are locked — I won't modify one after the "
            "customer signed it. Doing that would invalidate their "
            "signature and put you on the wrong side of any dispute.\n"
            "If something was wrong with it, create a CORRECTIVE CO instead:\n"
            "  · \"add CO on <project> — $<amount> — corrects CO #<n>\"\n"
            "Both stay in the record, and the customer signs the correction."
        ), "tier": "local", "latency_ms": 0,
           "source": "safety_refused_modify_signed"}

    if _SAFETY_INCREASE_UNAUTHORIZED_RE.match(msg):
        audit.log_event(DATA_DIR, actor=user_rec.get("username", "?"),
                        action="safety.refused.unauthorized_increase",
                        meta={"message": message[:200]})
        return {"reply": (
            "I won't raise a contract amount without client authorization — "
            "that's the exact thing change orders exist to prevent.\n"
            "Proper path: \"add CO on <project> — $<amount> for <reason>\". "
            "The customer signs, then it's added to the contract automatically."
        ), "tier": "local", "latency_ms": 0,
           "source": "safety_refused_unauthorized_increase"}

    if _SAFETY_IMPERSONATE_RE.match(msg):
        audit.log_event(DATA_DIR, actor=user_rec.get("username", "?"),
                        action="safety.refused.impersonate",
                        meta={"message": message[:200]})
        return {"reply": (
            "I won't switch you to another user's account. If you actually "
            "need to be that person, log out and log in with their "
            "credentials — that way every action is properly attributed in "
            "the audit log.\n"
            "If you're just trying to see what their dashboard looks like "
            "from a staff perspective, the Staff tab lets you preview the "
            "view without taking over their session."
        ), "tier": "local", "latency_ms": 0,
           "source": "safety_refused_impersonate"}

    if _SAFETY_FAKE_PAID_RE.match(msg):
        audit.log_event(DATA_DIR, actor=user_rec.get("username", "?"),
                        action="safety.refused.fake_payment",
                        meta={"message": message[:200]})
        return {"reply": (
            "I won't mark an invoice paid when no payment exists — that's "
            "books-cooking territory and it'll bite you at tax time.\n"
            "If you actually received cash/check, tell me: \"received "
            "$<amount> on INV-XXXX\" and I'll record it properly with a "
            "real payment line."
        ), "tier": "local", "latency_ms": 0,
           "source": "safety_refused_fake_payment"}

    if _SAFETY_CHARGE_RE.match(msg):
        audit.log_event(DATA_DIR, actor=user_rec.get("username", "?"),
                        action="safety.refused.charge_or_refund",
                        meta={"message": message[:200]})
        return {"reply": (
            "I won't move money — Stripe is read-only on my end, and "
            "charging cards or issuing refunds is a one-way door I shouldn't "
            "be walking through on a chat command.\n"
            "If you actually want to charge a customer, do it from your "
            "Stripe dashboard directly. Then tell me \"received $<amount> "
            "on INV-XXXX\" and I'll record the payment against the invoice."
        ), "tier": "local", "latency_ms": 0,
           "source": "safety_refused_charge"}

    # Conditional/future-tense action — "if Joe pays by Friday, mark X paid"
    # / "when the customer signs, send the invoice". I can't watch and act
    # later. Be honest about it instead of falsely promising async behavior.
    if _re.match(
        r"^\s*(?:if|when|once|as\s+soon\s+as)\s+.+?(?:,\s*|\s+then\s+)"
        r"(?:mark|send|email|charge|record|update|cancel|delete|create|file)\b",
        msg, _re.IGNORECASE):
        audit.log_event(DATA_DIR, actor=user_rec.get("username", "?"),
                        action="safety.refused.async_conditional",
                        meta={"message": message[:200]})
        return {"reply": (
            "I can't watch for a future event and then act on it — I only "
            "run when you talk to me. So \"if X happens, do Y\" is a "
            "promise I can't keep.\n"
            "What WILL work:\n"
            "  · Set a reminder: \"remind me Friday to check whether Joe paid\"\n"
            "  · Come back when it happens: \"Joe paid $X on INV-XXXX\" and "
            "I'll record it right then."
        ), "tier": "local", "latency_ms": 0,
           "source": "safety_refused_async"}

    # Partial payment WITHOUT an explicit amount — ask, don't fabricate.
    if _SAFETY_PARTIAL_NO_AMOUNT_RE.match(msg):
        # Only block if there's no explicit dollar amount in the message
        if not _re.search(r"\$\s*[\d,]+", message):
            audit.log_event(DATA_DIR, actor=user_rec.get("username", "?"),
                            action="safety.asked.partial_no_amount",
                            meta={"message": message[:200]})
            return {"reply": (
                "I need an exact dollar amount before I record a partial "
                "payment — \"half\" / \"part\" / \"some\" isn't precise "
                "enough for the ledger.\n"
                "Try: \"received $<amount> on INV-XXXX\" and I'll log it "
                "properly against the invoice."
            ), "tier": "local", "latency_ms": 0,
               "source": "safety_partial_no_amount"}

    if _SAFETY_SEND_WITHOUT_APPROVAL_RE.match(msg):
        audit.log_event(DATA_DIR, actor=user_rec.get("username", "?"),
                        action="safety.refused.skip_approval",
                        meta={"message": message[:200]})
        return {"reply": (
            "Change orders go to the customer for SIGNATURE — but in the "
            "current workflow that's the same moment the foreman shows it "
            "to them on site. You're always in the loop because you're the "
            "one creating the CO.\n"
            "If you want to skip the foreman-handoff step and just email "
            "the sign link, that's possible — but I'm not going to send "
            "anything WITHOUT generating the CO record first."
        ), "tier": "local", "latency_ms": 0,
           "source": "safety_refused_skip_approval"}

    if _SAFETY_DELETE_FILES_RE.match(msg):
        m = _SAFETY_DELETE_FILES_RE.match(msg)
        who = (m.group("who") or m.group("who2") or "").strip()
        audit.log_event(DATA_DIR, actor=user_rec.get("username", "?"),
                        action="safety.refused.bulk_file_delete",
                        meta={"target": who, "message": message[:200]})
        return {"reply": (
            f"I won't bulk-delete files. Even if I could find every file "
            f"related to \"{who}\", a one-shot delete with no confirmation "
            f"is too dangerous — you lose records you might need for "
            f"warranty calls, disputes, or taxes.\n"
            f"What I CAN do safely:\n"
            f"  · Archive a project (\"mark <project> complete\") — files "
            f"stay readable but are visually moved out of the active list.\n"
            f"  · Delete one specific document if you point me at it by "
            f"exact filename."
        ), "tier": "local", "latency_ms": 0,
           "source": "safety_refused_bulk_delete"}
    return None


_TASK_COMPLETE_RE = _re.compile(
    r"^\s*(?:"
    r"(?:i'?m\s+)?done\s+(?:with\s+)?(?P<body>.+?)"
    r"|(?:i\s+)?(?:finished|completed|did)\s+(?:with\s+)?(?P<body2>.+?)"
    r"|(?:mark|march|check)\s+(?:off\s+)?(?P<body3>.+?)\s+(?:as\s+)?(?:done|complete|completed|finished)"
    r"|(?P<body4>.+?)\s+(?:is\s+)?(?:done|complete|completed|finished|wrapped)"
    r")\s*[?.!]?\s*$",
    _re.IGNORECASE,
)


def _try_task_complete(message: str, user_rec: dict) -> dict | None:
    """'Done with the supplier call' / 'I finished the budget review' →
    mark a matching open task done. Falls through if there's no task that
    fuzzy-matches the body."""
    if not message:
        return None
    msg = _strip_polite_prefix(message)
    if _re.match(r"^\s*(?:what|show|list|which|do|does|did)\b", msg, _re.IGNORECASE):
        return None
    m = _TASK_COMPLETE_RE.match(msg)
    if not m:
        return None
    body = (m.group("body") or m.group("body2") or m.group("body3")
            or m.group("body4") or "").strip().rstrip("?.!")
    if not body or len(body) < 3:
        return None
    # Filter out things that obviously aren't task references — these
    # would catch generic life statements ("I'm done", "we're finished").
    if body.lower() in {"it", "that", "this", "everything", "all of it",
                        "for now", "for the day", "for today"}:
        return None
    username = user_rec.get("username", "owner")
    try:
        user_dir = users_mod.get_user_dir(DATA_DIR, username)
    except Exception:
        return None
    try:
        open_tasks = mod_tasks.list_all(user_dir, include_done=False)
    except Exception:
        return None
    if not open_tasks:
        return None
    body_l = body.lower()
    body_tokens = set(w for w in _re.split(r"\W+", body_l) if len(w) >= 3)
    if not body_tokens:
        return None
    # Score each open task by token-overlap with the user's phrase
    scored = []
    for t in open_tasks:
        ttext = (t.get("text") or "").lower()
        ttokens = set(w for w in _re.split(r"\W+", ttext) if len(w) >= 3)
        overlap = len(body_tokens & ttokens)
        if overlap > 0:
            scored.append((overlap, t))
    if not scored:
        return None
    scored.sort(key=lambda x: -x[0])
    top_score = scored[0][0]
    # If top match is much stronger than second-best (or only one match),
    # take it. Otherwise ask which.
    exactish = any(
        body_l in ((t.get("text") or "").lower())
        or ((t.get("text") or "").lower() in body_l and len((t.get("text") or "")) >= 6)
        for _, t in scored[:1]
    )
    if top_score >= 2 or exactish:
        target = scored[0][1]
        try:
            mod_tasks.mark_done(user_dir, target["id"])
        except Exception as e:
            return {"reply": f"Couldn't mark done: {e}",
                    "tier": "local", "latency_ms": 0,
                    "source": "task_done_error"}
        audit.log_event(DATA_DIR, actor=username, action="task.done",
                        meta={"task_id": target["id"], "text": target.get("text", "")})
        return {"reply": f"✓ Marked done: \"{target.get('text','')}\"",
                "tier": "local", "latency_ms": 0,
                "source": "task_done"}
    # Ambiguous
    listed = "\n".join(f"  · {t['text']}" for _, t in scored[:5])
    return {"reply": f"A few tasks could match \"{body}\":\n{listed}\nWhich one?",
            "tier": "local", "latency_ms": 0,
            "source": "task_done_ambiguous"}


_REMINDERS_LIST_RE = _re.compile(
    r"^\s*(?:"
    r"what\s+reminders?\s+do\s+i\s+have(?:\s+(?:coming\s+up|this\s+week|today|upcoming|soon|scheduled))?"
    r"|show\s+(?:me\s+)?(?:my\s+)?(?:upcoming\s+|open\s+)?reminders?"
    r"|list\s+(?:my\s+)?reminders?"
    r"|any\s+(?:upcoming\s+|open\s+)?reminders?"
    r"|what\s+(?:are\s+)?my\s+(?:upcoming\s+|open\s+)?reminders?"
    r")\s*[?.!]?\s*$",
    _re.IGNORECASE,
)
_REMINDER_DONE_RE = _re.compile(
    r"^\s*(?:"
    r"(?:mark|check)\s+(?:off\s+)?(?P<body>.+?)\s+(?:as\s+)?(?:done|dunn|complete|completed|finished)"
    r"|(?:mark|check)\s+(?:it|that|this)\s+(?:as\s+)?(?:done|dunn|complete|completed|finished)"
    r"|(?P<body2>.+?)\s+(?:is\s+)?(?:done|complete|completed|finished)"
    r")\s*[?.!]?\s*$",
    _re.IGNORECASE,
)


def _fmt_reminder_due(due_iso: str) -> str:
    try:
        s = str(due_iso or "").replace("Z", "+00:00")
        dt = _datetime.fromisoformat(s)
        if dt.tzinfo is None:
            dt = dt.replace(tzinfo=_timezone.utc)
        local = dt.astimezone()
        return local.strftime("%a %b %-d at %-I:%M %p")
    except Exception:
        return due_iso or "unknown time"


def _reminder_tokens(text: str) -> set[str]:
    stop = {"the", "and", "for", "with", "from", "this", "that", "about",
            "into", "your", "their", "our", "you", "me", "my", "any", "all",
            "now", "out", "off", "but", "not", "one", "two", "are", "was",
            "were", "has", "had", "will", "as", "done", "dunn", "complete",
            "completed", "finished", "mark", "check"}
    return {w for w in _re.split(r"\W+", (text or "").lower())
            if len(w) >= 3 and w not in stop}


def _find_matching_reminders(user_dir: Path, query: str) -> list[dict]:
    try:
        open_rem = [r for r in mod_reminders.list_all(user_dir)
                    if r.get("status") in (None, "pending", "snoozed")]
    except Exception:
        return []
    q_tokens = _reminder_tokens(query)
    if not q_tokens:
        return []
    scored: list[tuple[int, dict]] = []
    for r in open_rem:
        overlap = len(q_tokens & _reminder_tokens(r.get("text") or ""))
        if overlap:
            scored.append((overlap, r))
    scored.sort(key=lambda x: (-x[0], x[1].get("due", "")))
    return [r for _, r in scored]


def _recent_reminder_query_from_history(history: list[dict]) -> str:
    if not isinstance(history, list):
        return ""
    for item in reversed(history[-6:]):
        if (item or {}).get("role") != "assistant":
            continue
        text = str((item or {}).get("content") or "")
        m = _re.search(r"reminder\s+(?:for|to)\s+\"?([^\".]+)\"?", text, _re.IGNORECASE)
        if m:
            return m.group(1).strip()
        m = _re.search(r"\"([^\"]{3,80})\"", text)
        if m and "reminder" in text.lower():
            return m.group(1).strip()
    return ""


