def _try_legal_chat(message: str, user_rec: dict,
                    history: list) -> dict | None:
    """Deterministic handler for natural-language legal paralegal commands."""
    msg = message.strip()

    # Log time
    m = _LEGAL_LOG_TIME_RE.match(msg)
    if m:
        try:
            hours = float(m.group("hours"))
        except ValueError:
            return None
        matter_q = (m.group("matter") or "").strip()
        desc = (m.group("desc") or "").strip() or f"Work on {matter_q}"
        matters = mod_legal.list_matters(DATA_DIR, search=matter_q)
        if matters:
            matter = matters[0]
            entry = mod_legal.log_time(
                DATA_DIR,
                matter_id=matter["id"],
                matter_title=matter["title"],
                hours=hours,
                description=desc,
                rate=float(matter.get("rate") or 0),
            )
            return {
                "reply": (
                    f"Logged {hours}h to {matter['title']} "
                    f"({matter['matter_number']}) — {desc}."
                ),
                "source": "legal.time",
            }
        return {
            "reply": f"I don't have a matter matching \"{matter_q}\". Want me to open one?",
            "source": "legal.time",
        }

    # Conflict check
    m = _LEGAL_CONFLICT_RE.match(msg)
    if m:
        name = (m.group("name") or "").strip()
        hits = mod_legal.conflict_check(DATA_DIR, name)
        if not hits:
            return {
                "reply": f"No conflicts found for \"{name}\". Clear to open a matter.",
                "source": "legal.conflict",
            }
        lines = [f"CONFLICT FLAG — \"{name}\" found in {len(hits)} matter(s):"]
        for h in hits:
            lines.append(
                f"  • {h['matter_number']} {h['title']} — "
                f"{h['conflict_type']} ({h['status']})"
            )
        lines.append("Attorney must review before opening a new matter.")
        return {"reply": "\n".join(lines), "source": "legal.conflict"}

    # Open new matter
    m = _LEGAL_OPEN_MATTER_RE.match(msg)
    if m:
        client = (m.group("client") or "").strip()
        return {
            "reply": (
                f"Got it — opening a matter for {client}. "
                f"What's the case title (e.g. \"{client} v. [opposing party]\"), "
                f"the practice area, and their contact info?"
            ),
            "source": "legal.matter.open_prompt",
            "pending": {"action": "open_matter", "client_name": client},
        }

    # List matters
    if _LEGAL_MATTERS_RE.match(msg):
        matters = mod_legal.list_matters(DATA_DIR, status="active")
        if not matters:
            matters = mod_legal.list_matters(DATA_DIR)
        if not matters:
            return {
                "reply": "No matters on file yet. Say \"open a matter for [client name]\" to start one.",
                "source": "legal.matters",
            }
        lines = [f"You have {len(matters)} matter(s):"]
        for mat in matters[:10]:
            lines.append(
                f"  • {mat['matter_number']} — {mat['title']} "
                f"({mat.get('status','?')}, {mat.get('practice_area') or mat.get('type','?')})"
            )
        if len(matters) > 10:
            lines.append(f"  … and {len(matters) - 10} more.")
        return {"reply": "\n".join(lines), "source": "legal.matters"}

    # Matter status query — "what's the status of Smith v. Jones?"
    m = _LEGAL_MATTER_STATUS_RE.match(msg)
    if m:
        matter_q = (m.group("matter") or "").strip()
        # Strip trailing question marks, "matter", "case"
        matter_q = _re.sub(r'[\?\s]+$', '', matter_q)
        matter_q = _re.sub(r'\b(?:matter|case|file)\b', '', matter_q, flags=_re.I).strip()
        hits = mod_legal.list_matters(DATA_DIR, search=matter_q) if matter_q else []
        if not hits:
            # Broader fallback — try each word
            for word in matter_q.split():
                if len(word) > 3:
                    hits = mod_legal.list_matters(DATA_DIR, search=word)
                    if hits:
                        break
        if not hits:
            return {
                "reply": (
                    f"I couldn't find a matter matching \"{matter_q}\". "
                    "Try the client name or matter number."
                ),
                "source": "legal.matter.status",
            }
        mat = hits[0]
        from datetime import date as _status_date
        today = _status_date.today()
        # Upcoming deadlines for this matter
        upcoming = mod_legal.list_deadlines(DATA_DIR, matter_id=mat["id"],
                                             status="pending", upcoming_days=30)
        # Unbilled time
        time_entries = mod_legal.list_time(DATA_DIR, matter_id=mat["id"])
        unbilled = [e for e in time_entries if not e.get("billed")]
        unbilled_hrs  = sum(e.get("hours", 0) for e in unbilled)
        unbilled_amt  = sum(e.get("amount", 0) for e in unbilled)
        total_hrs     = sum(e.get("hours", 0) for e in time_entries)

        lines = [
            f"**{mat['title']}** ({mat['matter_number']})",
            f"Status: {mat.get('status','?').upper()}  |  "
            f"Practice area: {(mat.get('practice_area') or 'unspecified').replace('_', ' ')}",
        ]
        if mat.get("client_name"):
            lines.append(f"Client: {mat['client_name']}")
        if mat.get("opposing_party"):
            lines.append(f"Opposing: {mat['opposing_party']}")
        if mat.get("court"):
            lines.append(f"Court: {mat['court']}"
                         + (f"  |  Case #: {mat['case_number']}" if mat.get("case_number") else ""))
        lines.append(f"Time logged: {total_hrs:.1f}h total  |  Unbilled: {unbilled_hrs:.1f}h (${unbilled_amt:.2f})")
        if upcoming:
            lines.append(f"\nUpcoming deadlines (next 30 days):")
            for dl in upcoming[:5]:
                due = _status_date.fromisoformat(dl["due_date"])
                days_out = (due - today).days
                label = "Today" if days_out == 0 else f"in {days_out}d ({dl['due_date']})"
                lines.append(f"  • {dl['title']} — {label}")
        else:
            lines.append("No deadlines in the next 30 days.")
        return {"reply": "\n".join(lines), "source": "legal.matter.status"}

    # Add deadline to a matter — "add deadline to Jones matter: discovery due July 15"
    _add_dl_m = _re.match(
        r"^\s*(?:add|set|create|log)\s+(?:a\s+)?deadline\s+(?:to|for|on)\s+"
        r"(?:the\s+)?(?P<matter>.+?)\s+(?:matter|case|file)?\s*:\s*"
        r"(?P<title>.+?)\s+(?:due\s+)?(?P<date>(?:jan|feb|mar|apr|may|jun|jul|aug|sep|oct|nov|dec)[a-z]*\.?\s+\d{1,2}|\d{4}-\d{2}-\d{2}|\d{1,2}/\d{1,2}(?:/\d{2,4})?)"
        r"\s*[.!]?\s*$",
        msg, _re.IGNORECASE,
    )
    if _add_dl_m:
        matter_q = _add_dl_m.group("matter").strip()
        title = _add_dl_m.group("title").strip()
        date_raw = _add_dl_m.group("date").strip()
        hits = mod_legal.list_matters(DATA_DIR, search=matter_q)
        if not hits:
            return {"reply": f"I don't see a matter matching \"{matter_q}\". Check the name and try again.",
                    "source": "legal.deadline.matter_not_found"}
        mat = hits[0]
        try:
            import dateutil.parser as _dp
            due_date = _dp.parse(date_raw, default=_datetime.now()).date().isoformat()
        except Exception:
            due_date = date_raw
        dl = mod_legal.add_deadline(DATA_DIR, matter_id=mat["id"],
                                    matter_title=mat["title"], title=title, due_date=due_date)
        audit.log_event(DATA_DIR, actor=user_rec.get("username", "owner"),
                        action="legal.deadline.add", resource=dl.get("id"))
        return {"reply": f"Deadline added to {mat['title']}: {title} due {due_date}.",
                "source": "legal.deadline.added"}

    # Upcoming deadlines
    if _LEGAL_DEADLINES_RE.match(msg):
        summary = mod_legal.upcoming_deadlines_summary(DATA_DIR, days=30)
        return {"reply": summary, "source": "legal.deadlines"}

    # Legal dashboard
    if _LEGAL_DASHBOARD_RE.match(msg) and "legal" in msg.lower():
        data = mod_legal.dashboard_summary(DATA_DIR)
        upcoming = mod_legal.upcoming_deadlines_summary(DATA_DIR, days=7)
        reply = (
            f"Legal summary: {data['active_matters']} active matter(s), "
            f"{data['deadlines_next_7']} deadline(s) in the next 7 days, "
            f"${data['unbilled_amount']:.2f} unbilled ({data['unbilled_hours']}h).\n\n"
            f"Next 7 days:\n{upcoming}"
        )
        return {"reply": reply, "source": "legal.dashboard"}

    # Contract analysis — "analyze this contract", "find loopholes", "exit strategy", etc.
    # Also fires if a long message looks like a pasted contract (>500 chars + contract keywords)
    is_contract_cmd = bool(_LEGAL_CONTRACT_CMD_RE.search(msg))
    msg_lower = msg.lower()
    is_contract_paste = (
        len(msg) > 500
        and any(kw in msg_lower for kw in _CONTRACT_PASTE_KEYWORDS)
        and not is_contract_cmd
        and not _LEGAL_DRAFT_RE.match(msg)
        and not _LEGAL_FILING_RE.search(msg)
    )
    if is_contract_cmd or is_contract_paste:
        # Extract contract text from the message
        contract_text = ""
        client_side = ""

        # Look for text after "contract:" / "agreement:" / "lease:" in same message
        paste_m = _re.search(
            r'(?:contract|agreement|lease|nda|document|terms?)\s*[:]\s*(.{50,})$',
            msg, _re.IGNORECASE | _re.DOTALL,
        )
        if paste_m:
            contract_text = paste_m.group(1).strip()
        elif is_contract_paste or len(msg) > 500:
            contract_text = msg

        # Try to extract who the client is ("my client is the buyer/seller/landlord/etc.")
        client_m = _re.search(
            r'(?:my\s+client\s+is|client\s+is\s+the|client\s*=)\s*(?:the\s+)?([a-z\s]{3,40})',
            msg_lower,
        )
        if client_m:
            client_side = client_m.group(1).strip()

        # Pull jurisdiction from history
        jurisdiction = ""
        try:
            import re as _re3
            for item in reversed((history or [])[-6:]):
                txt = str((item or {}).get("content") or "")
                jx_m = _re3.search(r'\b(?:jurisdiction|state|court):\s*([A-Za-z\s]+)', txt, _re.I)
                if jx_m:
                    jurisdiction = jx_m.group(1).strip()[:40]
                    break
        except Exception:
            pass

        if not contract_text:
            return {
                "reply": (
                    "I'll analyze the contract and map out every exit option. "
                    "Paste the full contract text here (or the key sections you need reviewed). "
                    "If you know which party your client is — buyer, seller, tenant, service provider, etc. — "
                    "mention that so I can frame the analysis from their side."
                ),
                "source": "legal.contract.prompt",
            }

        # Phase 1 — extract parties, exit grounds, and search queries
        extraction_prompt = mod_legal.build_contract_extraction_prompt(contract_text, client_side)
        extraction_system = (
            "You are a contract attorney. Extract key legal issues and potential exit grounds "
            "from this contract precisely. Only extract what is actually in the text."
        )
        try:
            extraction = llm_client.generate_legal(
                CONFIG, extraction_system,
                [{"role": "user", "content": extraction_prompt}],
            ).text
        except Exception:
            log.exception("contract phase-1 extraction failed")
            return None

        # Pull search terms from extraction output (Section 7: SEARCH TERMS)
        search_terms = []
        try:
            sq_block = _re.search(
                r'7\.\s*SEARCH\s*TERMS\s*[:\n]+(.+?)(?=\n\d+\.|\Z)',
                extraction, _re.IGNORECASE | _re.DOTALL,
            )
            if sq_block:
                for line in sq_block.group(1).split('\n'):
                    term = line.strip().lstrip('-•* ').strip()
                    if term and len(term) > 10:
                        search_terms.append(term)
        except Exception:
            pass
        if not search_terms:
            search_terms = [f"contract exit strategy loopholes {jurisdiction}".strip()]

        # Phase 2 — hit legal databases on the extracted exit grounds
        from tools import legal_research as tool_legal
        all_results: dict = {"cases": [], "statutes": [], "secondary": [], "total": 0,
                             "query": search_terms[0], "jurisdiction": jurisdiction}
        for term in search_terms[:3]:
            try:
                r = tool_legal.search(term, jurisdiction=jurisdiction)
                all_results["cases"].extend(r.get("cases", []))
                all_results["statutes"].extend(r.get("statutes", []))
                all_results["secondary"].extend(r.get("secondary", []))
                all_results["total"] += r.get("total", 0)
            except Exception as e:
                log.warning(f"contract db search failed for {term!r}: {e}")

        # Deduplicate cases by citation/name
        seen_keys: set = set()
        unique_cases = []
        for c in all_results["cases"]:
            key = c.get("citation") or c.get("name", "")
            if key and key not in seen_keys:
                unique_cases.append(c)
                seen_keys.add(key)
        all_results["cases"] = unique_cases[:12]

        db_block = tool_legal.format_for_prompt(all_results) if all_results["total"] > 0 else ""

        # Phase 3 — synthesize full exit strategy memo
        analysis_prompt = mod_legal.build_contract_analysis_prompt(
            contract_text, extraction,
            db_results_block=db_block,
            jurisdiction=jurisdiction,
            client_side=client_side,
        )
        analysis_system = (
            "You are an experienced contract attorney. Write a thorough, practical exit strategy "
            "memo for attorney review. Use ONLY cases from the database results — never invent citations."
        )
        memo = ""
        for _attempt in range(2):
            try:
                memo = llm_client.generate_legal(
                    CONFIG, analysis_system,
                    [{"role": "user", "content": analysis_prompt}],
                ).text or ""
                if len(memo) > 200:
                    break
                log.warning(f"contract phase-3 attempt {_attempt+1} returned short content ({len(memo)} chars), retrying")
            except Exception:
                log.exception("contract phase-3 synthesis failed")
                if _attempt == 1:
                    return None
        if len(memo) < 200:
            return {"reply": "I had trouble generating the contract analysis — the AI returned empty content. Please try again.", "source": "legal.contract.error"}

        src_note = (
            f"\n\n*{all_results['total']} source(s) retrieved from CourtListener, "
            f"Harvard Caselaw, Cornell LII, and Justia.*"
            if all_results["total"] else
            "\n\n*No results found in legal databases — verify all citations independently.*"
        )
        return {
            "reply": (
                memo
                + "\n\n---\n*Contract exit strategy memo — prepared for attorney review. "
                "Verify all citations before relying on this memo in practice.*"
                + src_note
            ),
            "source": "legal.contract.analysis",
        }

    # Legal research
    m = _LEGAL_RESEARCH_RE.match(msg)
    if m:
        question = (m.group("question") or "").strip()
        # Pull jurisdiction hint from recent history if a matter was mentioned
        jurisdiction = ""
        try:
            import re as _re2
            for item in reversed((history or [])[-6:]):
                txt = str((item or {}).get("content") or "")
                jx_m = _re2.search(r'\b(?:jurisdiction|state|court):\s*([A-Za-z\s]+)', txt, _re2.I)
                if jx_m:
                    jurisdiction = jx_m.group(1).strip()[:40]
                    break
        except Exception:
            pass

        # Hit real legal databases first
        from tools import legal_research as tool_legal
        db_results = {}
        try:
            db_results = tool_legal.search(question, jurisdiction=jurisdiction)
            log.info(f"legal chat research: {db_results.get('total',0)} db results")
        except Exception as e:
            log.warning(f"legal chat db search failed: {e}")
        db_block = tool_legal.format_for_prompt(db_results) if db_results else ""

        research_prompt = mod_legal.build_research_prompt(
            question, jurisdiction=jurisdiction, db_results_block=db_block)
        system = (
            "You are an experienced paralegal preparing a legal research memo "
            "for attorney review. ONLY cite cases and statutes from the REAL "
            "LEGAL RESEARCH RESULTS block — do NOT invent citations. Be thorough. "
            "Always end with: 'Attorney should verify all citations before relying on this memo.'"
        )
        try:
            memo = llm_client.generate_legal(CONFIG, system,
                                           [{"role": "user", "content": research_prompt}]).text
        except Exception:
            log.exception("legal research via chat failed")
            return None
        found_note = (f"\n\n*{db_results.get('total',0)} source(s) retrieved from "
                      f"CourtListener, Harvard Caselaw, Cornell LII, and Justia.*"
                      if db_results.get("total") else
                      "\n\n*No results from legal databases — memo based on training data only. Verify all citations.*")
        return {
            "reply": memo + "\n\n---\n*Research memo prepared for attorney review.*" + found_note,
            "source": "legal.research",
        }

    # ── Filing intent: "I'm filing a lawsuit against Acme for Jim Smith" ────────
    filing_m = _LEGAL_FILING_RE.search(msg)
    if filing_m:
        # Extract defendant from regex, and look for plaintiff/client in the message
        defendant = (filing_m.group("defendant") or "").strip().rstrip(".,;")
        plaintiff = ""
        pm = _re.search(r'(?:client\s+is|for\s+(?:my\s+)?client|plaintiff\s+is|on\s+behalf\s+of)\s+(?P<n>[A-Z][a-zA-Z\s]{1,40})', msg)
        if pm:
            plaintiff = pm.group("n").strip()
        # Jump straight to complaint generation
        draft_prompt = mod_legal.build_auto_draft_prompt(
            "complaint",
            f"Filing a civil lawsuit. Plaintiff: {plaintiff or '[FILL: client name]'}. "
            f"Defendant: {defendant or '[FILL: defendant name]'}. "
            f"Additional attorney statement: {msg}",
        )
        if not draft_prompt:
            return None
        content = ""
        for _attempt in range(2):
            try:
                content = (llm_client.generate_legal(
                    CONFIG, mod_legal._DRAFT_SYSTEM,
                    [{"role": "user", "content": draft_prompt}],
                ).text or "").strip()
                if len(content) > 100:
                    break
                log.warning(f"draft generation attempt {_attempt+1} returned short content ({len(content)} chars), retrying")
            except Exception:
                log.exception("filing complaint generation failed")
        if len(content) < 100:
            return {"reply": "I had trouble generating the draft — the AI returned empty content. Please try again.", "source": "legal.draft.error"}
        saved = mod_legal.save_draft(
            DATA_DIR,
            matter_id="",
            matter_title=f"{plaintiff or 'Client'} v. {defendant}",
            template_key="complaint",
            template_name="Civil Complaint",
            content=content,
            fields={"plaintiff_name": plaintiff, "defendant_name": defendant},
        )
        return {
            "reply": (
                f"Here's the complaint draft — {plaintiff or 'Client'} v. {defendant}.\n\n"
                f"{content}\n\n"
                f"---\nReview it and tell me any changes. Any section marked [FILL: ...] "
                f"needs your details — just say what goes there. "
                f"When it's ready, say 'finalize it' and I'll mark it approved. "
                f"To print: say 'export draft {saved['id'][:8]}' or open Legal → Drafts in the dashboard."
            ),
            "source": "legal.draft.complaint",
            "draft_id": saved["id"],
        }

    # ── Document drafting: "draft a complaint / motion / affidavit …" ───────────
    m = _LEGAL_DRAFT_RE.match(msg)
    if m:
        doc_phrase = (m.group("doc") or "").strip().lower()
        # Match doc_phrase to a template key — try exact, then longest prefix match
        template_key = _DOC_KEY_MAP.get(doc_phrase)
        if not template_key:
            for phrase, key in _DOC_KEY_MAP.items():
                if phrase in doc_phrase or doc_phrase in phrase:
                    template_key = key
                    break
        if not template_key:
            return None
        tmpl = mod_legal.get_template(template_key)
        if not tmpl:
            return None

        # Generate immediately with whatever the attorney provided, placeholders for the rest
        draft_prompt = mod_legal.build_auto_draft_prompt(template_key, msg)
        if not draft_prompt:
            return None

        # For research-heavy documents (MSJ, trial brief, opposition), hit databases first
        db_block = ""
        if template_key in ("motion_summary_judgment", "trial_brief", "opposition", "appellate_brief"):
            try:
                from tools import legal_research as tool_legal
                r = tool_legal.search(msg[:200])
                db_block = tool_legal.format_for_prompt(r) if r.get("total") else ""
            except Exception:
                pass
            if db_block:
                draft_prompt = mod_legal.build_auto_draft_prompt(template_key, msg, db_results_block=db_block)

        content = ""
        for _attempt in range(2):
            try:
                content = (llm_client.generate_legal(
                    CONFIG, mod_legal._DRAFT_SYSTEM,
                    [{"role": "user", "content": draft_prompt}],
                ).text or "").strip()
                if len(content) > 100:
                    break
                log.warning(f"draft generation attempt {_attempt+1} returned short content ({len(content)} chars), retrying")
            except Exception:
                log.exception("legal draft generation failed")
        if len(content) < 100:
            return {"reply": "I had trouble generating the draft — the AI returned empty content. Please try again.", "source": "legal.draft.error"}

        saved = mod_legal.save_draft(
            DATA_DIR,
            matter_id="",
            matter_title=f"{tmpl['name']} — {msg[:50]}",
            template_key=template_key,
            template_name=tmpl["name"],
            content=content,
            fields={},
        )
        return {
            "reply": (
                f"Here's your {tmpl['name']} draft:\n\n"
                f"{content}\n\n"
                f"---\nReview it and tell me any changes. Any section marked [FILL: ...] "
                f"needs your details. When it's ready, say 'finalize it'. "
                f"To print: say 'export draft {saved['id'][:8]}'."
            ),
            "source": f"legal.draft.{template_key}",
            "draft_id": saved["id"],
        }

    # ── Revision: "change the prayer to add punitive damages" ───────────────────
    if _LEGAL_REVISE_DRAFT_RE.match(msg):
        # Look back through history for the most recent legal document draft
        recent_draft = None
        recent_draft_id = None
        for item in reversed((history or [])[-12:]):
            if (item or {}).get("role") == "assistant":
                content_str = str((item or {}).get("content") or "")
                # Check for our paralegal footer OR common legal document markers
                if ("Prepared by myOrby AI Paralegal" in content_str
                        or any(marker in content_str for marker in [
                            "IN THE ", "COMPLAINT FOR", "MOTION TO ", "MOTION FOR ",
                            "AFFIDAVIT OF", "NOTICE OF DEPOSITION", "SUBPOENA",
                            "SETTLEMENT AGREEMENT", "PLAINTIFF", "DEFENDANT",
                            "TRIAL BRIEF", "APPELLATE BRIEF",
                        ])):
                    # Extract draft text — look for draft ID hint from prior response
                    did_m = _re.search(r'export draft\s+([a-f0-9]{8})', content_str)
                    if did_m:
                        recent_draft_id = did_m.group(1)
                    recent_draft = content_str
                    break

        if recent_draft:
            rev_prompt = mod_legal.build_revision_prompt(recent_draft, msg)
            try:
                revised = llm_client.generate(
                    CONFIG,
                    "You are a litigation paralegal applying attorney revisions to a legal document. "
                    "Return the COMPLETE revised document — not just the changed section.",
                    [{"role": "user", "content": rev_prompt}],
                ).text
            except Exception:
                log.exception("draft revision failed")
                return None

            # Try to find and update the saved draft
            if recent_draft_id:
                try:
                    matches = [d for d in mod_legal.list_drafts(DATA_DIR)
                               if d["id"].startswith(recent_draft_id)]
                    if matches:
                        mod_legal.revise_draft(DATA_DIR, matches[0]["id"], revised,
                                               notes=f"Revision: {msg[:120]}")
                        recent_draft_id = matches[0]["id"][:8]
                except Exception:
                    pass

            id_hint = f" (draft {recent_draft_id})" if recent_draft_id else ""
            return {
                "reply": (
                    f"Here's the revised document{id_hint}:\n\n"
                    f"{revised}\n\n"
                    f"---\nTell me any other changes, or say 'finalize it' when it's ready to print."
                ),
                "source": "legal.draft.revision",
            }

    # ── Finalize / approve ───────────────────────────────────────────────────────
    if _LEGAL_FINALIZE_RE.match(msg):
        # Look for a recent draft to approve
        for item in reversed((history or [])[-12:]):
            if (item or {}).get("role") == "assistant":
                c = str((item or {}).get("content") or "")
                did_m = _re.search(r'export draft\s+([a-f0-9]{8})', c)
                if did_m:
                    try:
                        matches = [d for d in mod_legal.list_drafts(DATA_DIR)
                                   if d["id"].startswith(did_m.group(1))]
                        if matches:
                            mod_legal.approve_draft(DATA_DIR, matches[0]["id"])
                            did8 = matches[0]["id"][:8]
                            return {
                                "reply": (
                                    f"Document approved and saved. "
                                    f"To print it: open Legal → Drafts in the dashboard, "
                                    f"or say 'export draft {did8}' and I'll give you the direct download link."
                                ),
                                "source": "legal.draft.approved",
                            }
                    except Exception:
                        pass
            break

    # SOL lookup
    m = _LEGAL_SOL_RE.search(msg)
    if m and any(kw in msg.lower() for kw in ("sol", "statute of limitation")):
        area = (m.group("area") or "").strip().lower().replace(" ", "_")
        date_str = (m.group("date") or "").strip()
        result = mod_legal.sol_deadline_estimate(date_str, area) if date_str \
            else mod_legal.sol_lookup(area)
        if result:
            if isinstance(result, dict) and "estimated_deadline" in result:
                reply = (
                    f"SOL estimate for {area.replace('_',' ')}: "
                    f"{result.get('estimated_deadline','unknown')} "
                    f"({result.get('days_remaining','?')} days remaining).\n"
                    f"{result.get('notes','')}\n"
                    f"⚠ {result.get('warning','Attorney must verify.')}"
                )
            else:
                r = result
                reply = (
                    f"SOL reference for {area.replace('_',' ')}: "
                    f"{r.get('default_years','?')} year(s) default.\n"
                    f"{r.get('notes','')}\n"
                    f"⚠ Attorney must verify for specific facts and jurisdiction."
                )
            return {"reply": reply, "source": "legal.sol"}

    return None


def _try_reminders_chat(message: str, user_rec: dict,
                        history: list[dict]) -> dict | None:
    if not message:
        return None
    msg = _strip_polite_prefix(message)
    if _PA_REMINDERS_DONE_RE.search(msg):
        return None
    username = user_rec.get("username", "owner")
    try:
        user_dir = users_mod.get_user_dir(DATA_DIR, username)
    except Exception:
        return None

    if _REMINDERS_LIST_RE.match(msg):
        reminders = [r for r in mod_reminders.list_all(user_dir)
                     if r.get("status") in (None, "pending", "snoozed")]
        if not reminders:
            return {"reply": "You don't have any open reminders.",
                    "tier": "local", "latency_ms": 0,
                    "source": "reminders_list_empty"}
        lines = [f"You have {len(reminders)} open reminder{'s' if len(reminders) != 1 else ''}:"]
        for idx, r in enumerate(reminders[:10], 1):
            lines.append(f"{idx}. {r.get('text', '')} — {_fmt_reminder_due(r.get('due', ''))}")
        return {"reply": "\n".join(lines),
                "tier": "local", "latency_ms": 0,
                "source": "reminders_list"}

    m = _REMINDER_DONE_RE.match(msg)
    if not m:
        return None
    body = (m.group("body") or m.group("body2") or "").strip().rstrip("?.!")
    if not body or body.lower() in {"it", "that", "this"}:
        body = _recent_reminder_query_from_history(history)
    if not body:
        return {"reply": "Which reminder should I mark complete?",
                "tier": "local", "latency_ms": 0,
                "source": "reminder_done_needs_target"}
    matches = _find_matching_reminders(user_dir, body)
    if not matches:
        return {"reply": f"I don't see an open reminder matching \"{body}\".",
                "tier": "local", "latency_ms": 0,
                "source": "reminder_done_no_match"}
    if len(matches) > 1:
        top_tokens = _reminder_tokens(matches[0].get("text") or "")
        body_tokens = _reminder_tokens(body)
        if len(body_tokens & top_tokens) < 2:
            listed = "\n".join(f"  · {r.get('text','')} — {_fmt_reminder_due(r.get('due',''))}"
                               for r in matches[:5])
            return {"reply": f"A few reminders could match \"{body}\":\n{listed}\nWhich one?",
                    "tier": "local", "latency_ms": 0,
                    "source": "reminder_done_ambiguous"}
    target = matches[0]
    target_text_l = (target.get("text") or "").lower()
    body_l = body.lower()
    exactish = body_l in target_text_l or (target_text_l in body_l and len(target_text_l) >= 6)
    if len(_reminder_tokens(body) & _reminder_tokens(target.get("text") or "")) < 2 and not exactish:
        return {"reply": f"I found a weak match for \"{body}\" but won't mark it complete. Which reminder should I complete?",
                "tier": "local", "latency_ms": 0,
                "source": "reminder_done_weak_match"}
    if mod_reminders.mark_done(user_dir, target["id"]):
        audit.log_event(DATA_DIR, actor=username, action="reminder.done",
                        meta={"reminder_id": target["id"],
                              "text": target.get("text", "")})
        return {"reply": f"Marked reminder complete: \"{target.get('text','')}\"",
                "tier": "local", "latency_ms": 0,
                "source": "reminder_done"}
    return {"reply": f"Couldn't mark reminder complete: \"{target.get('text','')}\"",
            "tier": "local", "latency_ms": 0,
            "source": "reminder_done_failed"}


_REMINDER_REMOVE_RE = _re.compile(
    r"^\s*(?:"
    r"don'?t\s+remind\s+me\s+(?:about|to|of)\s+(?P<body>.+?)"
    r"|(?:cancel|remove|delete|drop|kill|clear)\s+(?:the\s+|that\s+|my\s+)?reminder\s+(?:about|to|for|on)\s+(?P<body2>.+?)"
    r"|(?:cancel|remove|delete|drop|kill|clear)\s+(?:my\s+|the\s+)?(?P<body3>.+?)\s+reminder"
    r"|forget\s+(?:about\s+)?(?:the\s+)?reminder\s+(?:about|to|for)\s+(?P<body4>.+?)"
    r"|(?:un[\s-]?set|un[\s-]?schedule)\s+(?:the\s+|my\s+)?reminder\s+(?:about|to|for)\s+(?P<body5>.+?)"
    r")\s*[?.!]?\s*$",
    _re.IGNORECASE,
)


def _try_reminder_remove(message: str, user_rec: dict) -> dict | None:
    """'Don't remind me about the meeting' / 'cancel the reminder about
    Friday' — find matching open reminders by token overlap and remove
    them (mark_done). Multiple matches → ask which."""
    if not message:
        return None
    msg = _strip_polite_prefix(message)
    m = _REMINDER_REMOVE_RE.match(msg)
    if not m:
        return None
    body = (m.group("body") or m.group("body2") or m.group("body3")
            or m.group("body4") or m.group("body5") or "").strip().rstrip("?.!")
    if not body or len(body) < 2:
        return None
    username = user_rec.get("username", "owner")
    try:
        user_dir = users_mod.get_user_dir(DATA_DIR, username)
    except Exception:
        return None
    try:
        open_rem = [r for r in mod_reminders.list_all(user_dir)
                    if r.get("status") in (None, "pending", "snoozed")]
    except Exception:
        return None
    if not open_rem:
        return {"reply": "You don't have any open reminders to cancel.",
                "tier": "local", "latency_ms": 0,
                "source": "reminder_remove_none"}
    # Stopwords get filtered out so "the" / "my" don't make every reminder
    # match every query. Same set used by the task-complete handler.
    _STOPWORDS = {"the", "and", "for", "with", "from", "this", "that",
                  "about", "into", "your", "their", "our", "you", "me",
                  "my", "any", "all", "now", "out", "off", "but", "not",
                  "one", "two", "are", "was", "were", "has", "had", "will"}
    body_l = body.lower()
    body_tokens = set(w for w in _re.split(r"\W+", body_l)
                       if len(w) >= 3 and w not in _STOPWORDS)
    if not body_tokens:
        return None
    scored = []
    for r in open_rem:
        rtext = (r.get("text") or "").lower()
        rtokens = set(w for w in _re.split(r"\W+", rtext)
                       if len(w) >= 3 and w not in _STOPWORDS)
        overlap = len(body_tokens & rtokens)
        if overlap > 0:
            scored.append((overlap, r))
    if not scored:
        return {"reply": f"I don't see a reminder matching \"{body}\". "
                          f"You have {len(open_rem)} open reminder{'s' if len(open_rem) != 1 else ''}.",
                "tier": "local", "latency_ms": 0,
                "source": "reminder_remove_no_match"}
    scored.sort(key=lambda x: -x[0])
    top_score = scored[0][0]
    if len(scored) == 1 or top_score >= scored[1][0] * 2 or top_score >= 2:
        target = scored[0][1]
        try:
            mod_reminders.mark_done(user_dir, target["id"])
        except Exception as e:
            return {"reply": f"Couldn't remove: {e}",
                    "tier": "local", "latency_ms": 0,
                    "source": "reminder_remove_error"}
        audit.log_event(DATA_DIR, actor=username, action="reminder.removed",
                        meta={"reminder_id": target["id"], "text": target.get("text", "")})
        return {"reply": f"✓ Removed reminder: \"{target.get('text','')}\"",
                "tier": "local", "latency_ms": 0,
                "source": "reminder_removed"}
    listed = "\n".join(f"  · {r['text']}" for _, r in scored[:5])
    return {"reply": f"A few reminders could match \"{body}\":\n{listed}\nWhich one?",
            "tier": "local", "latency_ms": 0,
            "source": "reminder_remove_ambiguous"}


_PROJECT_BALANCE_RE = _re.compile(
    r"^\s*(?:"
    r"what(?:'s| was| is)\s+(?:the\s+)?(?:final\s+|outstanding\s+|remaining\s+|current\s+)?balance\s+(?:on|for|of)\s+(?:the\s+)?(?P<q>.+?)(?:\s+(?:project|job|build|closeout))?"
    r"|(?:what\s+(?:did|does)\s+(?:the\s+)?(?P<q2>.+?)\s+(?:project|job|build)?\s*owe|how\s+much\s+(?:did|does)\s+(?:the\s+)?(?P<q3>.+?)\s+(?:project|job|build)?\s*owe)"
    r"|balance\s+(?:on|for)\s+(?P<q4>.+?)(?:\s+(?:project|job|build|closeout))?"
    r")\s*[?.!]?\s*$",
    _re.IGNORECASE,
)


def _try_project_balance(message: str, user_rec: dict) -> dict | None:
    """'What was the final balance on the Birch closeout?' / 'balance on
    Oak' / 'what did Maple owe' — look up the project's billed-vs-paid.
    Honest 'no such project' if not found instead of LLM fabrication."""
    if not message:
        return None
    msg = _strip_polite_prefix(message)
    m = _PROJECT_BALANCE_RE.match(msg)
    if not m:
        return None
    q = (m.group("q") or m.group("q2") or m.group("q3") or m.group("q4") or "").strip()
    q = _re.sub(r"^the\s+", "", q, flags=_re.IGNORECASE)
    q = _re.sub(r"\s+(?:project|job|build|closeout)$", "", q, flags=_re.IGNORECASE).strip()
    if not q or len(q) < 2:
        return None
    matches = mod_projects.find_by_address(DATA_DIR, q)
    if not matches:
        matches = _find_projects_by_customer(q)
    if not matches:
        return {"reply": (
            f"I don't see a project matching \"{q}\". Either the project "
            f"name is different, or it was never added. Try: \"list jobs\" "
            f"for active projects, or \"history for <customer name>\" if "
            f"it's an older one."
        ), "tier": "local", "latency_ms": 0,
           "source": "gc_project_balance_not_found"}
    if len(matches) > 1:
        listed = "\n".join(f"  · {p['address']}" for p in matches[:5])
        return {"reply": f"Multiple projects match \"{q}\":\n{listed}\nWhich one?",
                "tier": "local", "latency_ms": 0,
                "source": "gc_project_balance_ambiguous"}
    p = matches[0]
    invs = mod_invoices.list_for_project(DATA_DIR, p["id"])
    if not invs:
        return {"reply": (
            f"{p['address']} — no invoices on record yet, so the balance "
            f"is $0 (and contract value of "
            f"${float(p.get('contract_amount') or 0):,.0f} is unbilled)."
        ), "tier": "local", "latency_ms": 0,
           "source": "gc_project_balance_no_invs"}
    billed = sum(float(i.get("amount_due", 0)) for i in invs
                  if i.get("status") not in ("draft", "void"))
    paid = sum(float(i.get("amount_paid", 0)) for i in invs)
    balance = billed - paid
    retainage = sum(float(i.get("retainage_held", 0)) for i in invs
                     if i.get("status") in ("paid", "partial"))
    status_word = "PAID IN FULL" if balance <= 0 else "BALANCE OWED"
    lines = [f"{p['address']} — {p.get('label','(no label)')}"]
    lines.append(f"  Status:    {p.get('status','?').upper()}")
    lines.append(f"  Billed:    ${billed:,.0f}")
    lines.append(f"  Paid:      ${paid:,.0f}")
    lines.append(f"  Balance:   ${balance:,.0f} ({status_word})")
    if retainage:
        lines.append(f"  Retainage: ${retainage:,.0f} (released at closeout)")
    return {"reply": "\n".join(lines), "tier": "local",
            "latency_ms": 0, "source": "gc_project_balance"}


def _try_math_quick(message: str) -> dict | None:
    """Hypothetical balance math from a single message: ' billed X $A and
    paid $B' → owed = A - B. 'X owes $A but paid $B' → balance = A - B.
    Plus the simplest two-amount subtraction: 'A minus B' or 'A - B'."""
    if not message:
        return None
    msg = _strip_polite_prefix(message)
    # Hypothetical billed/paid form
    m = _re.match(
        r"^\s*(?:if|suppose|imagine|what\s+if|let'?s\s+say)\s+"
        r".+?(?:bill(?:ed)?|invoice[ds]?|charge[ds]?)\s+.+?\$([\d,]+(?:\.\d+)?)\s*(?:k|K)?"
        r".+?(?:paid|pay(?:s|ed)?|sent|gave|wrote\s+(?:me\s+)?a\s+check\s+for)\s+\$?([\d,]+(?:\.\d+)?)\s*(?:k|K)?"
        r".+?(?:owed|still\s+owed?|remaining|left|balance|owe)?",
        message, _re.IGNORECASE)
    if m:
        def _to_num(s: str, k_suffix: bool) -> float:
            v = float(s.replace(",", ""))
            return v * 1000 if k_suffix else v
        # Check if the captured amounts had "k" suffix
        billed_str = m.group(1)
        paid_str = m.group(2)
        billed = float(billed_str.replace(",", ""))
        paid = float(paid_str.replace(",", ""))
        # Crude k-suffix detection from raw match span
        raw = m.group(0).lower()
        if _re.search(rf"\${_re.escape(billed_str)}\s*k", raw): billed *= 1000
        if _re.search(rf"\${_re.escape(paid_str)}\s*k", raw): paid *= 1000
        owed = billed - paid
        sign = "owes you" if owed > 0 else "you owe them" if owed < 0 else "you're square"
        if owed > 0:
            return {"reply": (
                f"Billed ${billed:,.0f} − paid ${paid:,.0f} = "
                f"**${owed:,.0f} still owed**.\n"
                f"(If this is a real invoice, tell me which INV-XXXX and I'll record the partial payment.)"
            ), "tier": "local", "latency_ms": 0, "source": "math_balance"}
        if owed < 0:
            return {"reply": (
                f"Billed ${billed:,.0f} − paid ${abs(owed) + billed:,.0f} = "
                f"customer overpaid by **${abs(owed):,.0f}**.\n"
                f"You'd refund the difference or apply it as a credit."
            ), "tier": "local", "latency_ms": 0, "source": "math_overpaid"}
        return {"reply": f"Billed ${billed:,.0f} − paid ${paid:,.0f} = $0. Square.",
                "tier": "local", "latency_ms": 0, "source": "math_square"}
    return None


def _try_appointments_today(message: str, user_rec: dict) -> dict | None:
    """'What appointments are scheduled today?' / 'appointments today' —
    hit the calendar deterministically so the LLM can't fabricate."""
    msg = _strip_polite_prefix(message or "")
    if not _APPT_TODAY_RE.match(msg):
        return None
    username = user_rec.get("username", "owner")
    try:
        user_dir = users_mod.get_user_dir(DATA_DIR, username)
    except Exception:
        return None
    try:
        events = mod_calendar.today(user_dir) or []
    except Exception:
        events = []
    if not events:
        return {"reply": "No appointments on the calendar for today.",
                "tier": "local", "latency_ms": 0,
                "source": "appt_today_clear"}
    lines = [f"Today's calendar ({len(events)}):"]
    for e in events[:10]:
        start = (e.get("start") or "")[11:16] or "?"
        title = e.get("title", "")
        lines.append(f"  · {start} — {title}")
    return {"reply": "\n".join(lines), "tier": "local",
            "latency_ms": 0, "source": "appt_today"}


def _try_capabilities_overview(message: str) -> str | None:
    """Fast-path for 'list your capabilities' / 'what can you do' that
    works even when the LLM is offline. Returns a curated overview text
    directly from the shipped doc — no LLM call needed."""
    if not message:
        return None
    # Run polite-prefix strip + Orbeez→Orby normalization first, then test.
    cleaned = _strip_polite_prefix(message)
    cleaned = _ORBI_PHONETIC_RE.sub("orbi", cleaned)
    if not (_CAPABILITIES_RE.search(cleaned) or _WHAT_CAN_YOU_DO_RE.search(cleaned)):
        return None
    doc = _load_capabilities_doc()
    if not doc:
        return None
    # Pull H1, H2 and H3 headers — but skip the document title (the very
    # first H1) and admin-y sections users don't care about as "things
    # she can do".
    lines = doc.split("\n")
    sections = []
    saw_first_h1 = False
    for ln in lines:
        if ln.startswith("# ") and not ln.startswith("## "):
            if not saw_first_h1:
                saw_first_h1 = True
                continue
            sections.append(ln.lstrip("# ").strip())
        elif ln.startswith("## ") or ln.startswith("### "):
            sections.append(ln.lstrip("# ").strip())
    if not sections:
        return None
    skip = {
        "quick start — your first 10 minutes",
        "when something's wrong",
        "what orby won't do",
    }
    bullets = "\n".join(f"  • {s}" for s in sections
                        if s and s.lower() not in skip)
    return ("Here's everything I can do — pick any one and I'll walk you "
            "through it (or open the **Help** tab for the full guide with "
            "example phrases):\n\n" + bullets)


_PA_INBOX_RE = _re.compile(
    # Covers: 'check my email', 'check that email', 'show me my email',
    # 'read me my email', 'any new emails?', 'what's in my inbox',
    # 'do I have any new mail', 'what's important in my inbox'.
    # "(?:e[\s-]?mails?|inbox|mails?|messages?)" tolerates plurals.
    r"\b(?:check|read|show|list|see|fetch|get|pull|look\s+at|tell\s+me\s+about)"
    r"\s+(?:me\s+)?(?:my\s+|the\s+|that\s+|some\s+)?(?:e[\s-]?mails?|inbox|mails?|messages?)\b"
    r"|\b(?:any|got|have|do\s+i\s+have)\s+(?:any\s+)?(?:new\s+)?(?:e[\s-]?mails?|mails?|messages?)\b"
    r"|\bwhat(?:'s|s| is)?\s+(?:important\s+)?(?:in|on)\s+(?:my\s+)?(?:e[\s-]?mails?|inbox|mails?)\b"
    r"|\bwhat(?:'s|s| is)\s+new\s+in\s+(?:my\s+)?(?:e[\s-]?mails?|inbox|mails?)\b",
    _re.IGNORECASE,
)

# Capture the explicit count when the user asks for a specific number of
# emails: 'show me my last 25 emails', 'give me 10 messages', 'last 50 emails'.
_PA_INBOX_COUNT_RE = _re.compile(
    r"\b(?:show|list|read|give|fetch|pull|see|get|tell)\s+(?:me\s+)?"
    r"(?:my\s+)?(?:last\s+|recent\s+|latest\s+|top\s+)?"
    r"(?P<n>\d{1,3})\s+"
    r"(?:e[\s-]?mails?|messages?|mails?)\b",
    _re.IGNORECASE,
)


# Sender local-parts that almost never represent a real person.
# We hide emails from these by default. The user can override with
# "show all my email" / "include newsletters" / etc.
_NOISE_LOCAL_PARTS = {
    "noreply", "no-reply", "donotreply", "do-not-reply", "do_not_reply",
    "marketing", "newsletter", "newsletters", "news", "updates",
    "notifications", "notification", "alerts", "alert", "deals", "promo",
    "promos", "promotions", "offers", "ads", "sales", "info",
    "auto", "automated", "auto-reply", "system",
}
_NOISE_SUBJECT_RE = _re.compile(
    r"\b(?:\d{1,3}\s*%\s*off|off!|on\s+sale|limited\s+time|free\s+shipping|"
    r"exclusive\s+(?:deal|offer)|memorial\s+day\s+sale|labor\s+day\s+sale|"
    r"unsubscribe|cyber\s+monday|black\s+friday|flash\s+sale|"
    r"don'?t\s+miss|act\s+now|today\s+only|hurry|"
    r"open\s+rate|click\s+here|claim\s+now|invitation\s+to\s+earn|"
    r"survey|webinar|"
    # extra patterns caught in real-world testing:
    r"\$\d+\s+down|no\s+perfect\s+credit|apply\s+for\s+the|"
    r"qualified\s+for|qualify\s+for|up\s+to\s+\d+%|save\s+(?:up\s+to|\d+)|"
    r"discount|coupon|special\s+offer|grand\s+opening|new\s+arrival|"
    r"summer.?ready|new\s+listings|cover\s+your\s+vehicle|"
    r"betting\s+outlook|mlb\s+plays|free\s+trial|risk[- ]?free|"
    r"\bad\s+credit\b|just\s+for\s+you|today's\s+outlook|"
    r"membership\s+deal|metal\s+roof|insurance\s+options|"
    r"social\s+security\s+update|benefits\s+now\s+available|"
    r"flexible\s+pricing|cost-effective|"
    r"final\s+(?:offer|opportunity|hours)|smb\s+month|"
    r"phone\s+making|making\s+more\s+money|"
    r"steady\s+energy|gut\s+doctor|"
    r"perfect\s+credit\s*needed|reliable\s+and\s+cost)\b",
    _re.IGNORECASE,
)
# Sender display-name patterns that scream "marketing list"
_NOISE_DISPLAY_NAME_RE = _re.compile(
    r"\b(?:save\s+big|cheap|discount|insure|insurance|vehicle\s+protection|"
    r"protection\s+usa|roofing|mastercard|credit\s+card|cash\s+for\s+you|"
    r"endurance\s+auto|seniors?\s+(?:save|discount)|deals?|"
    r"quote\s*reduction|loans?\s+(?:for|to)|sweepstake|"
    r"ballot\s+news|betting\s+daily|inside.?vegas|"
    r"\bads?\b|advertising|advertiser|coach\s+\(re\)?loved|"
    r"morning\s+health\s+fix|ancient\s+remedies|"
    r"casino|gambling|sports?\s+book|free\s+spins?)\b",
    _re.IGNORECASE,
)
# Subjects with these stay — even if other heuristics would hide them.
_KEEP_SUBJECT_RE = _re.compile(
    r"\b(?:invoice|receipt|order|payment|refund|appointment|meeting|"
    r"booking|reservation|delivery|shipped|tracking|security\s+alert|"
    r"sign[- ]?in|verify|verification|password\s+(?:was|changed|reset)|"
    r"two[- ]factor|2fa|action\s+required|account|deposit|paid|"
    r"thank\s+you|quote|estimate|lead|inquiry|contract|signed|"
    r"complaint|cancellation)\b",
    _re.IGNORECASE,
)


def _is_promotional(msg: dict) -> bool:
    """Quick heuristic to decide whether an email is noisy newsletter/promo
    junk vs something a human owner cares about. Conservative: when in
    doubt, treat as personal (false negatives are MUCH better than hiding
    a real lead)."""
    subj = (msg.get("subject") or "").strip()
    sender = (msg.get("from") or "").lower()

    # KEEP overrides — receipts, security, real-business signals
    if _KEEP_SUBJECT_RE.search(subj):
        return False

    # Extract local-part from From header
    local = ""
    if "<" in sender and ">" in sender:
        addr = sender.split("<", 1)[1].split(">", 1)[0]
    else:
        addr = sender
    if "@" in addr:
        local = addr.split("@", 1)[0]

    if local in _NOISE_LOCAL_PARTS:
        return True
    # Local-parts that LOOK auto-generated: long random strings, lots of
    # digits, hyphenated marketing-y compounds
    if local and len(local) > 18 and any(c.isdigit() for c in local):
        return True
    # Subject contains classic promo language
    if _NOISE_SUBJECT_RE.search(subj):
        return True
    # Display name contains marketing-list signals
    display_name = sender.split("<", 1)[0].strip(' "')
    if display_name and _NOISE_DISPLAY_NAME_RE.search(display_name):
        return True
    # Subject starts with "Frank, $X" / "Frank, $300" — classic personalized
    # marketing pattern
    if _re.match(r"^frank,?\s*\$\d", subj.strip(), _re.IGNORECASE):
        return True
    return False


_PA_REMINDER_DIAGNOSTIC_RE = _re.compile(
    r"\bwhy\s+(?:didn'?t|did\s+not)\s+i\s+(?:get|see|hear)\s+(?:the|a|my)?\s*reminder\b"
    r"|\bdid\s+(?:you|orby)\s+remind\s+me\b"
    r"|\bwhere'?s\s+my\s+reminder\b"
    r"|\bwhat\s+happened\s+to\s+(?:the|my)\s+reminder\b"
    r"|\bdid\s+my\s+reminder\s+(?:fire|go\s+off|come)\b",
    _re.IGNORECASE,
)


def _try_reminder_diagnostic(message: str, user_dir: Path) -> str | None:
    """Honest answer for 'why didn't I get the reminder I just set'.
    Without this, the LLM hallucinates 'I don't have the capability to
    set reminders that trigger outside of our conversation' — total
    fabrication because she literally has a firing worker and a toast/
    voice/chat-bubble pipeline."""
    if not message or not _PA_REMINDER_DIAGNOSTIC_RE.search(message):
        return None
    try:
        items = mod_reminders.list_all(user_dir)
    except Exception as e:
        return f"I couldn't read your reminders to check: {e}"
    pending = [r for r in items if r.get("status") == "pending"]
    fired = [r for r in items if r.get("status") == "fired"]
    notify_cfg = (CONFIG.get("notifications") or {})
    channels = []
    if notify_cfg.get("owner_pwa_push", True):
        channels.append("web push (if you installed the PWA + allowed notifications)")
    if notify_cfg.get("owner_email") and (CONFIG.get("owner") or {}).get("email"):
        channels.append("email")
    if notify_cfg.get("owner_sms") and (CONFIG.get("owner") or {}).get("phone"):
        channels.append("SMS")
    lines = [
        "My reminder system IS working — here's what's actually happening:",
        "",
        f"  • Pending reminders: {len(pending)}",
        f"  • Fired (already triggered): {len(fired)}",
        "",
        "When a reminder fires, I do ALL of these:",
        "  1. Play a chime",
        "  2. Speak it out loud (TTS): 'Hey Frank, this is your reminder. <body>'",
        "  3. Show a big yellow pulsing banner with Got It + Snooze buttons",
        "  4. Drop a ⏰ message into the Ask Orby chat history",
        "  5. Repeat the chime + voice every 3 min (up to 3x) until you click Got It",
    ]
    if fired:
        lines.append("")
        lines.append("Most recent fires:")
        for r in fired[-3:]:
            fired_at = _fmt_email_date(r.get("fired_at", ""))
            lines.append(f"  • {fired_at} — \"{r.get('text','')}\"")
    lines.append("")
    if channels:
        lines.append("External channels configured: " + ", ".join(channels))
    else:
        lines.append("⚠ No external channels (push / email / SMS) are configured "
                     "in your notification settings — that means the in-app toast "
                     "+ chime + voice are your ONLY signals. If the dashboard tab "
                     "is closed or the chime is muted, you'd miss it.")
    lines.append("")
    lines.append("If you DIDN'T see/hear the in-app signals: refresh the dashboard "
                 "and try a 1-min test reminder. If you still don't, that's a real "
                 "bug — tell me and I'll dig in.")
    return "\n".join(lines)


# Capture 'emails from X' / 'any new emails from Bill'
_PA_EMAIL_FROM_RE = _re.compile(
    r"\b(?:any\s+(?:new\s+)?|got\s+|do\s+i\s+have\s+(?:any\s+)?)?"
    r"(?:e[\s-]?mails?|messages?|mails?)\s+from\s+"
    r"(?P<sender>[A-Za-z][A-Za-z0-9\s.@'-]+?)\s*[?.!]?\s*$",
    _re.IGNORECASE,
)


_PA_INBOX_INCLUDE_ALL_RE = _re.compile(
    r"\b(?:include|with|show)\s+(?:newsletters?|promos?|promotions?|all|everything)\b"
    r"|\b(?:show|see)\s+(?:me\s+)?(?:all|everything)\b"
    r"|\bincluding\s+(?:newsletters?|promos?)\b",
    _re.IGNORECASE,
)


def _fmt_email_date(iso: str) -> str:
    """Turn the email's Date header into a friendly local-time string the
    owner can compare against what they see in their inbox UI."""
    return _format_iso_friendly(iso)


def _fmt_iso_local_time(iso: str) -> str:
    """ISO timestamp → just "9:00 am" / "2:30 pm" in the system's local
    TZ. For day/brief summaries where the date is already implied. Falls
    back to the raw [11:16] slice for malformed inputs."""
    if not iso:
        return "?"
    from datetime import datetime as _dt, timezone as _tz
    try:
        s = iso.rstrip().replace("Z", "+00:00")
        dt = _dt.fromisoformat(s)
        if dt.tzinfo is None:
            dt = dt.replace(tzinfo=_tz.utc)
        return dt.astimezone().strftime("%-I:%M %p").lower()
    except (ValueError, TypeError):
        return (iso or "")[11:16] or "?"


def _format_iso_friendly(iso: str) -> str:
    """Friendly local-time renderer used for email dates AND any other
    place we render an ISO timestamp to the owner. Was previously inlined
    in `_format_email_date`."""
    if not iso:
        return ""
    from datetime import datetime as _dt, timedelta as _td, timezone as _tz
    try:
        # Python 3.10's fromisoformat doesn't accept trailing 'Z' (it
        # expects '+00:00'); strip it so reminder UTC timestamps like
        # '2026-05-29T00:00:00Z' parse instead of falling to the
        # raw-UTC fallback.
        s = iso.rstrip().replace("Z", "+00:00")
        dt = _dt.fromisoformat(s)
        if dt.tzinfo is None:
            dt = dt.replace(tzinfo=_tz.utc)
        local = dt.astimezone()
        now_local = _dt.now().astimezone()
        same_day = local.date() == now_local.date()
        yesterday = local.date() == (now_local - _td(days=1)).date()
        time_str = local.strftime("%I:%M %p").lstrip("0").lower()
        if same_day:
            return time_str
        if yesterday:
            return "yesterday " + time_str
        tomorrow = local.date() == (now_local + _td(days=1)).date()
        if tomorrow:
            return "tomorrow " + time_str
        if local.year == now_local.year:
            return local.strftime("%a %b %d ").lower() + time_str
        return local.strftime("%Y-%m-%d ").lower() + time_str
    except (ValueError, TypeError):
        return iso[:16].replace("T", " ")


def _try_inbox_check(message: str, user_dir: Path) -> str | None:
    """Detect 'check my email / what's in my inbox' and pull a live summary
    directly from email_inbox.fetch_inbox. Without this fast-path the
    request bounces to the LLM, which has no idea the IMAP/Gmail/Outlook
    accounts are connected and tells the user 'I don't have access'."""
    # Match either the broad inbox-check pattern, the explicit-count one,
    # or the "emails from X" sender filter.
    count_match  = _PA_INBOX_COUNT_RE.search(message or "")
    sender_match = _PA_EMAIL_FROM_RE.search(message or "")
    if not message or (not _PA_INBOX_RE.search(message)
                       and not count_match and not sender_match):
        return None
    sender_filter = None
    if sender_match:
        sender_filter = sender_match.group("sender").strip().rstrip("?.!").strip()

    # If the user said "show me 25 emails", honor that count exactly. Cap at
    # 200 so we don't accidentally pull the entire inbox.
    requested_n = None
    if count_match:
        try:
            requested_n = max(1, min(200, int(count_match.group("n"))))
        except ValueError:
            requested_n = None
    fetch_limit = max(100, (requested_n or 0) * 2)  # pull extra so the filter
                                                    # can hide promos and still
                                                    # leave the requested count

    try:
        result = email_inbox.fetch_inbox(CONFIG, user_dir, source="all",
                                         limit=fetch_limit, force_refresh=True)
    except Exception as e:
        log.warning(f"inbox fetch_inbox failed: {e}")
        return f"I tried to check your inbox but hit an error: {e}"

    messages = result.get("messages") or []
    errors   = result.get("errors") or {}
    # Sender filter — narrow to just the sender the user asked about
    if sender_filter:
        sf = sender_filter.lower()
        messages = [m for m in messages
                    if sf in (m.get("from") or "").lower()]
        if not messages:
            return (f"I don't see any recent emails from \"{sender_filter}\" "
                    f"in your inbox. (Check the spelling, or try a partial "
                    f"match like just the first name.)")
    if not messages:
        msg = "Your inbox is empty (or I can't see anything new)."
        if errors:
            details = "; ".join(f"{k}: {v[:80]}" for k, v in errors.items())
            msg += f" Errors: {details}"
        return msg

    # When the user asks for a specific N emails OR for emails from a
    # specific sender, treat as 'include all' — don't pre-filter promos
    # or the count won't match / the sender filter will look broken.
    if requested_n is not None or sender_filter is not None:
        show_all = True
    else:
        show_all = bool(_PA_INBOX_INCLUDE_ALL_RE.search(message))
    if show_all:
        kept = messages
        hidden_promo = []
    else:
        kept = []
        hidden_promo = []
        for m in messages:
            (hidden_promo if _is_promotional(m) else kept).append(m)

    by_provider = result.get("by_provider") or {}
    unread = sum(1 for m in kept if m.get("unread"))
    important = [m for m in kept if m.get("flagged") or
                 any(t in ("lead", "urgent", "complaint") for t in (m.get("tags") or []))]

    if show_all:
        lines = [f"You have {len(messages)} recent messages ({unread} unread)."]
    else:
        lines = [f"You have {len(kept)} important / personal messages "
                 f"({unread} unread). I filtered out {len(hidden_promo)} "
                 f"newsletters & promos — say 'show me everything' to see them."]
    if by_provider:
        lines.append("Sources: " + ", ".join(f"{k} ({v})" for k, v in by_provider.items()) + ".")

    if important:
        lines.append("")
        lines.append(f"⚡ {len(important)} flagged as important:")
        for m in important[:5]:
            date_str = _fmt_email_date(m.get("date", ""))
            lines.append(f"  - [{date_str}] {m.get('from','?')[:35]}: "
                         f"{m.get('subject','(no subject)')[:55]}")

    lines.append("")
    if requested_n is not None:
        show_n = min(len(kept), requested_n)
        lines.append(f"Your last {show_n} emails:")
    else:
        show_n = min(len(kept), 40)
        label = "everything" if show_all else "newest (filtered)"
        lines.append(f"Top {show_n} {label}:")
    for m in kept[:show_n]:
        unread_mark = "● " if m.get("unread") else "  "
        date_str = _fmt_email_date(m.get("date", ""))
        sender  = (m.get("from") or "?")[:26]
        subject = (m.get("subject") or "(no subject)")[:46]
        folder  = m.get("folder") or m.get("provider") or "?"
        lines.append(f"  {unread_mark}[{folder:<6} {date_str:>13}]  {sender:<26} — {subject}")

    if not show_all and hidden_promo:
        lines.append("")
        lines.append(f"📭 Hidden ({len(hidden_promo)} promos / newsletters):")
        # Just list the senders so Frank knows who's been emailing him
        senders = {}
        for m in hidden_promo:
            s = (m.get("from") or "?").split("<", 1)[0].strip(' "')
            senders[s] = senders.get(s, 0) + 1
        sender_list = sorted(senders.items(), key=lambda x: -x[1])
        for s, n in sender_list[:8]:
            lines.append(f"  - {s[:50]}" + (f" ({n})" if n > 1 else ""))
        if len(sender_list) > 8:
            lines.append(f"  ...and {len(sender_list) - 8} more")

    if errors:
        lines.append("")
        lines.append("(Some sources errored: " +
                     ", ".join(f"{k}={v[:50]}" for k, v in errors.items()) + ")")

    return "\n".join(lines)


